def _codex_subtree_uses_feature_at_least(
    feature: tuple[int, ...],
    left: tuple[int, ...],
    right: tuple[int, ...],
    min_feature: int,
) -> tuple[bool, ...]:
    memo: dict[int, bool] = {}

    def visit(node: int) -> bool:
        if node < 0:
            return False
        cached = memo.get(node)
        if cached is not None:
            return cached
        node_feature = feature[node]
        uses_feature = node_feature >= min_feature
        if node_feature >= 0:
            uses_feature = uses_feature or visit(left[node]) or visit(right[node])
        memo[node] = uses_feature
        return uses_feature

    return tuple(visit(node) for node in range(len(feature)))


