def trim_pred_by_valid_mask(pred, valid_mask):
    """If the decoder returned a serialized point order, trim all per-point
    fields (masks, order) to the valid-only length; otherwise index by mask."""
    valid_mask = valid_mask.bool()
    if pred.get("_serialized_point_order", None) is not None:
        raw_size = int(valid_mask.sum().item())
        pm = pred["pred_masks"]
        if pm.dim() == 4:
            pred["pred_masks"] = pm[:, :, :raw_size, :]
        elif pm.dim() == 3:
            pred["pred_masks"] = pm[:, :, :raw_size]
        pred["_serialized_point_order"] = pred["_serialized_point_order"][:raw_size]
        return pred
    pm = pred["pred_masks"]
    if pm.dim() == 4:
        pred["pred_masks"] = pm[:, :, valid_mask, :]
    elif pm.dim() == 3:
        pred["pred_masks"] = pm[:, :, valid_mask]
    return pred


@torch.no_grad()
def _compute_clf_keep_mask(full_data, full_clf_scores, clf_recall=0.995):
    valid_mask = full_data.valid_mask.bool()
    if float(clf_recall) >= 1.0:
        return valid_mask
    if full_clf_scores is None:
        raise ValueError("clf_keep requires clf scores.")
    scores = full_clf_scores.squeeze(-1).float()
    y_true = full_data.targets[0][0]["y_true"]
    pos_scores = scores[valid_mask][y_true]
    if pos_scores.numel() == 0:
        return valid_mask
    clf_thres = torch.quantile(pos_scores, 1.0 - clf_recall)
    return (scores >= clf_thres) & valid_mask


@torch.no_grad()
def _sub_event_topk_queries(
    pred_masks,
    pred_logits,
    point_order,
    sub,
    active_prob_threshold=0.0,
    active_prob_power=1.0,
    active_prob_floor=0.0,
    active_query_topk=0,
    topk=1,
    use_logit_scores=False,
    score_mode="prob",
    score_bf16=False,
    compile_assign=False,
):
    n_queries_total = int(pred_masks.shape[1])
    query_ids = None
    if int(active_query_topk) > 0 and int(active_query_topk) < int(pred_masks.shape[1]):
        query_scores = pred_logits.softmax(-1)[0, :, 0].float()
        query_ids = query_scores.topk(int(active_query_topk), largest=True).indices
        pred_masks = pred_masks.index_select(1, query_ids)
        pred_logits = pred_logits.index_select(1, query_ids)

    mode = str(score_mode or "prob")
    if bool(use_logit_scores) and mode == "prob":
        mode = "logit"
    orig_idx = sub["orig_idx"]
    valid_mask_sub = sub["valid_mask"].bool()
    n_sub_padded = valid_mask_sub.numel()
    n_sub_valid = orig_idx.numel()
    if (
        bool(compile_assign)
        and bool(score_bf16)
        and pred_masks.is_cuda
        and int(topk) == 1
        and query_ids is None
        and float(active_prob_threshold) <= 0.0
        and float(active_prob_floor) <= 0.0
        and pred_masks.shape[2] == n_sub_padded
        and mode in ("prob", "clamp_logprob")
    ):
        if point_order is not None:
            point_order = point_order.to(device=pred_masks.device, dtype=torch.long)
            if point_order.numel() != n_sub_padded:
                raise RuntimeError(
                    f"Serialized point order length {point_order.numel()} does not match padded width {n_sub_padded}."
                )
            sorted_valid_mask = valid_mask_sub.index_select(0, point_order)
            sorted_orig_idx = sub["all_idx"].index_select(0, point_order)[sorted_valid_mask]
        else:
            sorted_valid_mask = valid_mask_sub
            sorted_orig_idx = orig_idx
        if mode == "clamp_logprob":
            scores_one, idx_one = _score_top1_clamp_logprob_bf16_padded_compiled(
                pred_masks,
                pred_logits,
                sorted_valid_mask,
                float(active_prob_power),
            )
        else:
            scores_one, idx_one = _score_top1_prob_bf16_padded_compiled(
                pred_masks,
                pred_logits,
                sorted_valid_mask,
                float(active_prob_power),
            )
        scores_top = scores_one[sorted_valid_mask].unsqueeze(1).contiguous()
        idx_top = idx_one[sorted_valid_mask].unsqueeze(1).contiguous()
        return sorted_orig_idx, idx_top, scores_top, n_queries_total, "padded"
    if mode.startswith("rawtop") and mode.endswith("_clamp_logprob") and int(topk) == 1:
        try:
            candidate_topk = int(mode[len("rawtop") : mode.index("_clamp_logprob")])
        except ValueError:
            candidate_topk = 4
        raw_scores = pred_masks.float()[0, ..., 0]
        n_scores = raw_scores.shape[1]
        if n_scores == n_sub_padded:
            if point_order is not None:
                point_order = point_order.to(device=raw_scores.device, dtype=torch.long)
                if point_order.numel() != n_sub_padded:
                    raise RuntimeError(
                        f"Serialized point order length {point_order.numel()} does not match padded width {n_sub_padded}."
                    )
                sorted_valid_mask = valid_mask_sub.index_select(0, point_order)
                raw_scores = raw_scores.masked_fill(~sorted_valid_mask, float("-inf"))
                sorted_orig_idx = sub["all_idx"].index_select(0, point_order)[sorted_valid_mask]
            else:
                sorted_valid_mask = valid_mask_sub
                sorted_orig_idx = orig_idx
                raw_scores = raw_scores.masked_fill(~valid_mask_sub, float("-inf"))
            sub_mask_mode = "padded"
        elif n_scores == n_sub_valid:
            sub_mask_mode = "trimmed"
        else:
            raise RuntimeError(
                f"Incompatible sub-event shapes: mask_scores={n_scores}, "
                f"valid={n_sub_padded}, orig={n_sub_valid}"
            )
        k_cand = max(1, min(int(candidate_topk), int(raw_scores.shape[0])))
        cand_vals, cand_idx = raw_scores.topk(k_cand, dim=0)
        active_bias = pred_logits.log_softmax(-1)[0, :, 0].float()
        if float(active_prob_power) != 1.0:
            active_bias = active_bias * float(active_prob_power)
        cand_scores = cand_vals.clamp_max(0) + active_bias[cand_idx]
        if float(active_prob_threshold) > 0.0:
            active_keep = pred_logits.softmax(-1)[0, :, 0].float() >= float(active_prob_threshold)
            cand_scores = cand_scores.masked_fill(~active_keep[cand_idx], float("-inf"))
        scores_one, best_pos = cand_scores.max(dim=0)
        idx_one = cand_idx.gather(0, best_pos.unsqueeze(0)).squeeze(0)
        if query_ids is not None:
            idx_one = query_ids[idx_one]
        scores_top = scores_one.float().unsqueeze(0)
        idx_top = idx_one.unsqueeze(0)
        if sub_mask_mode == "padded":
            scores_top = scores_top[:, sorted_valid_mask]
            idx_top = idx_top[:, sorted_valid_mask]
            orig_idx = sorted_orig_idx
        elif point_order is not None:
            point_order = point_order.to(device=raw_scores.device, dtype=torch.long)
            if point_order.numel() != n_sub_valid:
                raise RuntimeError(
                    f"Serialized point order length {point_order.numel()} does not match trimmed width {n_sub_valid}."
                )
            orig_idx = orig_idx.index_select(0, point_order)
        return orig_idx, idx_top.t().contiguous(), scores_top.t().contiguous(), n_queries_total, sub_mask_mode
    if mode == "logit":
        mask_scores = pred_masks.float()[0, ..., 0]  # [Q, N_sub], threshold units are logits.
        if float(active_prob_threshold) > 0.0:
            active_keep = pred_logits.softmax(-1)[0, :, 0].float() >= float(active_prob_threshold)
            mask_scores = mask_scores.masked_fill(~active_keep[:, None], float("-inf"))
    elif mode == "clamp_logprob" and float(active_prob_floor) <= 0.0:
        if bool(score_bf16) and pred_masks.is_cuda:
            mask_scores = pred_masks[0, ..., 0].to(torch.bfloat16)
            mask_scores.clamp_max_(0)
        else:
            mask_scores = pred_masks.float()[0, ..., 0].clamp_max(0)
        if float(active_prob_power) != 0.0:
            active_bias = pred_logits.log_softmax(-1)[0, :, 0].float()
            if float(active_prob_power) != 1.0:
                active_bias = active_bias * float(active_prob_power)
            if bool(score_bf16) and pred_masks.is_cuda:
                mask_scores.add_(active_bias.to(torch.bfloat16)[:, None])
            else:
                mask_scores = mask_scores + active_bias[:, None]
        if float(active_prob_threshold) > 0.0:
            active_keep = pred_logits.softmax(-1)[0, :, 0].float() >= float(active_prob_threshold)
            mask_scores = mask_scores.masked_fill(~active_keep[:, None], float("-inf"))
    elif mode == "logprob" and float(active_prob_floor) <= 0.0:
        masks = pred_masks[0, ..., 0]
        if bool(score_bf16) and pred_masks.is_cuda:
            mask_scores = F.logsigmoid(masks.to(torch.bfloat16))
        else:
            mask_scores = F.logsigmoid(masks.float())
        if float(active_prob_power) != 0.0:
            active_bias = pred_logits.log_softmax(-1)[0, :, 0].float()
            if float(active_prob_power) != 1.0:
                active_bias = active_bias * float(active_prob_power)
            if bool(score_bf16) and pred_masks.is_cuda:
                mask_scores = mask_scores + active_bias.to(torch.bfloat16)[:, None]
            else:
                mask_scores = mask_scores + active_bias[:, None]
        if float(active_prob_threshold) > 0.0:
            active_keep = pred_logits.softmax(-1)[0, :, 0].float() >= float(active_prob_threshold)
            mask_scores = mask_scores.masked_fill(~active_keep[:, None], float("-inf"))
    elif mode in ("logit_logprob", "logit_logodds"):
        if bool(score_bf16) and pred_masks.is_cuda:
            mask_scores = pred_masks[0, ..., 0].to(torch.bfloat16)
        else:
            mask_scores = pred_masks.float()[0, ..., 0]
        if mode == "logit_logprob":
            active_bias = pred_logits.log_softmax(-1)[0, :, 0].float()
        else:
            active_bias = (pred_logits[0, :, 0] - pred_logits[0, :, 1]).float()
        if float(active_prob_power) != 1.0:
            active_bias = active_bias * float(active_prob_power)
        if bool(score_bf16) and pred_masks.is_cuda:
            mask_scores.add_(active_bias.to(torch.bfloat16)[:, None])
        else:
            mask_scores = mask_scores + active_bias[:, None]
    else:
        active_probs = pred_logits.softmax(-1)[..., 0].float()
        active_weight = active_probs
        if float(active_prob_power) == 0.0:
            active_weight = torch.ones_like(active_probs)
        elif float(active_prob_power) != 1.0:
            active_weight = active_probs.clamp_min(1e-12).pow(float(active_prob_power))
        if float(active_prob_floor) > 0.0:
            floor = float(active_prob_floor)
            active_weight = floor + (1.0 - floor) * active_weight
        if bool(score_bf16) and pred_masks.is_cuda:
            mask_scores = pred_masks[0, ..., 0].to(torch.bfloat16)
            mask_scores.sigmoid_()
            mask_scores.mul_(active_weight[0].to(torch.bfloat16)[:, None])
        else:
            mask_scores = (active_weight.unsqueeze(-1).unsqueeze(-1) * pred_masks.sigmoid()).float()
            mask_scores = mask_scores[0, ..., 0]  # [Q, N_sub]
        if float(active_prob_threshold) > 0.0:
            active_keep = active_probs[0] >= float(active_prob_threshold)
            mask_scores = mask_scores.masked_fill(~active_keep[:, None], float("-inf"))

    n_scores = mask_scores.shape[1]

    if n_scores == n_sub_padded:
        if point_order is not None:
            point_order = point_order.to(device=mask_scores.device, dtype=torch.long)
            if point_order.numel() != n_sub_padded:
                raise RuntimeError(
                    f"Serialized point order length {point_order.numel()} does not match padded width {n_sub_padded}."
                )
            sorted_valid_mask = valid_mask_sub.index_select(0, point_order)
            mask_scores = mask_scores.masked_fill(~sorted_valid_mask, float("-inf"))
            sorted_orig_idx = sub["all_idx"].index_select(0, point_order)[sorted_valid_mask]
        else:
            sorted_valid_mask = valid_mask_sub
            sorted_orig_idx = orig_idx
            mask_scores = mask_scores.masked_fill(~valid_mask_sub, float("-inf"))
        sub_mask_mode = "padded"
    elif n_scores == n_sub_valid:
        sub_mask_mode = "trimmed"
    else:
        raise RuntimeError(
            f"Incompatible sub-event shapes: mask_scores={n_scores}, "
            f"valid={n_sub_padded}, orig={n_sub_valid}"
        )

    serialized_order = None
    if point_order is not None and sub_mask_mode == "trimmed":
        point_order = point_order.to(device=mask_scores.device, dtype=torch.long)
        if point_order.numel() != n_sub_valid:
            raise RuntimeError(
                f"Serialized point order length {point_order.numel()} does not match trimmed width {n_sub_valid}."
            )
        serialized_order = point_order

    k = max(1, min(int(topk), int(mask_scores.shape[0])))
    if k == 1:
        scores_one, idx_one = mask_scores.max(dim=0)
        scores_top = scores_one.float().unsqueeze(0)
        idx_top = idx_one.unsqueeze(0)
    else:
        scores_top, idx_top = mask_scores.topk(k, dim=0)
        scores_top = scores_top.float()
    if query_ids is not None:
        idx_top = query_ids[idx_top]
    if sub_mask_mode == "padded":
        scores_top = scores_top[:, sorted_valid_mask]
        idx_top = idx_top[:, sorted_valid_mask]
        orig_idx = sorted_orig_idx
    elif serialized_order is not None:
        orig_idx = orig_idx.index_select(0, serialized_order)
    return orig_idx, idx_top.t().contiguous(), scores_top.t().contiguous(), n_queries_total, sub_mask_mode


@torch.no_grad()
def _sub_event_winning_queries(
    pred_masks,
    pred_logits,
    point_order,
    sub,
    active_prob_threshold=0.0,
    active_prob_power=1.0,
    active_prob_floor=0.0,
    active_query_topk=0,
    use_logit_scores=False,
    score_mode="prob",
    score_bf16=False,
    compile_assign=False,
):
    orig_idx, idx_top, scores_top, n_queries, sub_mask_mode = _sub_event_topk_queries(
        pred_masks,
        pred_logits,
        point_order,
        sub,
        active_prob_threshold=active_prob_threshold,
        active_prob_power=active_prob_power,
        active_prob_floor=active_prob_floor,
        active_query_topk=active_query_topk,
        topk=1,
        use_logit_scores=use_logit_scores,
        score_mode=score_mode,
        score_bf16=score_bf16,
        compile_assign=compile_assign,
    )
    return orig_idx, idx_top[:, 0], scores_top[:, 0], n_queries, sub_mask_mode


@torch.no_grad()
def _build_decoder_assignments_batched_top1(
    pred_list,
    sub_events,
    full_data,
    clf_keep,
    mask_thres=0.0,
    active_prob_threshold=0.0,
    active_prob_power=1.0,
    active_prob_floor=0.0,
    active_query_topk=0,
    use_logit_scores=False,
    score_mode="prob",
    score_bf16=False,
    compile_assign=False,
    max_sub_events=0,
    return_scores=False,
):
    if bool(getattr(full_data, "decoder_overlap", True)):
        return None
    if int(active_query_topk) > 0:
        return None

    n_sub_events = len(sub_events) if sub_events is not None else 0
    if n_sub_events == 0 and hasattr(full_data, "decoder_sub_all_idx"):
        n_sub_events = int(full_data.decoder_sub_all_idx.shape[0])

    batched_input = (
        len(pred_list) == 1
        and pred_list[0][0].dim() == 4
        and pred_list[0][1].dim() == 3
        and int(pred_list[0][0].shape[0]) == n_sub_events
        and int(pred_list[0][0].shape[0]) > 1
    )
    if batched_input:
        first_masks, first_logits, first_order = pred_list[0]
        n_items = int(first_masks.shape[0])
        if int(max_sub_events) > 0:
            n_items = min(n_items, int(max_sub_events))
    else:
        if sub_events is None:
            return None
        items = list(zip(pred_list, sub_events))
        if int(max_sub_events) > 0:
            items = items[: int(max_sub_events)]
        if len(items) <= 1:
            return None
        first_masks = items[0][0][0]
        first_logits = items[0][0][1]
        n_items = len(items)
    if first_masks.dim() != 4 or first_logits.dim() != 3:
        return None
    q = int(first_masks.shape[1])
    n = int(first_masks.shape[2])
    mask_shape = tuple(first_masks.shape)
    logit_shape = tuple(first_logits.shape)

    orig_chunks = []
    device = full_data.x.device
    valid_masks_sorted = None
    sorted_orig_idx_batched = None
    if batched_input:
        if hasattr(full_data, "decoder_sub_all_idx") and hasattr(full_data, "decoder_sub_valid_mask"):
            batch_all_idx = full_data.decoder_sub_all_idx[:n_items].to(device=device, dtype=torch.long)
            batch_valid_mask = full_data.decoder_sub_valid_mask[:n_items].to(device=device, dtype=torch.bool)
        else:
            batch_all_idx = torch.stack([sub["all_idx"] for sub in sub_events[:n_items]], dim=0).to(
                device=device,
                dtype=torch.long,
            )
            batch_valid_mask = torch.stack([sub["valid_mask"].bool() for sub in sub_events[:n_items]], dim=0).to(
                device=device,
                dtype=torch.bool,
            )
        if int(batch_all_idx.shape[1]) != n or int(batch_valid_mask.shape[1]) != n:
            return None
        if first_order is not None:
            point_order = first_order[:n_items].to(device=device, dtype=torch.long)
            if int(point_order.shape[1]) != n:
                return None
            valid_masks_sorted = batch_valid_mask.gather(1, point_order)
            sorted_orig_idx_batched = batch_all_idx.gather(1, point_order)
        else:
            valid_masks_sorted = batch_valid_mask
            sorted_orig_idx_batched = batch_all_idx
        if bool(score_bf16) and first_masks.is_cuda:
            masks = first_masks[:n_items, ..., 0].to(torch.bfloat16)
        else:
            masks = first_masks[:n_items, ..., 0].float()
        logits = first_logits[:n_items]
    else:
        mask_chunks = []
        logit_chunks = []
        for (pred_masks, pred_logits, point_order), sub in items:
            if tuple(pred_masks.shape) != mask_shape or tuple(pred_logits.shape) != logit_shape:
                return None
            orig_idx = sub["orig_idx"]
            if int(orig_idx.numel()) != n:
                return None
            if point_order is not None:
                point_order = point_order.to(device=orig_idx.device, dtype=torch.long)
                if int(point_order.numel()) != n:
                    return None
                orig_idx = orig_idx.index_select(0, point_order)
            orig_chunks.append(orig_idx)
            if bool(score_bf16) and pred_masks.is_cuda:
                mask_chunks.append(pred_masks[0, ..., 0].to(torch.bfloat16))
            else:
                mask_chunks.append(pred_masks.float()[0, ..., 0])
            logit_chunks.append(pred_logits[0])
        masks = torch.stack(mask_chunks, dim=0)
        logits = torch.stack(logit_chunks, dim=0)
    mode = str(score_mode or "prob")
    if bool(use_logit_scores) and mode == "prob":
        mode = "logit"

    if (
        bool(compile_assign)
        and bool(score_bf16)
        and batched_input
        and first_masks.is_cuda
        and valid_masks_sorted is not None
        and float(active_prob_threshold) <= 0.0
        and float(active_prob_floor) <= 0.0
        and mode in ("prob", "clamp_logprob")
    ):
        masks_in = first_masks[:n_items]
        logits_in = first_logits[:n_items]
        if mode == "clamp_logprob":
            scores_max, idx_max = _score_top1_clamp_logprob_bf16_batched_padded_compiled(
                masks_in,
                logits_in,
                valid_masks_sorted,
                float(active_prob_power),
            )
        else:
            scores_max, idx_max = _score_top1_prob_bf16_batched_padded_compiled(
                masks_in,
                logits_in,
                valid_masks_sorted,
                float(active_prob_power),
            )
        offsets = torch.arange(n_items, device=device, dtype=torch.long).mul_(q).unsqueeze(1)
        labels = idx_max.long() + offsets
        if float(mask_thres) > float("-inf"):
            labels = labels.masked_fill(scores_max.float() < float(mask_thres), -1)
        predicted = torch.full((full_data.x.shape[0],), -1, device=device, dtype=torch.long)
        predicted[sorted_orig_idx_batched[valid_masks_sorted].long()] = labels[valid_masks_sorted].long()
        if clf_keep is not None:
            predicted[~clf_keep] = -1
        if bool(return_scores):
            out = [predicted]
            max_prob = torch.full((full_data.x.shape[0],), float("-inf"), device=device)
            max_prob[sorted_orig_idx_batched[valid_masks_sorted].long()] = scores_max[valid_masks_sorted].float()
            out.append(max_prob)
            return tuple(out)
        return predicted

    if mode == "logit":
        scores = masks.float()
        if float(active_prob_threshold) > 0.0:
            active_keep = logits.softmax(-1)[..., 0].float() >= float(active_prob_threshold)
            scores = scores.masked_fill(~active_keep.unsqueeze(-1), float("-inf"))
    elif mode == "clamp_logprob" and float(active_prob_floor) <= 0.0:
        if masks.dtype == torch.bfloat16:
            scores = masks.to(torch.bfloat16)
            scores.clamp_max_(0)
        else:
            scores = masks.float().clamp_max(0)
        if float(active_prob_power) != 0.0:
            active_bias = logits.log_softmax(-1)[..., 0].float()
            if float(active_prob_power) != 1.0:
                active_bias = active_bias * float(active_prob_power)
            if scores.dtype == torch.bfloat16:
                scores.add_(active_bias.to(torch.bfloat16).unsqueeze(-1))
            else:
                scores = scores + active_bias.unsqueeze(-1)
    elif mode == "logprob" and float(active_prob_floor) <= 0.0:
        scores = F.logsigmoid(masks)
        if float(active_prob_power) != 0.0:
            active_bias = logits.log_softmax(-1)[..., 0].float()
            if float(active_prob_power) != 1.0:
                active_bias = active_bias * float(active_prob_power)
            if scores.dtype == torch.bfloat16:
                scores = scores + active_bias.to(torch.bfloat16).unsqueeze(-1)
            else:
                scores = scores + active_bias.unsqueeze(-1)
        if float(active_prob_threshold) > 0.0:
            active_keep = logits.softmax(-1)[..., 0].float() >= float(active_prob_threshold)
            scores = scores.masked_fill(~active_keep.unsqueeze(-1), float("-inf"))
    elif mode in ("logit_logprob", "logit_logodds"):
        scores = masks
        if mode == "logit_logprob":
            active_bias = logits.log_softmax(-1)[..., 0].float()
        else:
            active_bias = (logits[..., 0] - logits[..., 1]).float()
        if float(active_prob_power) != 1.0:
            active_bias = active_bias * float(active_prob_power)
        if scores.dtype == torch.bfloat16:
            scores = scores + active_bias.to(torch.bfloat16).unsqueeze(-1)
        else:
            scores = scores + active_bias.unsqueeze(-1)
    else:
        active_probs = logits.softmax(-1)[..., 0].float()
        active_weight = active_probs
        if float(active_prob_power) == 0.0:
            active_weight = torch.ones_like(active_probs)
        elif float(active_prob_power) != 1.0:
            active_weight = active_probs.clamp_min(1e-12).pow(float(active_prob_power))
        if float(active_prob_floor) > 0.0:
            floor = float(active_prob_floor)
            active_weight = floor + (1.0 - floor) * active_weight
        scores = masks.sigmoid()
        if scores.dtype == torch.bfloat16:
            scores = scores * active_weight.to(torch.bfloat16).unsqueeze(-1)
        else:
            scores = scores * active_weight.unsqueeze(-1)
        if float(active_prob_threshold) > 0.0:
            active_keep = active_probs >= float(active_prob_threshold)
            scores = scores.masked_fill(~active_keep.unsqueeze(-1), float("-inf"))
    if valid_masks_sorted is not None:
        scores = scores.masked_fill(~valid_masks_sorted[:, None, :], float("-inf"))

    scores_max, idx_max = scores.max(dim=1)
    offsets = torch.arange(n_items, device=device, dtype=torch.long).mul_(q).unsqueeze(1)
    labels = idx_max.long() + offsets
    if float(mask_thres) > float("-inf"):
        labels = labels.masked_fill(scores_max.float() < float(mask_thres), -1)

    predicted = torch.full((full_data.x.shape[0],), -1, device=device, dtype=torch.long)
    if valid_masks_sorted is not None:
        predicted[sorted_orig_idx_batched[valid_masks_sorted].long()] = labels[valid_masks_sorted].long()
    else:
        predicted[torch.cat(orig_chunks).long()] = labels.reshape(-1)
    if clf_keep is not None:
        predicted[~clf_keep] = -1
    if bool(return_scores):
        out = [predicted]
        max_prob = torch.full((full_data.x.shape[0],), float("-inf"), device=device)
        if valid_masks_sorted is not None:
            max_prob[sorted_orig_idx_batched[valid_masks_sorted].long()] = scores_max[valid_masks_sorted].float()
        else:
            max_prob[torch.cat(orig_chunks).long()] = scores_max.reshape(-1).float()
        out.append(max_prob)
        return tuple(out)
    return predicted


@torch.no_grad()
def _build_decoder_assignments_from_mask_embed_batched_top1(
    mask_embed,
    point_feats,
    pred_logits,
    point_order,
    full_data,
    clf_keep,
    mask_thres=0.0,
    active_prob_power=1.0,
    query_chunk_size=512,
    active_query_topk=0,
    return_scores=False,
):
    if bool(getattr(full_data, "decoder_overlap", True)):
        return None
    if not hasattr(full_data, "decoder_sub_all_idx") or not hasattr(full_data, "decoder_sub_valid_mask"):
        return None
    device = full_data.x.device
    n_items = int(mask_embed.shape[0])
    q = int(mask_embed.shape[1])
    n = int(point_feats.shape[1])
    query_ids = None
    if int(active_query_topk) > 0 and int(active_query_topk) < q:
        query_scores = pred_logits.softmax(-1)[..., 0].float()
        query_ids = query_scores.topk(int(active_query_topk), dim=1, largest=True).indices
        mask_embed = mask_embed.gather(
            1,
            query_ids[:, :, None].expand(-1, -1, int(mask_embed.shape[2])),
        )
        pred_logits = pred_logits.gather(
            1,
            query_ids[:, :, None].expand(-1, -1, int(pred_logits.shape[2])),
        )
    batch_all_idx = full_data.decoder_sub_all_idx[:n_items].to(device=device, dtype=torch.long)
    batch_valid_mask = full_data.decoder_sub_valid_mask[:n_items].to(device=device, dtype=torch.bool)
    if int(batch_all_idx.shape[1]) != n or int(batch_valid_mask.shape[1]) != n:
        return None
    if point_order is not None:
        point_order = point_order[:n_items].to(device=device, dtype=torch.long)
        if int(point_order.shape[1]) != n:
            return None
        valid_masks_sorted = batch_valid_mask.gather(1, point_order)
        sorted_orig_idx_batched = batch_all_idx.gather(1, point_order)
    else:
        valid_masks_sorted = batch_valid_mask
        sorted_orig_idx_batched = batch_all_idx

    if _CODEX_ASSIGN_FP16:
        scores_max, idx_max = _score_top1_clamp_logprob_fp16_mask_embed_batched_compiled(
            mask_embed,
            point_feats,
            pred_logits,
            valid_masks_sorted,
            float(active_prob_power),
            int(query_chunk_size),
        )
    else:
        scores_max, idx_max = _score_top1_clamp_logprob_bf16_mask_embed_batched_compiled(
            mask_embed,
            point_feats,
            pred_logits,
            valid_masks_sorted,
            float(active_prob_power),
            int(query_chunk_size),
        )
    offsets = torch.arange(n_items, device=device, dtype=torch.long).mul_(q).unsqueeze(1)
    idx_labels = idx_max.long()
    if query_ids is not None:
        idx_labels = query_ids.gather(1, idx_labels)
    labels = idx_labels + offsets
    if float(mask_thres) > float("-inf"):
        labels = labels.masked_fill(scores_max.float() < float(mask_thres), -1)
    n_total = int(full_data.x.shape[0])
    flat_valid = valid_masks_sorted.reshape(-1)
    flat_orig = sorted_orig_idx_batched.reshape(-1).long()
    flat_labels = labels.reshape(-1).long()
    safe_orig = torch.where(flat_valid, flat_orig, torch.full_like(flat_orig, n_total))
    predicted_pad = torch.full((n_total + 1,), -1, device=device, dtype=torch.long)
    predicted_pad[safe_orig] = torch.where(flat_valid, flat_labels, torch.full_like(flat_labels, -1))
    predicted = predicted_pad[:n_total]
    if clf_keep is not None:
        predicted[~clf_keep] = -1
    if bool(return_scores):
        flat_scores = scores_max.reshape(-1).float()
        max_prob_pad = torch.full((n_total + 1,), float("-inf"), device=device, dtype=torch.float32)
        max_prob_pad[safe_orig] = torch.where(
            flat_valid,
            flat_scores,
            torch.full_like(flat_scores, float("-inf")),
        )
        max_prob = max_prob_pad[:n_total]
        return predicted, max_prob
    return predicted


@torch.no_grad()
def _sub_event_column_winning_queries(
    pred_masks,
    pred_logits,
    col_idx,
    active_prob_threshold=0.0,
    active_prob_power=1.0,
    active_prob_floor=0.0,
    active_query_topk=0,
    use_logit_scores=False,
    score_mode="prob",
    score_bf16=False,
):
    n_queries_total = int(pred_masks.shape[1])
    if col_idx.numel() == 0:
        empty_score = torch.empty(0, device=pred_masks.device, dtype=torch.float32)
        empty_idx = torch.empty(0, device=pred_masks.device, dtype=torch.long)
        return empty_idx, empty_score, n_queries_total
    query_ids = None
    if int(active_query_topk) > 0 and int(active_query_topk) < int(pred_masks.shape[1]):
        query_scores = pred_logits.softmax(-1)[0, :, 0].float()
        query_ids = query_scores.topk(int(active_query_topk), largest=True).indices
        pred_masks = pred_masks.index_select(1, query_ids)
        pred_logits = pred_logits.index_select(1, query_ids)
    if pred_masks.dim() == 4:
        masks = pred_masks.index_select(2, col_idx)[0, :, :, 0]
    else:
        masks = pred_masks.index_select(2, col_idx)[0]
    if bool(use_logit_scores):
        score_mode = "logit"
    mode = str(score_mode or "prob")
    if mode == "logit":
        scores = masks.float()
    elif mode == "logprob" and float(active_prob_floor) <= 0.0:
        if bool(score_bf16) and pred_masks.is_cuda:
            scores = F.logsigmoid(masks.to(torch.bfloat16))
        else:
            scores = F.logsigmoid(masks.float())
        if float(active_prob_power) != 0.0:
            active_bias = pred_logits.log_softmax(-1)[0, :, 0].float()
            if float(active_prob_power) != 1.0:
                active_bias = active_bias * float(active_prob_power)
            if bool(score_bf16) and pred_masks.is_cuda:
                scores = scores + active_bias.to(torch.bfloat16)[:, None]
            else:
                scores = scores + active_bias[:, None]
    elif mode in ("logit_logprob", "logit_logodds"):
        scores = masks.to(torch.bfloat16) if bool(score_bf16) and pred_masks.is_cuda else masks.float()
        if mode == "logit_logprob":
            active_bias = pred_logits.log_softmax(-1)[0, :, 0].float()
        else:
            active_bias = (pred_logits[0, :, 0] - pred_logits[0, :, 1]).float()
        if float(active_prob_power) != 1.0:
            active_bias = active_bias * float(active_prob_power)
        if bool(score_bf16) and pred_masks.is_cuda:
            scores.add_(active_bias.to(torch.bfloat16)[:, None])
        else:
            scores = scores + active_bias[:, None]
    else:
        active_probs = pred_logits.softmax(-1)[0, :, 0].float()
        active_weight = active_probs
        if float(active_prob_power) == 0.0:
            active_weight = torch.ones_like(active_probs)
        elif float(active_prob_power) != 1.0:
            active_weight = active_probs.clamp_min(1e-12).pow(float(active_prob_power))
        if float(active_prob_floor) > 0.0:
            floor = float(active_prob_floor)
            active_weight = floor + (1.0 - floor) * active_weight
        if bool(score_bf16) and pred_masks.is_cuda:
            scores = masks.to(torch.bfloat16)
            scores.sigmoid_()
            scores.mul_(active_weight.to(torch.bfloat16)[:, None])
        else:
            scores = masks.sigmoid() * active_weight[:, None]
    vals, idx = scores.max(dim=0)
    if query_ids is not None:
        idx = query_ids[idx]
    return idx, vals.float(), n_queries_total


@torch.no_grad()
def _build_decoder_assignments(
    pred_list,
    sub_events,
    full_data,
    clf_keep,
    mask_thres=0.0,
    active_prob_threshold=0.0,
    active_prob_power=1.0,
    active_prob_floor=0.0,
    active_query_topk=0,
    use_logit_scores=False,
    score_mode="prob",
    score_bf16=False,
    compile_assign=False,
    max_sub_events=0,
    batch_assignments=False,
    return_scores=False,
):
    device = full_data.x.device
    n_total = full_data.x.shape[0]
    decoder_overlap = bool(getattr(full_data, "decoder_overlap", True))
    track_scores = bool(return_scores) or bool(decoder_overlap)
    if bool(batch_assignments) and not bool(decoder_overlap):
        batched = _build_decoder_assignments_batched_top1(
            pred_list,
            sub_events,
            full_data,
            clf_keep,
            mask_thres=mask_thres,
            active_prob_threshold=active_prob_threshold,
            active_prob_power=active_prob_power,
            active_prob_floor=active_prob_floor,
            active_query_topk=active_query_topk,
            use_logit_scores=use_logit_scores,
            score_mode=score_mode,
            score_bf16=score_bf16,
            compile_assign=compile_assign,
            max_sub_events=max_sub_events,
            return_scores=return_scores,
        )
        if batched is not None:
            return batched
    max_prob = (
        torch.full((n_total,), float("-inf"), device=device)
        if track_scores
        else None
    )
    predicted = torch.full((n_total,), -1, device=device, dtype=torch.long)
    total_queries = 0

    if _DEBUG:
        print(f"[pp] n_total={n_total} n_subs={len(pred_list)} "
              f"clf_keep={int(clf_keep.sum())} decoder_overlap={decoder_overlap}")

    items = [] if sub_events is None else list(zip(pred_list, sub_events))
    if int(max_sub_events) > 0:
        items = items[: int(max_sub_events)]
    for sub_i, ((pred_masks, pred_logits, point_order), sub) in enumerate(items):
        orig_idx, idx_max, scores_max, n_queries, sub_mask_mode = _sub_event_winning_queries(
            pred_masks,
            pred_logits,
            point_order,
            sub,
            active_prob_threshold=active_prob_threshold,
            active_prob_power=active_prob_power,
            active_prob_floor=active_prob_floor,
            active_query_topk=active_query_topk,
            use_logit_scores=use_logit_scores,
            score_mode=score_mode,
            score_bf16=score_bf16,
            compile_assign=compile_assign,
        )
        n_sub_valid = orig_idx.numel()
        offset = total_queries
        total_queries += n_queries

        if _DEBUG:
            unique_q = torch.unique(idx_max[scores_max > 0])
            print(f"[pp]  sub{sub_i} mode={sub_mask_mode} n_valid={n_sub_valid} "
                  f"Q={n_queries} "
                  f"scores_max>0: {int((scores_max > 0).sum())}/{scores_max.numel()} "
                  f"unique_winning_queries={unique_q.numel()} "
                  f"score_stats=min/mean/max {scores_max.min().item():.3f}/"
                  f"{scores_max.mean().item():.3f}/{scores_max.max().item():.3f}")

        if decoder_overlap:
            better = scores_max > max_prob[orig_idx]
            if better.any():
                idx = orig_idx[better]
                max_prob[idx] = scores_max[better]
                predicted[idx] = offset + idx_max[better]
        else:
            if max_prob is not None:
                if (max_prob[orig_idx] > float("-inf")).any():
                    raise RuntimeError("decoder_overlap=False expected unique orig_idx across sub-events.")
                max_prob[orig_idx] = scores_max
            labels = offset + idx_max
            if float(mask_thres) > float("-inf"):
                labels = labels.masked_fill(scores_max < float(mask_thres), -1)
            predicted[orig_idx] = labels

    if max_prob is not None:
        predicted[max_prob < float(mask_thres)] = -1
    if _DEBUG:
        before_clf = int((predicted >= 0).sum())
        if clf_keep is not None:
            predicted[~clf_keep] = -1
        after_clf = int((predicted >= 0).sum())
        n_unique = int(torch.unique(predicted[predicted >= 0]).numel())
        print(f"[pp] assigned_before_clf={before_clf} after_clf={after_clf} "
              f"unique_clusters={n_unique} total_queries={total_queries}")
    elif clf_keep is not None:
        predicted[~clf_keep] = -1
    if return_scores:
        out = [predicted]
        out.append(max_prob)
        return tuple(out)
    return predicted


def _find_root(parent, x):
    while parent[x] != x:
        parent[x] = parent[parent[x]]
        x = parent[x]
    return x


def _union_roots(parent, rank, a, b):
    root_a = _find_root(parent, a)
    root_b = _find_root(parent, b)
    if root_a == root_b:
        return
    if rank[root_a] < rank[root_b]:
        root_a, root_b = root_b, root_a
    parent[root_b] = root_a
    if rank[root_a] == rank[root_b]:
        rank[root_a] += 1


def _compact_nonnegative_labels(labels, max_bincount_labels=65536):
    """Map nonnegative labels to dense ids using bincount when labels are bounded."""
    if labels.numel() == 0:
        empty = torch.empty(0, device=labels.device, dtype=torch.long)
        return empty, empty, empty
    max_label = int(labels.max().item()) + 1
    if max_label <= int(max_bincount_labels):
        counts_all = torch.bincount(labels, minlength=max_label)
        active_ids = torch.nonzero(counts_all > 0, as_tuple=False).squeeze(1)
        counts = counts_all.index_select(0, active_ids)
        dense = torch.empty(max_label, device=labels.device, dtype=torch.long)
        dense[active_ids] = torch.arange(active_ids.numel(), device=labels.device, dtype=torch.long)
        inv = dense.index_select(0, labels)
        return active_ids, inv, counts
    return torch.unique(labels, return_inverse=True, return_counts=True)


def _pair_keys_from_grouped_candidates(sorted_cand, sorted_source, group_counts, total_queries):
    """Build query-pair keys for candidates grouped by the same physical hit."""
    if group_counts.numel() == 0:
        return None

    starts = torch.cat(
        [
            torch.zeros(1, device=group_counts.device, dtype=torch.long),
            group_counts.cumsum(0)[:-1],
        ]
    )
    max_count = int(group_counts.max().item())
    keys = []
    scale = int(total_queries)
    for left in range(max_count - 1):
        for right in range(left + 1, max_count):
            keep = group_counts > right
            if not bool(keep.any()):
                continue
            left_pos = starts[keep] + left
            right_pos = starts[keep] + right
            cross_window = sorted_source[left_pos] != sorted_source[right_pos]
            if not bool(cross_window.any()):
                continue
            left_pos = left_pos[cross_window]
            right_pos = right_pos[cross_window]
            a = sorted_cand[left_pos]
            b = sorted_cand[right_pos]
            lo = torch.minimum(a, b)
            hi = torch.maximum(a, b)
            keys.append(lo * scale + hi)
    if not keys:
        return None
    return torch.cat(keys)


def _assign_by_topk_components(orig, cand, score, roots, n_total, total_queries, score_gate=0.0):
    """Assign each hit to the component with the largest summed top-k score."""
    finite = torch.isfinite(score) & (score > float(score_gate))
    if not bool(finite.any()):
        return None, None

    orig = orig[finite].long()
    root = roots[cand[finite].long()]
    score = score[finite].float()
    scale = int(total_queries)
    pair_key = orig * scale + root
    uniq, inv = torch.unique(pair_key, return_inverse=True)
    agg = torch.zeros(uniq.numel(), device=score.device, dtype=score.dtype)
    agg.scatter_add_(0, inv, score)

    uniq_orig = torch.div(uniq, scale, rounding_mode="floor")
    uniq_root = uniq.remainder(scale)
    best_score = torch.full((n_total,), float("-inf"), device=score.device, dtype=score.dtype)
    best_score.scatter_reduce_(0, uniq_orig, agg, reduce="amax", include_self=True)
    keep = agg == best_score[uniq_orig]
    if not bool(keep.any()):
        return None, None

    chosen_orig = uniq_orig[keep]
    chosen_root = uniq_root[keep]
    chosen_score = agg[keep]
    order = torch.argsort(chosen_orig)
    chosen_orig = chosen_orig[order]
    chosen_root = chosen_root[order]
    chosen_score = chosen_score[order]
    unique_orig, counts = torch.unique_consecutive(chosen_orig, return_counts=True)
    starts = counts.cumsum(0) - counts

    predicted = torch.full((n_total,), -1, device=score.device, dtype=torch.long)
    hit_scores = torch.full((n_total,), float("-inf"), device=score.device, dtype=score.dtype)
    predicted[unique_orig] = chosen_root[starts]
    hit_scores[unique_orig] = chosen_score[starts]
    return predicted, hit_scores


@torch.no_grad()
def _restore_from_topk_components(
    predicted,
    orig,
    cand,
    score,
    roots,
    full_data,
    clf_keep,
    min_score=0.01,
    max_conflict_size=0,
    min_target_size=3,
    unique_layer=True,
):
    """Use non-winning top-k query candidates as conservative fallback hits."""
    if orig.numel() == 0 or roots.numel() == 0:
        return predicted

    target = roots[cand.long()]
    active = predicted >= 0
    max_label = max(int(roots.max().item()) + 1, int(predicted[active].max().item()) + 1 if bool(active.any()) else 0)
    if max_label <= 0:
        return predicted
    label_sizes = torch.zeros(max_label, device=predicted.device, dtype=torch.long)
    if bool(active.any()):
        label_sizes.scatter_add_(0, predicted[active].long(), torch.ones_like(predicted[active], dtype=torch.long))

    current = predicted[orig]
    current_size = torch.zeros_like(current, dtype=torch.long)
    current_active = current >= 0
    if bool(current_active.any()):
        current_size[current_active] = label_sizes[current[current_active].long()]

    target_size = label_sizes[target.clamp_max(max_label - 1)]
    valid = (
        torch.isfinite(score)
        & (score > float(min_score))
        & clf_keep[orig]
        & (target >= 0)
        & (target < max_label)
        & (target_size >= int(min_target_size))
        & ((current < 0) | (current_size <= int(max_conflict_size)))
        & (current != target)
    )
    if not bool(valid.any()):
        return predicted

    orig_v = orig[valid].long()
    target_v = target[valid].long()
    score_v = score[valid].float()
    best_score = torch.full((predicted.numel(),), float("-inf"), device=predicted.device, dtype=score_v.dtype)
    best_score.scatter_reduce_(0, orig_v, score_v, reduce="amax", include_self=True)
    keep = score_v == best_score[orig_v]
    if not bool(keep.any()):
        return predicted

    orig_v = orig_v[keep]
    target_v = target_v[keep]
    score_v = score_v[keep]
    order = torch.argsort(score_v, descending=True)
    orig_v = orig_v[order]
    target_v = target_v[order]

    out = predicted.clone()
    has_layer = bool(unique_layer and hasattr(full_data, "layer") and full_data.layer is not None)
    layer_sets = {}
    if has_layer and bool(active.any()):
        active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
        for label_t, layer_t in zip(
            predicted[active_idx].detach().cpu().tolist(),
            full_data.layer[active_idx].detach().cpu().tolist(),
        ):
            layer_sets.setdefault(int(label_t), set()).add(int(layer_t))

    for hit_t, label_t in zip(orig_v.detach().cpu().tolist(), target_v.detach().cpu().tolist()):
        hit = int(hit_t)
        label = int(label_t)
        cur = int(out[hit].item())
        if cur == label:
            continue
        if cur >= 0 and int(label_sizes[cur].item()) > int(max_conflict_size):
            continue
        if label >= label_sizes.numel() or int(label_sizes[label].item()) < int(min_target_size):
            continue
        if has_layer:
            hit_layer = int(full_data.layer[hit].item())
            if hit_layer in layer_sets.get(label, set()):
                continue
        if cur >= 0:
            label_sizes[cur] -= 1
        out[hit] = label
        label_sizes[label] += 1
        if has_layer:
            layer_sets.setdefault(label, set()).add(int(full_data.layer[hit].item()))
    return out


@torch.no_grad()
def _restore_from_window_candidates(
    predicted,
    orig,
    cand,
    score,
    clf_keep,
    min_size=3,
    min_new_hits=3,
    min_score=0.0,
    max_conflict_size=2,
    min_new_frac=0.6,
):
    """Restore small missing fragments from raw per-window decoder clusters.

    This uses the base/shifted window top-1 clusters as candidate fragments,
    but only writes hits that are currently unassigned or belong to tiny
    clusters. It is intentionally conservative to avoid damaging already
    countable tracks.
    """
    if orig.numel() == 0:
        return predicted

    valid = torch.isfinite(score) & (score > float(min_score)) & clf_keep[orig]
    if not bool(valid.any()):
        return predicted

    orig = orig[valid].long()
    cand = cand[valid].long()
    score = score[valid].float()
    candidate_ids, inv, counts = torch.unique(cand, return_inverse=True, return_counts=True)
    if candidate_ids.numel() == 0:
        return predicted

    active = predicted >= 0
    protected_size = torch.zeros_like(predicted, dtype=torch.long)
    if bool(active.any()):
        active_ids, active_inv, active_counts = torch.unique(
            predicted[active], return_inverse=True, return_counts=True
        )
        del active_ids
        protected_size[active] = active_counts[active_inv]

    allowed_hits = (predicted[orig] < 0) | (protected_size[orig] <= int(max_conflict_size))
    allowed_counts = torch.zeros(candidate_ids.numel(), device=predicted.device, dtype=torch.long)
    allowed_counts.scatter_add_(0, inv, allowed_hits.long())
    mean_scores = scatter_mean(score.unsqueeze(1), inv, dim=0, dim_size=candidate_ids.numel()).squeeze(1)
    candidate_mask = (
        (counts >= int(min_size))
        & (allowed_counts >= int(min_new_hits))
        & (allowed_counts.float() / counts.float().clamp_min(1.0) >= float(min_new_frac))
    )
    if not bool(candidate_mask.any()):
        return predicted

    priority = allowed_counts.float() + 0.01 * mean_scores
    rows = torch.nonzero(candidate_mask, as_tuple=False).squeeze(1)
    _, row_order = priority[rows].sort(descending=True)
    rows = rows[row_order]

    order = torch.argsort(inv)
    inv_sorted = inv[order]
    orig_sorted = orig[order]
    _, sorted_counts = torch.unique_consecutive(inv_sorted, return_counts=True)
    starts = sorted_counts.cumsum(0) - sorted_counts

    out = predicted.clone()
    used = torch.zeros_like(predicted, dtype=torch.bool)
    next_label = int(out[out >= 0].max().item()) + 1 if bool((out >= 0).any()) else 0
    for row_t in rows.detach().cpu().tolist():
        row = int(row_t)
        start = int(starts[row].item())
        end = start + int(sorted_counts[row].item())
        hits = orig_sorted[start:end]
        can_write = ((out[hits] < 0) | (protected_size[hits] <= int(max_conflict_size))) & (~used[hits])
        if int(can_write.sum().item()) < int(min_new_hits):
            continue
        write_hits = hits[can_write]
        out[write_hits] = next_label
        used[write_hits] = True
        next_label += 1
    return out


@torch.no_grad()
def _bridge_clusters_from_window_candidates(
    predicted,
    orig,
    cand,
    score,
    clf_keep,
    min_score=0.005,
    min_candidate_size=3,
    min_label_overlap=1,
    max_cluster_size=3,
    max_merged_size=8,
):
    """Merge small current fragments when one window query covers them together."""
    if orig.numel() == 0 or not bool((predicted >= 0).any()):
        return predicted

    valid = torch.isfinite(score) & (score > float(min_score)) & clf_keep[orig]
    if not bool(valid.any()):
        return predicted

    active = predicted >= 0
    max_label = int(predicted[active].max().item()) + 1
    label_sizes = torch.bincount(predicted[active], minlength=max_label)

    orig_v = orig[valid].long()
    cand_v = cand[valid].long()
    labels_v = predicted[orig_v]
    label_valid = labels_v >= 0
    if not bool(label_valid.any()):
        return predicted
    cand_v = cand_v[label_valid]
    labels_v = labels_v[label_valid].long()

    scale = max_label
    keys = cand_v * scale + labels_v
    uniq, overlap_counts = torch.unique(keys, return_counts=True)
    cand_ids = torch.div(uniq, scale, rounding_mode="floor")
    label_ids = uniq.remainder(scale)
    keep = overlap_counts >= int(min_label_overlap)
    keep &= label_sizes[label_ids] <= int(max_cluster_size)
    if not bool(keep.any()):
        return predicted

    cand_ids = cand_ids[keep]
    label_ids = label_ids[keep]
    overlap_counts = overlap_counts[keep]
    order = torch.argsort(cand_ids)
    cand_ids = cand_ids[order]
    label_ids = label_ids[order]
    overlap_counts = overlap_counts[order]
    unique_cand, group_counts = torch.unique_consecutive(cand_ids, return_counts=True)
    del unique_cand
    starts = group_counts.cumsum(0) - group_counts

    parent = list(range(max_label))
    rank = [0] * max_label
    comp_size = [int(v) for v in label_sizes.detach().cpu().tolist()]
    for start_t, count_t in zip(starts.detach().cpu().tolist(), group_counts.detach().cpu().tolist()):
        if int(count_t) < 2:
            continue
        start = int(start_t)
        end = start + int(count_t)
        if int(overlap_counts[start:end].sum().item()) < int(min_candidate_size):
            continue
        labels = label_ids[start:end].detach().cpu().tolist()
        # Merge around the best-supported fragment first, respecting a small
        # combined-size cap to keep the bridge conservative.
        local_counts = overlap_counts[start:end].detach().cpu().tolist()
        center = labels[int(np.argmax(local_counts))]
        for label in labels:
            if int(label) == int(center):
                continue
            root_a = _find_root(parent, int(center))
            root_b = _find_root(parent, int(label))
            if root_a == root_b:
                continue
            if comp_size[root_a] + comp_size[root_b] > int(max_merged_size):
                continue
            size_sum = comp_size[root_a] + comp_size[root_b]
            _union_roots(parent, rank, root_a, root_b)
            new_root = _find_root(parent, root_a)
            comp_size[new_root] = size_sum

    roots = torch.as_tensor(
        [_find_root(parent, i) for i in range(max_label)],
        device=predicted.device,
        dtype=torch.long,
    )
    if torch.equal(roots, torch.arange(max_label, device=predicted.device, dtype=torch.long)):
        return predicted
    out = predicted.clone()
    active = out >= 0
    out[active] = roots[out[active]]
    return out


@torch.no_grad()
def _bridge_small_clusters_from_extra_windows(
    predicted,
    pred_list,
    sub_events,
    full_data,
    max_cluster_size=2,
    max_merged_size=6,
    min_score=0.003,
    min_label_hits=1,
    active_prob_power=1.0,
    active_prob_floor=0.0,
    use_logit_scores=False,
    score_mode="prob",
    score_bf16=False,
    max_hits=0,
    active_query_topk=0,
):
    if not pred_list or not bool((predicted >= 0).any()):
        return predicted

    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not bool(active.any()):
        return predicted
    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    max_label = int(predicted[active].max().item()) + 1
    label_sizes = torch.bincount(predicted[active], minlength=max_label)
    hit_sizes = torch.zeros_like(predicted, dtype=torch.long)
    hit_sizes[active_idx] = label_sizes[predicted[active].long()]
    small_hits = active_idx[hit_sizes[active_idx] <= int(max_cluster_size)]
    if int(max_hits) > 0 and small_hits.numel() > int(max_hits):
        small_hits = small_hits[: int(max_hits)]
    if small_hits.numel() == 0:
        return predicted

    query_chunks = []
    label_chunks = []
    n_total = int(predicted.numel())
    query_offset = 0
    for (pred_masks, pred_logits, point_order), sub in zip(pred_list, sub_events):
        orig_idx = sub["orig_idx"]
        n_sub_valid = int(orig_idx.numel())
        if point_order is not None:
            order = point_order.to(device=orig_idx.device, dtype=torch.long)
            ordered_orig = orig_idx.index_select(0, order)
        else:
            ordered_orig = orig_idx
        pos_lookup = torch.full((n_total,), -1, device=predicted.device, dtype=torch.long)
        pos_lookup[ordered_orig] = torch.arange(n_sub_valid, device=predicted.device, dtype=torch.long)
        cols = pos_lookup[small_hits]
        in_window = cols >= 0
        if not bool(in_window.any()):
            query_offset += int(pred_masks.shape[1])
            continue
        hits = small_hits[in_window]
        cols = cols[in_window]
        idx, score, n_queries = _sub_event_column_winning_queries(
            pred_masks,
            pred_logits,
            cols,
            active_prob_power=active_prob_power,
            active_prob_floor=active_prob_floor,
            active_query_topk=active_query_topk,
            use_logit_scores=use_logit_scores,
            score_mode=score_mode,
            score_bf16=score_bf16,
        )
        keep = torch.isfinite(score) & (score >= float(min_score))
        if bool(keep.any()):
            query_chunks.append(idx[keep].long() + int(query_offset))
            label_chunks.append(predicted[hits[keep]].long())
        query_offset += int(n_queries)
    if not query_chunks:
        return predicted

    query_ids = torch.cat(query_chunks).long()
    labels = torch.cat(label_chunks).long()
    scale = int(max_label)
    keys = query_ids * scale + labels
    uniq, overlap_counts = torch.unique(keys, return_counts=True)
    query_ids = torch.div(uniq, scale, rounding_mode="floor")
    labels = uniq.remainder(scale)
    keep = (overlap_counts >= int(min_label_hits)) & (label_sizes[labels] <= int(max_cluster_size))
    if not bool(keep.any()):
        return predicted
    query_ids = query_ids[keep]
    labels = labels[keep]
    overlap_counts = overlap_counts[keep]
    order = torch.argsort(query_ids)
    query_ids = query_ids[order]
    labels = labels[order]
    overlap_counts = overlap_counts[order]
    _, group_counts = torch.unique_consecutive(query_ids, return_counts=True)
    starts = group_counts.cumsum(0) - group_counts

    parent = list(range(max_label))
    rank = [0] * max_label
    comp_size = [int(v) for v in label_sizes.detach().cpu().tolist()]
    for start_t, count_t in zip(starts.detach().cpu().tolist(), group_counts.detach().cpu().tolist()):
        count = int(count_t)
        if count < 2:
            continue
        start = int(start_t)
        end = start + count
        local_labels = labels[start:end].detach().cpu().tolist()
        local_counts = overlap_counts[start:end].detach().cpu().tolist()
        center = int(local_labels[int(np.argmax(local_counts))])
        for label_t in local_labels:
            label = int(label_t)
            if label == center:
                continue
            root_a = _find_root(parent, center)
            root_b = _find_root(parent, label)
            if root_a == root_b:
                continue
            if comp_size[root_a] + comp_size[root_b] > int(max_merged_size):
                continue
            size_sum = comp_size[root_a] + comp_size[root_b]
            _union_roots(parent, rank, root_a, root_b)
            comp_size[_find_root(parent, root_a)] = size_sum

    roots = torch.as_tensor(
        [_find_root(parent, i) for i in range(max_label)],
        device=predicted.device,
        dtype=torch.long,
    )
    if torch.equal(roots, torch.arange(max_label, device=predicted.device, dtype=torch.long)):
        return predicted
    out = predicted.clone()
    active = out >= 0
    out[active] = roots[out[active].long()]
    return out


@torch.no_grad()
def _pad_size2_from_window_candidates(
    predicted,
    orig,
    cand,
    score,
    full_data,
    clf_keep,
    min_score=0.005,
    extra_min_score=0.005,
    min_overlap=2,
    unique_layer=True,
    max_proposals_per_label=0,
):
    """Fast size-2 padding using hits from the same raw window query."""
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not bool(active.any()) or orig.numel() == 0:
        return predicted

    active_ids, _, counts = torch.unique(predicted[active], return_inverse=True, return_counts=True)
    size2_ids = active_ids[counts == 2]
    if size2_ids.numel() == 0:
        return predicted

    valid = torch.isfinite(score) & (score > float(min_score)) & clf_keep[orig]
    if not bool(valid.any()):
        return predicted
    orig_v = orig[valid].long()
    cand_v = cand[valid].long()
    score_v = score[valid].float()
    labels_v = predicted[orig_v]

    in_size2 = torch.isin(labels_v, size2_ids)
    if not bool(in_size2.any()):
        return predicted

    label_scale = int(predicted[predicted >= 0].max().item()) + 1
    size2_scores = score_v[in_size2]
    keys = cand_v[in_size2] * label_scale + labels_v[in_size2].long()
    uniq, inv_key, overlap = torch.unique(keys, return_inverse=True, return_counts=True)
    pair_scores = scatter_mean(size2_scores.unsqueeze(1), inv_key, dim=0, dim_size=uniq.numel()).squeeze(1)
    keep = overlap >= int(min_overlap)
    if not bool(keep.any()):
        return predicted

    proposal_cand = torch.div(uniq[keep], label_scale, rounding_mode="floor")
    proposal_label = uniq[keep].remainder(label_scale)
    proposal_overlap = overlap[keep]
    proposal_score = pair_scores[keep]
    if int(max_proposals_per_label) > 0 and proposal_label.numel() > 0:
        priority = proposal_overlap.float() + 0.01 * proposal_score.float()
        order_cpu = torch.argsort(priority, descending=True).detach().cpu().tolist()
        kept = []
        seen = defaultdict(int)
        cap = int(max_proposals_per_label)
        labels_cpu = proposal_label.detach().cpu().tolist()
        for idx in order_cpu:
            label_i = int(labels_cpu[idx])
            if seen[label_i] >= cap:
                continue
            seen[label_i] += 1
            kept.append(idx)
        if not kept:
            return predicted
        kept_t = torch.as_tensor(kept, device=proposal_label.device, dtype=torch.long)
        proposal_cand = proposal_cand[kept_t]
        proposal_label = proposal_label[kept_t]
        proposal_overlap = proposal_overlap[kept_t]
        proposal_score = proposal_score[kept_t]
    order = torch.argsort(proposal_overlap.float() + 0.01 * proposal_score.float(), descending=True)
    proposal_cand = proposal_cand[order]
    proposal_label = proposal_label[order]

    cand_order = torch.argsort(cand_v)
    cand_sorted = cand_v[cand_order]
    orig_sorted = orig_v[cand_order]
    score_sorted = score_v[cand_order]
    unique_cand, cand_counts = torch.unique_consecutive(cand_sorted, return_counts=True)
    cand_starts = cand_counts.cumsum(0) - cand_counts
    cand_ranges = {
        int(cid): (int(start), int(count))
        for cid, start, count in zip(
            unique_cand.detach().cpu().tolist(),
            cand_starts.detach().cpu().tolist(),
            cand_counts.detach().cpu().tolist(),
        )
    }

    has_layer = bool(unique_layer and hasattr(full_data, "layer") and full_data.layer is not None)
    out = predicted.clone()
    max_label = int(predicted[predicted >= 0].max().item()) + 1
    label_sizes = torch.bincount(predicted[predicted >= 0], minlength=max_label)
    cluster_layers = {}
    if has_layer:
        active_size2 = active & torch.isin(predicted, size2_ids)
        size2_hits = torch.nonzero(active_size2, as_tuple=False).squeeze(1)
        for hit_t, label_t, layer_t in zip(
            size2_hits.detach().cpu().tolist(),
            predicted[size2_hits].detach().cpu().tolist(),
            full_data.layer[size2_hits].detach().cpu().tolist(),
        ):
            del hit_t
            cluster_layers.setdefault(int(label_t), set()).add(int(layer_t))
    used = torch.zeros_like(predicted, dtype=torch.bool)
    for cand_id_t, label_t in zip(proposal_cand.detach().cpu().tolist(), proposal_label.detach().cpu().tolist()):
        label = int(label_t)
        if label >= label_sizes.numel() or int(label_sizes[label].item()) != 2:
            continue
        cand_range = cand_ranges.get(int(cand_id_t))
        if cand_range is None:
            continue
        start, count = cand_range
        end = start + count
        hits = orig_sorted[start:end]
        scores = score_sorted[start:end]
        can_add = (out[hits] < 0) & (~used[hits]) & (scores >= float(extra_min_score))
        if has_layer:
            existing_layers = cluster_layers.get(label, set())
            if existing_layers:
                forbidden = torch.as_tensor(
                    sorted(existing_layers),
                    device=full_data.layer.device,
                    dtype=full_data.layer.dtype,
                )
                can_add &= ~torch.isin(full_data.layer[hits], forbidden)
        if not bool(can_add.any()):
            continue
        add_hits = hits[can_add]
        add_scores = scores[can_add]
        best = int(add_scores.argmax().item())
        hit = add_hits[best]
        out[hit] = label
        label_sizes[label] += 1
        if has_layer:
            cluster_layers.setdefault(label, set()).add(int(full_data.layer[hit].item()))
        used[hit] = True
    return out


@torch.no_grad()
def _split_clusters_from_window_candidates(
    predicted,
    full_data,
    orig,
    cand,
    score,
    clf_keep,
    min_score=0.005,
    min_cluster_size=5,
    max_cluster_size=12,
    min_part_size=3,
    min_remaining_size=3,
    min_inside_frac=0.6,
    max_part_frac=0.7,
    min_duplicate_layers=0,
    max_part_duplicate_layers=-1,
    require_remainder_candidate=False,
    min_remainder_candidate_hits=3,
    max_splits=128,
):
    """Split overmerged clusters using raw window-query subsets as templates."""
    active = predicted >= 0
    if orig.numel() == 0 or not bool(active.any()):
        return predicted

    max_label = int(predicted[active].max().item()) + 1
    cluster_sizes = torch.bincount(predicted[active], minlength=max_label)
    has_layer = bool(hasattr(full_data, "layer") and full_data.layer is not None)
    duplicate_counts = None
    if has_layer and int(min_duplicate_layers) > 0:
        active_idx_all = torch.nonzero(active, as_tuple=False).squeeze(1)
        active_layers = full_data.layer[active_idx_all].long()
        layer_min = int(active_layers.min().item())
        layer_span = max(1, int(active_layers.max().item()) - layer_min + 1)
        layer_keys = predicted[active_idx_all].long() * layer_span + (active_layers - layer_min)
        unique_layer_labels = torch.unique(layer_keys) // layer_span
        unique_layer_counts = torch.bincount(unique_layer_labels, minlength=max_label)
        duplicate_counts = cluster_sizes - unique_layer_counts.to(
            device=cluster_sizes.device,
            dtype=cluster_sizes.dtype,
        )
    valid = torch.isfinite(score) & (score > float(min_score)) & clf_keep[orig]
    if not bool(valid.any()):
        return predicted

    orig_v = orig[valid].long()
    cand_v = cand[valid].long()
    cand_total_counts = torch.bincount(cand_v, minlength=int(cand_v.max().item()) + 1)
    labels_v = predicted[orig_v]
    in_cluster = labels_v >= 0
    if not bool(in_cluster.any()):
        return predicted
    orig_v = orig_v[in_cluster]
    cand_v = cand_v[in_cluster]
    labels_v = labels_v[in_cluster].long()

    # Count how many hits of each raw window query land in each current cluster.
    pair_scale = max_label
    pair_key = cand_v * pair_scale + labels_v
    uniq_pair, pair_counts = torch.unique(pair_key, return_counts=True)
    pair_cand = torch.div(uniq_pair, pair_scale, rounding_mode="floor")
    pair_label = uniq_pair.remainder(pair_scale)

    csize = cluster_sizes[pair_label]
    inside_frac = pair_counts.float() / cand_total_counts[pair_cand].float().clamp_min(1.0)
    part_frac = pair_counts.float() / csize.float().clamp_min(1.0)
    keep = (
        (pair_counts >= int(min_part_size))
        & (csize >= int(min_cluster_size))
        & (csize <= int(max_cluster_size))
        & ((csize - pair_counts) >= int(min_remaining_size))
        & (inside_frac >= float(min_inside_frac))
        & (part_frac <= float(max_part_frac))
    )
    if duplicate_counts is not None:
        keep &= duplicate_counts[pair_label] >= int(min_duplicate_layers)
    if not bool(keep.any()):
        return predicted

    rows = torch.nonzero(keep, as_tuple=False).squeeze(1)
    priority = pair_counts[rows].float() + inside_frac[rows]
    _, order = priority.sort(descending=True)
    rows = rows[order]
    if int(max_splits) > 0 and rows.numel() > int(max_splits):
        rows = rows[: int(max_splits)]

    out = predicted.clone()
    split_labels = set()
    next_label = int(out[out >= 0].max().item()) + 1 if bool((out >= 0).any()) else 0
    for row_t in rows.detach().cpu().tolist():
        row = int(row_t)
        label = int(pair_label[row].item())
        if label in split_labels:
            continue
        cand_id = int(pair_cand[row].item())
        current_hits = torch.nonzero(out == label, as_tuple=False).squeeze(1)
        if current_hits.numel() < int(min_cluster_size) or current_hits.numel() > int(max_cluster_size):
            continue
        hit_mask = (cand_v == cand_id) & (labels_v == label)
        part_hits = orig_v[hit_mask]
        # Some hits may have moved due to an earlier split.
        part_hits = part_hits[out[part_hits] == label]
        n_part = int(part_hits.numel())
        n_cluster = int(current_hits.numel())
        if n_part < int(min_part_size) or n_cluster - n_part < int(min_remaining_size):
            continue
        if n_part / max(1, n_cluster) > float(max_part_frac):
            continue
        if has_layer and int(max_part_duplicate_layers) >= 0:
            part_layers = full_data.layer[part_hits]
            part_dup = n_part - int(torch.unique(part_layers).numel())
            remaining_hits = current_hits[~torch.isin(current_hits, part_hits)]
            remaining_layers = full_data.layer[remaining_hits]
            remaining_dup = int(remaining_hits.numel()) - int(torch.unique(remaining_layers).numel())
            if part_dup > int(max_part_duplicate_layers) or remaining_dup > int(max_part_duplicate_layers):
                continue
        if bool(require_remainder_candidate):
            same_label_other = (labels_v == label) & (cand_v != cand_id)
            if not bool(same_label_other.any()):
                continue
            other_hits = orig_v[same_label_other]
            other_cands = cand_v[same_label_other]
            keep_other = (out[other_hits] == label) & (~torch.isin(other_hits, part_hits))
            if not bool(keep_other.any()):
                continue
            _, other_counts = torch.unique(other_cands[keep_other], return_counts=True)
            if other_counts.numel() == 0 or int(other_counts.max().item()) < int(min_remainder_candidate_hits):
                continue
        out[part_hits] = next_label
        next_label += 1
        split_labels.add(label)
    return out


@torch.no_grad()
def _build_decoder_overlap_stitched_assignments(
    pred_list,
    sub_events,
    full_data,
    clf_keep,
    score_gate=0.02,
    min_overlap=1,
    min_overlap_frac=0.6,
    mask_thres=0.0,
    active_prob_threshold=0.0,
    active_prob_power=1.0,
    active_prob_floor=0.0,
    active_query_topk=0,
    decoder_use_logit_scores=False,
    decoder_score_mode="prob",
    decoder_score_bf16=False,
    query_topk=1,
    union_topk=True,
    topk_score_gate=None,
    topk_assign=False,
    topk_assign_score_gate=0.0,
    stitch_source_matrix=False,
    restore_topk_components=False,
    restore_topk_min_score=0.01,
    restore_topk_max_conflict_size=0,
    restore_topk_min_target_size=3,
    restore_topk_unique_layer=True,
    restore_window_clusters=False,
    restore_window_min_size=3,
    restore_window_min_new_hits=3,
    restore_window_min_score=0.0,
    restore_window_max_conflict_size=2,
    restore_window_min_new_frac=0.6,
    bridge_window_clusters=False,
    bridge_window_min_score=0.005,
    bridge_window_min_candidate_size=3,
    bridge_window_min_label_overlap=1,
    bridge_window_max_cluster_size=3,
    bridge_window_max_merged_size=8,
    pad_window_size2=False,
    pad_window_min_score=0.005,
    pad_window_extra_min_score=0.005,
    pad_window_min_overlap=2,
    pad_window_unique_layer=True,
    pad_window_max_proposals_per_label=0,
    split_window_clusters=False,
    split_window_min_score=0.005,
    split_window_min_cluster_size=5,
    split_window_max_cluster_size=12,
    split_window_min_part_size=3,
    split_window_min_remaining_size=3,
    split_window_min_inside_frac=0.6,
    split_window_max_part_frac=0.7,
    split_window_min_duplicate_layers=0,
    split_window_max_part_duplicate_layers=-1,
    split_window_require_remainder_candidate=False,
    split_window_min_remainder_candidate_hits=3,
    split_window_max_splits=128,
    return_scores=False,
):
    """Merge query ids that claim the same physical hit in overlapping windows.

    The decoder split is intentionally overlapped, so a true track is often
    represented by different query ids in the base and shifted phi windows.
    Per-hit max assignment alone keeps those ids separate. This pass first
    records every window's winning query for each original hit, then unions
    query ids whose shared-hit overlap covers a large enough fraction of the
    smaller candidate.
    """
    device = full_data.x.device
    n_total = full_data.x.shape[0]
    max_prob = torch.full((n_total,), float("-inf"), device=device)
    predicted = torch.full((n_total,), -1, device=device, dtype=torch.long)
    total_queries = 0
    orig_chunks = []
    cand_chunks = []
    score_chunks = []
    source_chunks = []
    rank_chunks = []
    topk = max(1, int(query_topk))
    union_gate = float(score_gate if topk_score_gate is None else topk_score_gate)
    fast_top1 = (
        topk == 1
        and not bool(topk_assign)
        and not bool(restore_topk_components)
        and not bool(restore_window_clusters)
        and not bool(bridge_window_clusters)
        and not bool(pad_window_size2)
        and not bool(split_window_clusters)
    )

    if fast_top1:
        source_cands = None
        if bool(stitch_source_matrix):
            source_cands = torch.full(
                (len(pred_list), n_total),
                -1,
                device=device,
                dtype=torch.long,
            )
        for sub_i, ((pred_masks, pred_logits, point_order), sub) in enumerate(zip(pred_list, sub_events)):
            orig_idx, idx_max, scores_max, n_queries, _ = _sub_event_winning_queries(
                pred_masks,
                pred_logits,
                point_order,
                sub,
                active_prob_threshold=active_prob_threshold,
                active_prob_power=active_prob_power,
                active_prob_floor=active_prob_floor,
                active_query_topk=active_query_topk,
                use_logit_scores=decoder_use_logit_scores,
                score_mode=decoder_score_mode,
                score_bf16=decoder_score_bf16,
            )
            cand = idx_max + total_queries
            better = scores_max > max_prob[orig_idx]
            if better.any():
                idx = orig_idx[better]
                max_prob[idx] = scores_max[better]
                predicted[idx] = cand[better]

            gated = torch.isfinite(scores_max) & (scores_max > union_gate)
            if bool(gated.any()):
                gated_orig = orig_idx[gated].detach()
                gated_cand = cand[gated].detach()
                cand_chunks.append(gated_cand)
                if source_cands is not None:
                    source_cands[int(sub_i), gated_orig] = gated_cand
                else:
                    orig_chunks.append(gated_orig)
                    source_chunks.append(torch.full_like(gated_cand, int(sub_i)))
            total_queries += n_queries

        predicted[max_prob < float(mask_thres)] = -1
        if not cand_chunks:
            predicted[~clf_keep] = -1
            if return_scores:
                return predicted, max_prob
            return predicted

        cand = torch.cat(cand_chunks).long()
        if total_queries <= 1:
            predicted[~clf_keep] = -1
            if return_scores:
                return predicted, max_prob
            return predicted

        pair_keys = None
        sizes = torch.bincount(cand, minlength=total_queries)
        if source_cands is not None:
            pair_chunks = []
            scale = int(total_queries)
            for left in range(source_cands.shape[0] - 1):
                left_cand = source_cands[left]
                for right in range(left + 1, source_cands.shape[0]):
                    right_cand = source_cands[right]
                    keep = (left_cand >= 0) & (right_cand >= 0) & (left_cand != right_cand)
                    if not bool(keep.any()):
                        continue
                    a = left_cand[keep]
                    b = right_cand[keep]
                    lo = torch.minimum(a, b)
                    hi = torch.maximum(a, b)
                    pair_chunks.append(lo * scale + hi)
            if pair_chunks:
                pair_keys = torch.cat(pair_chunks)
        else:
            orig = torch.cat(orig_chunks).long()
            source = torch.cat(source_chunks).long()
            order = torch.argsort(orig)
            sorted_orig = orig[order]
            sorted_cand = cand[order]
            sorted_source = source[order]
            _, group_counts = torch.unique_consecutive(sorted_orig, return_counts=True)
            pair_keys = _pair_keys_from_grouped_candidates(
                sorted_cand, sorted_source, group_counts, total_queries
            )

        roots = None
        if pair_keys is not None and pair_keys.numel() > 0:
            uniq_pair_keys, counts = torch.unique(pair_keys, return_counts=True)
            a = torch.div(uniq_pair_keys, total_queries, rounding_mode="floor")
            b = uniq_pair_keys.remainder(total_queries)
            denom = torch.minimum(sizes[a], sizes[b]).clamp_min(1)
            keep = (counts >= int(min_overlap)) & (
                counts.float() / denom.float() >= float(min_overlap_frac)
            )
            if bool(keep.any()):
                parent = list(range(total_queries))
                rank = [0] * total_queries
                a_cpu = a[keep].detach().cpu().tolist()
                b_cpu = b[keep].detach().cpu().tolist()
                for a_i, b_i in zip(a_cpu, b_cpu):
                    _union_roots(parent, rank, int(a_i), int(b_i))
                roots = torch.as_tensor(
                    [_find_root(parent, i) for i in range(total_queries)],
                    device=device,
                    dtype=torch.long,
                )

        if roots is not None:
            active = predicted >= 0
            if bool(active.any()):
                predicted[active] = roots[predicted[active]]

        predicted[~clf_keep] = -1
        if _DEBUG:
            n_unique = int(torch.unique(predicted[predicted >= 0]).numel())
            print(f"[pp] stitched-fast unique_clusters={n_unique} total_queries={total_queries}")
        if return_scores:
            return predicted, max_prob
        return predicted

    for sub_i, ((pred_masks, pred_logits, point_order), sub) in enumerate(zip(pred_list, sub_events)):
        orig_idx, idx_top, scores_top, n_queries, _ = _sub_event_topk_queries(
            pred_masks,
            pred_logits,
            point_order,
            sub,
            active_prob_threshold=active_prob_threshold,
            active_prob_power=active_prob_power,
            active_prob_floor=active_prob_floor,
            active_query_topk=active_query_topk,
            topk=topk,
            use_logit_scores=decoder_use_logit_scores,
            score_mode=decoder_score_mode,
            score_bf16=decoder_score_bf16,
        )
        idx_max = idx_top[:, 0]
        scores_max = scores_top[:, 0]
        cand = idx_max + total_queries
        better = scores_max > max_prob[orig_idx]
        if better.any():
            idx = orig_idx[better]
            max_prob[idx] = scores_max[better]
            predicted[idx] = cand[better]
        cand_top = idx_top + total_queries
        orig_top = orig_idx[:, None].expand_as(cand_top)
        finite = torch.isfinite(scores_top)
        if finite.any():
            orig_chunks.append(orig_top[finite].detach())
            cand_chunks.append(cand_top[finite].detach())
            score_chunks.append(scores_top[finite].detach())
            source_chunks.append(torch.full_like(cand_top[finite], int(sub_i)))
            rank_top = torch.arange(topk, device=device, dtype=torch.long)[None, :].expand_as(cand_top)
            rank_chunks.append(rank_top[finite].detach())
        total_queries += n_queries

    predicted[max_prob < float(mask_thres)] = -1
    if total_queries <= 0:
        predicted[~clf_keep] = -1
        if return_scores:
            return predicted, max_prob
        return predicted

    parent = list(range(total_queries))
    rank = [0] * total_queries
    if orig_chunks:
        orig = torch.cat(orig_chunks).long()
        cand = torch.cat(cand_chunks).long()
        score = torch.cat(score_chunks).float()
        source = torch.cat(source_chunks).long()
        rank_pos = torch.cat(rank_chunks).long()
    else:
        orig = torch.empty(0, device=device, dtype=torch.long)
        cand = torch.empty(0, device=device, dtype=torch.long)
        score = torch.empty(0, device=device, dtype=torch.float32)
        source = torch.empty(0, device=device, dtype=torch.long)
        rank_pos = torch.empty(0, device=device, dtype=torch.long)
    gated = score > union_gate
    if not bool(union_topk):
        gated &= rank_pos == 0
    sizes = torch.bincount(cand[gated], minlength=total_queries)

    pair_keys = None
    if bool(gated.any()):
        # Each physical hit usually appears in the base and shifted decoder
        # windows. With top-k enabled, keep all small per-hit combinations on
        # GPU so the shifted-window ensemble stays latency friendly.
        orig_g = orig[gated]
        cand_g = cand[gated]
        source_g = source[gated]
        order = torch.argsort(orig_g)
        sorted_orig = orig_g[order]
        sorted_cand = cand_g[order]
        sorted_source = source_g[order]
        _, group_counts = torch.unique_consecutive(sorted_orig, return_counts=True)
        pair_keys = _pair_keys_from_grouped_candidates(
            sorted_cand, sorted_source, group_counts, total_queries
        )

    if pair_keys is not None and pair_keys.numel() > 0:
        uniq_pair_keys, counts = torch.unique(pair_keys, return_counts=True)
        a = torch.div(uniq_pair_keys, int(total_queries), rounding_mode="floor")
        b = uniq_pair_keys.remainder(int(total_queries))
        denom = torch.minimum(sizes[a], sizes[b]).clamp_min(1)
        keep = (counts >= int(min_overlap)) & (
            counts.float() / denom.float() >= float(min_overlap_frac)
        )
        if bool(keep.any()):
            a_cpu = a[keep].detach().cpu().tolist()
            b_cpu = b[keep].detach().cpu().tolist()
            for a_i, b_i in zip(a_cpu, b_cpu):
                _union_roots(parent, rank, int(a_i), int(b_i))

    roots = torch.as_tensor(
        [_find_root(parent, i) for i in range(total_queries)],
        device=device,
        dtype=torch.long,
    )
    if bool(topk_assign) and orig.numel() > 0:
        topk_pred, topk_scores = _assign_by_topk_components(
            orig,
            cand,
            score,
            roots,
            n_total=n_total,
            total_queries=total_queries,
            score_gate=max(float(mask_thres), float(topk_assign_score_gate)),
        )
        if topk_pred is not None:
            predicted = topk_pred
            max_prob = topk_scores
        else:
            active = predicted >= 0
            predicted[active] = roots[predicted[active]]
    else:
        active = predicted >= 0
        predicted[active] = roots[predicted[active]]
    predicted[~clf_keep] = -1
    if bool(restore_topk_components):
        predicted = _restore_from_topk_components(
            predicted,
            orig,
            cand,
            score,
            roots,
            full_data,
            clf_keep,
            min_score=restore_topk_min_score,
            max_conflict_size=restore_topk_max_conflict_size,
            min_target_size=restore_topk_min_target_size,
            unique_layer=restore_topk_unique_layer,
        )
    if bool(restore_window_clusters):
        predicted = _restore_from_window_candidates(
            predicted,
            orig,
            cand,
            score,
            clf_keep,
            min_size=restore_window_min_size,
            min_new_hits=restore_window_min_new_hits,
            min_score=restore_window_min_score,
            max_conflict_size=restore_window_max_conflict_size,
            min_new_frac=restore_window_min_new_frac,
        )
    if bool(bridge_window_clusters):
        predicted = _bridge_clusters_from_window_candidates(
            predicted,
            orig,
            cand,
            score,
            clf_keep,
            min_score=bridge_window_min_score,
            min_candidate_size=bridge_window_min_candidate_size,
            min_label_overlap=bridge_window_min_label_overlap,
            max_cluster_size=bridge_window_max_cluster_size,
            max_merged_size=bridge_window_max_merged_size,
        )
    if bool(pad_window_size2):
        predicted = _pad_size2_from_window_candidates(
            predicted,
            orig,
            cand,
            score,
            full_data,
            clf_keep,
            min_score=pad_window_min_score,
            extra_min_score=pad_window_extra_min_score,
            min_overlap=pad_window_min_overlap,
            unique_layer=pad_window_unique_layer,
            max_proposals_per_label=pad_window_max_proposals_per_label,
        )
    if bool(split_window_clusters):
        predicted = _split_clusters_from_window_candidates(
            predicted,
            full_data,
            orig,
            cand,
            score,
            clf_keep,
            min_score=split_window_min_score,
            min_cluster_size=split_window_min_cluster_size,
            max_cluster_size=split_window_max_cluster_size,
            min_part_size=split_window_min_part_size,
            min_remaining_size=split_window_min_remaining_size,
            min_inside_frac=split_window_min_inside_frac,
            max_part_frac=split_window_max_part_frac,
            min_duplicate_layers=split_window_min_duplicate_layers,
            max_part_duplicate_layers=split_window_max_part_duplicate_layers,
            require_remainder_candidate=split_window_require_remainder_candidate,
            min_remainder_candidate_hits=split_window_min_remainder_candidate_hits,
            max_splits=split_window_max_splits,
        )
    if _DEBUG:
        n_unique = int(torch.unique(predicted[predicted >= 0]).numel())
        print(f"[pp] stitched unique_clusters={n_unique} total_queries={total_queries}")
    if return_scores:
        return predicted, max_prob
    return predicted


def _l2_normalize(x):
    return F.normalize(x.float(), p=2, dim=1, eps=1e-12)


def _wrap_normalized_phi_diff_torch(x):
    return torch.remainder(x + 1.0, 2.0) - 1.0


@torch.no_grad()
def _pad_size2_clusters(
    predicted,
    full_data,
    full_emb,
    full_clf_scores=None,
    min_sim=0.0,
    clf_floor=0.0,
    clf_ceiling=0.0,
    unique_layer=True,
    topk=8,
    max_candidates=0,
    max_clusters=0,
    max_conflict_size=0,
    geom_z_max=0.0,
    geom_phi_max=0.0,
    geom_only=False,
    geom_clf_weight=0.0,
    rank_clusters_by_clf=True,
    rank_candidates_by_clf=True,
    chunk_size=8192,
    normalized_emb=None,
):
    """Promote promising size-2 clusters to the metric's size-3 threshold."""
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not active.any():
        return predicted

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    active_ids, inv_active, counts = torch.unique(
        predicted[active], return_inverse=True, return_counts=True
    )
    clf_scores = full_clf_scores.squeeze(-1).float() if full_clf_scores is not None else None
    size2_active_rows = torch.nonzero(counts == 2, as_tuple=False).squeeze(1)
    if int(max_clusters) > 0 and size2_active_rows.numel() > int(max_clusters):
        if bool(rank_clusters_by_clf) and clf_scores is not None:
            cluster_clf = scatter_mean(
                clf_scores[active_idx].unsqueeze(1),
                inv_active,
                dim=0,
                dim_size=active_ids.numel(),
            ).squeeze(1)
            _, order = cluster_clf[size2_active_rows].topk(int(max_clusters), largest=True)
            size2_active_rows = size2_active_rows[order]
        else:
            size2_active_rows = size2_active_rows[: int(max_clusters)]
    if size2_active_rows.numel() == 0:
        return predicted
    size2_ids = active_ids[size2_active_rows]

    max_label = int(predicted[active].max().item()) + 1
    label_sizes = torch.bincount(predicted[active], minlength=max_label)

    candidate_mask = valid_mask & (predicted < 0)
    if int(max_conflict_size) > 0:
        hit_sizes = torch.zeros_like(predicted, dtype=torch.long)
        hit_sizes[active_idx] = counts[inv_active]
        candidate_mask |= valid_mask & (predicted >= 0) & (hit_sizes <= int(max_conflict_size))
    if full_clf_scores is not None:
        if clf_floor > 0:
            candidate_mask &= clf_scores >= float(clf_floor)
        if clf_ceiling > 0:
            candidate_mask &= clf_scores <= float(clf_ceiling)
    cand_idx = torch.nonzero(candidate_mask, as_tuple=False).squeeze(1)
    if int(max_candidates) > 0 and cand_idx.numel() > int(max_candidates):
        if bool(rank_candidates_by_clf) and clf_scores is not None:
            _, order = clf_scores[cand_idx].topk(int(max_candidates), largest=True)
            cand_idx = cand_idx[order]
        else:
            cand_idx = cand_idx[: int(max_candidates)]
    if cand_idx.numel() == 0:
        return predicted

    emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
    has_layer = unique_layer and hasattr(full_data, "layer") and full_data.layer is not None

    row_map = torch.full((active_ids.numel(),), -1, device=predicted.device, dtype=torch.long)
    row_map[size2_active_rows] = torch.arange(size2_active_rows.numel(), device=predicted.device)
    active_size2 = row_map[inv_active] >= 0
    size2_hit_idx = active_idx[active_size2]
    size2_inv = row_map[inv_active[active_size2]]
    centroids = scatter_mean(emb[size2_hit_idx], size2_inv, dim=0, dim_size=size2_active_rows.numel())
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
    seed_order = torch.argsort(size2_inv)
    seed_idx = size2_hit_idx[seed_order].reshape(size2_active_rows.numel(), 2)

    layer_presence = None
    layer_min = 0
    if has_layer:
        cluster_layers = full_data.layer[size2_hit_idx].long()
        layer_min = int(cluster_layers.min().item())
        layer_span = max(1, int(cluster_layers.max().item()) - layer_min + 1)
        layer_presence = torch.zeros(
            (size2_active_rows.numel(), layer_span),
            device=predicted.device,
            dtype=torch.bool,
        )
        layer_presence[size2_inv, cluster_layers - layer_min] = True

    k = max(1, min(int(topk), int(cand_idx.numel())))
    best_vals = torch.full((size2_active_rows.numel(), k), float("-inf"), device=emb.device)
    best_cols = torch.full((size2_active_rows.numel(), k), -1, device=emb.device, dtype=torch.long)
    cand_pred = predicted[cand_idx]
    cand_layers = full_data.layer[cand_idx].long() if has_layer else None
    use_geom = float(geom_z_max) > 0.0 or float(geom_phi_max) > 0.0
    if use_geom:
        coords = full_data.coords.float()
        seed_coords = coords[seed_idx]
        r1 = seed_coords[:, 0, 2]
        r2 = seed_coords[:, 1, 2]
        z1 = seed_coords[:, 0, 4]
        z2 = seed_coords[:, 1, 4]
        p1 = seed_coords[:, 0, 3]
        p2 = seed_coords[:, 1, 3]
        denom = (r2 - r1).clamp_min(1e-6)
        neg = (r2 - r1) < 0
        denom = torch.where(neg, (r2 - r1).clamp_max(-1e-6), denom)
        dphi12 = _wrap_normalized_phi_diff_torch(p2 - p1)
    for start in range(0, int(cand_idx.numel()), int(chunk_size)):
        end = min(start + int(chunk_size), int(cand_idx.numel()))
        sim = centroids @ emb[cand_idx[start:end]].t()
        same_label = cand_pred[start:end][None, :] == size2_ids[:, None]
        sim = sim.masked_fill(same_label, float("-inf"))
        if layer_presence is not None:
            shifted = cand_layers[start:end] - int(layer_min)
            in_range = (shifted >= 0) & (shifted < layer_presence.shape[1])
            forbidden = torch.zeros(
                (size2_active_rows.numel(), end - start),
                device=predicted.device,
                dtype=torch.bool,
            )
            if bool(in_range.any()):
                cols = torch.nonzero(in_range, as_tuple=False).squeeze(1)
                forbidden[:, cols] = layer_presence[:, shifted[in_range]]
            sim = sim.masked_fill(forbidden, float("-inf"))
        if use_geom:
            cand_coords = coords[cand_idx[start:end]]
            rc = cand_coords[:, 2][None, :]
            zc = cand_coords[:, 4][None, :]
            pc = cand_coords[:, 3][None, :]
            t = (rc - r1[:, None]) / denom[:, None]
            geom_bad = torch.zeros_like(sim, dtype=torch.bool)
            if float(geom_z_max) > 0.0:
                z_pred = z1[:, None] + (z2 - z1)[:, None] * t
                geom_bad |= (zc - z_pred).abs() > float(geom_z_max)
            if float(geom_phi_max) > 0.0:
                dphi1c = _wrap_normalized_phi_diff_torch(pc - p1[:, None])
                phi_res = _wrap_normalized_phi_diff_torch(dphi1c - dphi12[:, None] * t).abs()
                geom_bad |= phi_res > float(geom_phi_max)
            sim = sim.masked_fill(geom_bad, float("-inf"))
        vals = torch.cat([best_vals, sim], dim=1)
        cols = torch.cat(
            [
                best_cols,
                torch.arange(start, end, device=emb.device, dtype=torch.long)
                .unsqueeze(0)
                .expand(size2_active_rows.numel(), -1),
            ],
            dim=1,
        )
        best_vals, order = vals.topk(k, dim=1)
        best_cols = cols.gather(1, order)

    padded = predicted.clone()
    if int(topk) == 1:
        cand_cols = best_cols[:, 0]
        cand_scores = best_vals[:, 0]
        row_ids = torch.arange(size2_active_rows.numel(), device=emb.device, dtype=torch.long)
        keep = (cand_cols >= 0) & (cand_scores >= float(min_sim))
        if not bool(keep.any()):
            return padded
        cand_cols = cand_cols[keep]
        cand_scores = cand_scores[keep]
        row_ids = row_ids[keep]

        # Resolve collisions on the same filler hit on GPU. Exact score ties are
        # vanishingly rare here; if they occur, the advanced assignment below is
        # still valid because both candidates are score-equivalent.
        best_for_col = torch.full((cand_idx.numel(),), float("-inf"), device=emb.device, dtype=cand_scores.dtype)
        best_for_col.scatter_reduce_(0, cand_cols, cand_scores, reduce="amax", include_self=True)
        winners = cand_scores >= best_for_col[cand_cols]
        if not bool(winners.any()):
            return padded
        hits = cand_idx[cand_cols[winners]]
        padded[hits] = size2_ids[row_ids[winners]]
        return padded

    used = torch.zeros(cand_idx.numel(), device=emb.device, dtype=torch.bool)
    row_order = torch.argsort(best_vals[:, 0], descending=True)
    for row in row_order.tolist():
        for slot in range(k):
            sim_val = float(best_vals[row, slot].item())
            if sim_val < float(min_sim):
                break
            col = int(best_cols[row, slot].item())
            if col < 0 or bool(used[col]):
                continue
            cur_label = int(predicted[cand_idx[col]].item())
            if cur_label >= 0 and (
                cur_label >= int(label_sizes.numel())
                or int(label_sizes[cur_label].item()) > int(max_conflict_size)
            ):
                continue
            hit = cand_idx[col]
            if cur_label >= 0:
                label_sizes[cur_label] -= 1
            target_label = int(size2_ids[row].item())
            padded[hit] = target_label
            if target_label < int(label_sizes.numel()):
                label_sizes[target_label] += 1
            used[col] = True
            break
    return padded


def _pad_size2_label_space_core(
    predicted,
    active_idx,
    labels,
    counts,
    size2_rows,
    cand_idx,
    emb,
    layers,
    coords,
    layer_min: int,
    layer_span: int,
    min_sim: float,
    geom_z_max: float,
    geom_phi_max: float,
):
    row_map = torch.full((int(counts.shape[0]),), -1, device=predicted.device, dtype=torch.long)
    row_map[size2_rows] = torch.arange(size2_rows.numel(), device=predicted.device, dtype=torch.long)
    active_size2 = row_map[labels] >= 0
    size2_hit_idx = active_idx[active_size2]
    size2_inv = row_map[labels[active_size2]]

    sums = torch.zeros((size2_rows.numel(), int(emb.shape[1])), device=emb.device, dtype=emb.dtype)
    sums.scatter_add_(0, size2_inv[:, None].expand(-1, int(emb.shape[1])), emb[size2_hit_idx])
    centroids = F.normalize(sums * 0.5, p=2, dim=1, eps=1e-12)

    seed_order = torch.argsort(size2_inv)
    seed_idx = size2_hit_idx[seed_order].reshape(size2_rows.numel(), 2)

    cluster_layers = layers[size2_hit_idx].long()
    layer_presence = torch.zeros(
        (size2_rows.numel(), int(layer_span)),
        device=predicted.device,
        dtype=torch.bool,
    )
    layer_presence[size2_inv, cluster_layers - int(layer_min)] = True

    sim = centroids @ emb[cand_idx].t()
    cand_pred = predicted[cand_idx]
    sim = sim.masked_fill(cand_pred[None, :] == size2_rows[:, None], float("-inf"))

    shifted = layers[cand_idx].long() - int(layer_min)
    in_range = (shifted >= 0) & (shifted < int(layer_span))
    shifted_safe = shifted.clamp(0, int(layer_span) - 1)
    forbidden = layer_presence[:, shifted_safe] & in_range[None, :]
    sim = sim.masked_fill(forbidden, float("-inf"))

    seed_coords = coords[seed_idx].float()
    r1 = seed_coords[:, 0, 2]
    r2 = seed_coords[:, 1, 2]
    z1 = seed_coords[:, 0, 4]
    z2 = seed_coords[:, 1, 4]
    p1 = seed_coords[:, 0, 3]
    p2 = seed_coords[:, 1, 3]
    denom_raw = r2 - r1
    denom = denom_raw.clamp_min(1e-6)
    denom = torch.where(denom_raw < 0, denom_raw.clamp_max(-1e-6), denom)
    cand_coords = coords[cand_idx].float()
    rc = cand_coords[:, 2][None, :]
    zc = cand_coords[:, 4][None, :]
    pc = cand_coords[:, 3][None, :]
    t = (rc - r1[:, None]) / denom[:, None]
    geom_bad = torch.zeros_like(sim, dtype=torch.bool)
    if float(geom_z_max) > 0.0:
        z_pred = z1[:, None] + (z2 - z1)[:, None] * t
        geom_bad |= (zc - z_pred).abs() > float(geom_z_max)
    if float(geom_phi_max) > 0.0:
        dphi12 = _wrap_normalized_phi_diff_torch(p2 - p1)
        dphi1c = _wrap_normalized_phi_diff_torch(pc - p1[:, None])
        phi_res = _wrap_normalized_phi_diff_torch(dphi1c - dphi12[:, None] * t).abs()
        geom_bad |= phi_res > float(geom_phi_max)
    sim = sim.masked_fill(geom_bad, float("-inf"))

    best_vals, best_cols = sim.max(dim=1)
    keep = (best_cols >= 0) & (best_vals >= float(min_sim))
    row_ids = torch.arange(size2_rows.numel(), device=predicted.device, dtype=torch.long)[keep]
    cand_cols = best_cols[keep]
    cand_scores = best_vals[keep]
    best_for_col = torch.full((cand_idx.numel(),), float("-inf"), device=predicted.device, dtype=cand_scores.dtype)
    best_for_col.scatter_reduce_(0, cand_cols, cand_scores, reduce="amax", include_self=True)
    winners = cand_scores >= best_for_col[cand_cols]

    padded = predicted.clone()
    padded[cand_idx[cand_cols[winners]]] = size2_rows[row_ids[winners]]
    return padded


_pad_size2_label_space_core_compiled = torch.compile(
    _pad_size2_label_space_core,
    dynamic=True,
)


def _pad_size2_label_space_geom_core(
    predicted,
    active_idx,
    labels,
    counts,
    size2_rows,
    cand_idx,
    layers,
    coords,
    cand_clf,
    layer_min: int,
    layer_span: int,
    geom_z_max: float,
    geom_phi_max: float,
    geom_clf_weight: float,
):
    row_map = torch.full((int(counts.shape[0]),), -1, device=predicted.device, dtype=torch.long)
    row_map[size2_rows] = torch.arange(size2_rows.numel(), device=predicted.device, dtype=torch.long)
    active_size2 = row_map[labels] >= 0
    size2_hit_idx = active_idx[active_size2]
    size2_inv = row_map[labels[active_size2]]
    seed_order = torch.argsort(size2_inv)
    seed_idx = size2_hit_idx[seed_order].reshape(size2_rows.numel(), 2)

    cluster_layers = layers[size2_hit_idx].long()
    layer_presence = torch.zeros(
        (size2_rows.numel(), int(layer_span)),
        device=predicted.device,
        dtype=torch.bool,
    )
    layer_presence[size2_inv, cluster_layers - int(layer_min)] = True

    seed_coords = coords[seed_idx].float()
    r1 = seed_coords[:, 0, 2]
    r2 = seed_coords[:, 1, 2]
    z1 = seed_coords[:, 0, 4]
    z2 = seed_coords[:, 1, 4]
    p1 = seed_coords[:, 0, 3]
    p2 = seed_coords[:, 1, 3]
    denom_raw = r2 - r1
    denom = denom_raw.clamp_min(1e-6)
    denom = torch.where(denom_raw < 0, denom_raw.clamp_max(-1e-6), denom)
    cand_coords = coords[cand_idx].float()
    rc = cand_coords[:, 2][None, :]
    zc = cand_coords[:, 4][None, :]
    pc = cand_coords[:, 3][None, :]
    t = (rc - r1[:, None]) / denom[:, None]

    score = cand_clf[None, :] * float(geom_clf_weight)
    geom_bad = torch.zeros((size2_rows.numel(), cand_idx.numel()), device=predicted.device, dtype=torch.bool)
    if float(geom_z_max) > 0.0:
        z_pred = z1[:, None] + (z2 - z1)[:, None] * t
        z_res = (zc - z_pred).abs()
        geom_bad |= z_res > float(geom_z_max)
        score = score - z_res / float(geom_z_max)
    if float(geom_phi_max) > 0.0:
        dphi12 = _wrap_normalized_phi_diff_torch(p2 - p1)
        dphi1c = _wrap_normalized_phi_diff_torch(pc - p1[:, None])
        phi_res = _wrap_normalized_phi_diff_torch(dphi1c - dphi12[:, None] * t).abs()
        geom_bad |= phi_res > float(geom_phi_max)
        score = score - phi_res / float(geom_phi_max)

    cand_pred = predicted[cand_idx]
    score = score.masked_fill(cand_pred[None, :] == size2_rows[:, None], float("-inf"))
    shifted = layers[cand_idx].long() - int(layer_min)
    in_range = (shifted >= 0) & (shifted < int(layer_span))
    shifted_safe = shifted.clamp(0, int(layer_span) - 1)
    forbidden = layer_presence[:, shifted_safe] & in_range[None, :]
    score = score.masked_fill(forbidden | geom_bad, float("-inf"))

    best_vals, best_cols = score.max(dim=1)
    keep = torch.isfinite(best_vals)
    row_ids = torch.arange(size2_rows.numel(), device=predicted.device, dtype=torch.long)[keep]
    cand_cols = best_cols[keep]
    cand_scores = best_vals[keep]
    best_for_col = torch.full((cand_idx.numel(),), float("-inf"), device=predicted.device, dtype=cand_scores.dtype)
    best_for_col.scatter_reduce_(0, cand_cols, cand_scores, reduce="amax", include_self=True)
    winners = cand_scores >= best_for_col[cand_cols]

    padded = predicted.clone()
    padded[cand_idx[cand_cols[winners]]] = size2_rows[row_ids[winners]]
    return padded


_pad_size2_label_space_geom_core_compiled = torch.compile(
    _pad_size2_label_space_geom_core,
    dynamic=True,
)


@torch.no_grad()
def _pad_size2_clusters_label_space_fast(
    predicted,
    full_data,
    full_emb,
    num_labels,
    full_clf_scores=None,
    min_sim=0.0,
    clf_floor=0.0,
    clf_ceiling=0.0,
    unique_layer=True,
    topk=1,
    max_candidates=0,
    max_clusters=0,
    max_conflict_size=0,
    geom_z_max=0.0,
    geom_phi_max=0.0,
    geom_only=False,
    geom_clf_weight=0.0,
    rank_clusters_by_clf=True,
    rank_candidates_by_clf=True,
    normalized_emb=None,
):
    if int(topk) != 1 or int(num_labels) <= 1:
        return None
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    if active_idx.numel() == 0:
        return predicted
    labels = predicted[active_idx].long()
    max_label = max(int(num_labels), int(labels.max().item()) + 1)
    counts = torch.bincount(labels, minlength=max_label)
    size2_rows = torch.nonzero(counts == 2, as_tuple=False).squeeze(1)
    if int(max_clusters) > 0 and size2_rows.numel() > int(max_clusters):
        clf_scores = full_clf_scores.squeeze(-1).float() if full_clf_scores is not None else None
        if bool(rank_clusters_by_clf) and clf_scores is not None:
            cluster_sum = torch.zeros(max_label, device=predicted.device, dtype=clf_scores.dtype)
            cluster_sum.scatter_add_(0, labels, clf_scores[active_idx])
            cluster_clf = cluster_sum / counts.to(clf_scores.dtype).clamp_min(1)
            _, order = cluster_clf[size2_rows].topk(int(max_clusters), largest=True)
            size2_rows = size2_rows[order]
        else:
            size2_rows = size2_rows[: int(max_clusters)]
    if size2_rows.numel() == 0:
        return predicted
    size2_ids = size2_rows

    clf_scores = full_clf_scores.squeeze(-1).float() if full_clf_scores is not None else None
    candidate_mask = valid_mask & (predicted < 0)
    if int(max_conflict_size) > 0:
        hit_sizes = torch.zeros_like(predicted, dtype=torch.long)
        hit_sizes[active_idx] = counts[labels]
        candidate_mask |= valid_mask & (predicted >= 0) & (hit_sizes <= int(max_conflict_size))
    if clf_scores is not None:
        if float(clf_floor) > 0.0:
            candidate_mask &= clf_scores >= float(clf_floor)
        if float(clf_ceiling) > 0.0:
            candidate_mask &= clf_scores <= float(clf_ceiling)
    cand_idx = torch.nonzero(candidate_mask, as_tuple=False).squeeze(1)
    if int(max_candidates) > 0 and cand_idx.numel() > int(max_candidates):
        if bool(rank_candidates_by_clf) and clf_scores is not None:
            _, order = clf_scores[cand_idx].topk(int(max_candidates), largest=True)
            cand_idx = cand_idx[order]
        else:
            cand_idx = cand_idx[: int(max_candidates)]
    if cand_idx.numel() == 0:
        return predicted

    has_layer = unique_layer and hasattr(full_data, "layer") and full_data.layer is not None
    if has_layer:
        layers_all = full_data.layer.long()
        layer_min_fast = 0
        layer_span_fast = 18
        if bool(geom_only):
            cand_clf = (
                clf_scores[cand_idx]
                if clf_scores is not None
                else torch.zeros(cand_idx.numel(), device=predicted.device, dtype=torch.float32)
            )
            return _pad_size2_label_space_geom_core_compiled(
                predicted,
                active_idx,
                labels,
                counts,
                size2_rows,
                cand_idx,
                layers_all,
                full_data.coords,
                cand_clf.float(),
                layer_min_fast,
                layer_span_fast,
                float(geom_z_max),
                float(geom_phi_max),
                float(geom_clf_weight),
            )
        emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
        return _pad_size2_label_space_core_compiled(
            predicted,
            active_idx,
            labels,
            counts,
            size2_rows,
            cand_idx,
            emb,
            layers_all,
            full_data.coords,
            layer_min_fast,
            layer_span_fast,
            float(min_sim),
            float(geom_z_max),
            float(geom_phi_max),
        )

    emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
    row_map = torch.full((max_label,), -1, device=predicted.device, dtype=torch.long)
    row_map[size2_rows] = torch.arange(size2_rows.numel(), device=predicted.device, dtype=torch.long)
    active_size2 = row_map[labels] >= 0
    size2_hit_idx = active_idx[active_size2]
    size2_inv = row_map[labels[active_size2]]
    if size2_hit_idx.numel() != size2_rows.numel() * 2:
        return None

    sums = torch.zeros((size2_rows.numel(), int(emb.shape[1])), device=emb.device, dtype=emb.dtype)
    sums.scatter_add_(0, size2_inv[:, None].expand(-1, int(emb.shape[1])), emb[size2_hit_idx])
    centroids = F.normalize(sums * 0.5, p=2, dim=1, eps=1e-12)
    seed_order = torch.argsort(size2_inv)
    seed_idx = size2_hit_idx[seed_order].reshape(size2_rows.numel(), 2)

    layer_presence = None
    layer_min = 0
    if has_layer:
        cluster_layers = full_data.layer[size2_hit_idx].long()
        layer_min = int(cluster_layers.min().item())
        layer_span = max(1, int(cluster_layers.max().item()) - layer_min + 1)
        layer_presence = torch.zeros(
            (size2_rows.numel(), layer_span),
            device=predicted.device,
            dtype=torch.bool,
        )
        layer_presence[size2_inv, cluster_layers - layer_min] = True

    cand_pred = predicted[cand_idx]
    cand_layers = full_data.layer[cand_idx].long() if has_layer else None
    use_geom = float(geom_z_max) > 0.0 or float(geom_phi_max) > 0.0
    if use_geom:
        coords = full_data.coords.float()
        seed_coords = coords[seed_idx]
        r1 = seed_coords[:, 0, 2]
        r2 = seed_coords[:, 1, 2]
        z1 = seed_coords[:, 0, 4]
        z2 = seed_coords[:, 1, 4]
        p1 = seed_coords[:, 0, 3]
        p2 = seed_coords[:, 1, 3]
        denom_raw = r2 - r1
        denom = denom_raw.clamp_min(1e-6)
        denom = torch.where(denom_raw < 0, denom_raw.clamp_max(-1e-6), denom)
        dphi12 = _wrap_normalized_phi_diff_torch(p2 - p1)

    sim = centroids @ emb[cand_idx].t()
    sim = sim.masked_fill(cand_pred[None, :] == size2_ids[:, None], float("-inf"))
    if layer_presence is not None:
        shifted = cand_layers - int(layer_min)
        in_range = (shifted >= 0) & (shifted < layer_presence.shape[1])
        forbidden = torch.zeros((size2_rows.numel(), cand_idx.numel()), device=predicted.device, dtype=torch.bool)
        if bool(in_range.any()):
            cols = torch.nonzero(in_range, as_tuple=False).squeeze(1)
            forbidden[:, cols] = layer_presence[:, shifted[in_range]]
        sim = sim.masked_fill(forbidden, float("-inf"))
    if use_geom:
        cand_coords = coords[cand_idx]
        rc = cand_coords[:, 2][None, :]
        zc = cand_coords[:, 4][None, :]
        pc = cand_coords[:, 3][None, :]
        t = (rc - r1[:, None]) / denom[:, None]
        geom_bad = torch.zeros_like(sim, dtype=torch.bool)
        if float(geom_z_max) > 0.0:
            z_pred = z1[:, None] + (z2 - z1)[:, None] * t
            geom_bad |= (zc - z_pred).abs() > float(geom_z_max)
        if float(geom_phi_max) > 0.0:
            dphi1c = _wrap_normalized_phi_diff_torch(pc - p1[:, None])
            phi_res = _wrap_normalized_phi_diff_torch(dphi1c - dphi12[:, None] * t).abs()
            geom_bad |= phi_res > float(geom_phi_max)
        sim = sim.masked_fill(geom_bad, float("-inf"))

    best_vals, best_cols = sim.max(dim=1)
    keep = (best_cols >= 0) & (best_vals >= float(min_sim))
    padded = predicted.clone()
    if not bool(keep.any()):
        return padded
    row_ids = torch.arange(size2_rows.numel(), device=predicted.device, dtype=torch.long)[keep]
    cand_cols = best_cols[keep]
    cand_scores = best_vals[keep]
    best_for_col = torch.full((cand_idx.numel(),), float("-inf"), device=predicted.device, dtype=cand_scores.dtype)
    best_for_col.scatter_reduce_(0, cand_cols, cand_scores, reduce="amax", include_self=True)
    winners = cand_scores >= best_for_col[cand_cols]
    if bool(winners.any()):
        padded[cand_idx[cand_cols[winners]]] = size2_ids[row_ids[winners]]
    return padded


@torch.no_grad()
def _pad_size2_clusters_from_direct_state(
    predicted,
    full_data,
    full_clf_scores,
    direct_state,
    min_sim=0.0,
    clf_floor=0.0,
    clf_ceiling=0.0,
    unique_layer=True,
    topk=1,
    max_candidates=0,
    max_clusters=0,
    max_conflict_size=0,
    geom_z_max=0.0,
    geom_phi_max=0.0,
    rank_clusters_by_clf=True,
    rank_candidates_by_clf=True,
):
    """Promote size-2 clusters reusing the dense cluster state from direct merge."""
    if direct_state is None or int(topk) != 1:
        return None

    valid_mask = full_data.valid_mask.bool()
    active_idx = direct_state["active_idx"]
    active_ids = direct_state["active_ids"]
    inv_active = direct_state["inv"]
    counts = direct_state["counts"]
    remap = direct_state["remap"]
    emb = direct_state["normalized_emb"]
    if active_idx.numel() == 0 or active_ids.numel() == 0:
        return predicted

    post_inv = remap[inv_active]
    merged_counts = torch.zeros_like(counts)
    merged_counts.scatter_add_(0, remap, counts)
    size2_rows = torch.nonzero(merged_counts == 2, as_tuple=False).squeeze(1)
    if size2_rows.numel() == 0:
        return predicted

    clf_scores = full_clf_scores.squeeze(-1).float() if full_clf_scores is not None else None
    if int(max_clusters) > 0 and size2_rows.numel() > int(max_clusters):
        if bool(rank_clusters_by_clf) and clf_scores is not None:
            cluster_clf = scatter_mean(
                clf_scores[active_idx].unsqueeze(1),
                post_inv,
                dim=0,
                dim_size=active_ids.numel(),
            ).squeeze(1)
            _, order = cluster_clf[size2_rows].topk(int(max_clusters), largest=True)
            size2_rows = size2_rows[order]
        else:
            size2_rows = size2_rows[: int(max_clusters)]
    size2_ids = active_ids[size2_rows]

    candidate_mask = valid_mask & (predicted < 0)
    if int(max_conflict_size) > 0:
        hit_sizes = torch.zeros_like(predicted, dtype=torch.long)
        hit_sizes[active_idx] = merged_counts[post_inv]
        candidate_mask |= valid_mask & (predicted >= 0) & (hit_sizes <= int(max_conflict_size))
    if clf_scores is not None:
        if float(clf_floor) > 0.0:
            candidate_mask &= clf_scores >= float(clf_floor)
        if float(clf_ceiling) > 0.0:
            candidate_mask &= clf_scores <= float(clf_ceiling)
    cand_idx = torch.nonzero(candidate_mask, as_tuple=False).squeeze(1)
    if int(max_candidates) > 0 and cand_idx.numel() > int(max_candidates):
        if bool(rank_candidates_by_clf) and clf_scores is not None:
            _, order = clf_scores[cand_idx].topk(int(max_candidates), largest=True)
            cand_idx = cand_idx[order]
        else:
            cand_idx = cand_idx[: int(max_candidates)]
    if cand_idx.numel() == 0:
        return predicted

    row_map = torch.full((active_ids.numel(),), -1, device=predicted.device, dtype=torch.long)
    row_map[size2_rows] = torch.arange(size2_rows.numel(), device=predicted.device)
    active_size2 = row_map[post_inv] >= 0
    size2_hit_idx = active_idx[active_size2]
    size2_inv = row_map[post_inv[active_size2]]
    if size2_hit_idx.numel() != size2_rows.numel() * 2:
        return None
    centroids = scatter_mean(emb[size2_hit_idx], size2_inv, dim=0, dim_size=size2_rows.numel())
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)

    seed_order = torch.argsort(size2_inv)
    seed_idx = size2_hit_idx[seed_order].reshape(size2_rows.numel(), 2)

    has_layer = unique_layer and hasattr(full_data, "layer") and full_data.layer is not None
    layer_presence = None
    layer_min = 0
    if has_layer:
        cluster_layers = full_data.layer[size2_hit_idx].long()
        layer_min = int(cluster_layers.min().item())
        layer_span = max(1, int(cluster_layers.max().item()) - layer_min + 1)
        layer_presence = torch.zeros(
            (size2_rows.numel(), layer_span),
            device=predicted.device,
            dtype=torch.bool,
        )
        layer_presence[size2_inv, cluster_layers - layer_min] = True

    cand_pred = predicted[cand_idx]
    cand_layers = full_data.layer[cand_idx].long() if has_layer else None
    use_geom = float(geom_z_max) > 0.0 or float(geom_phi_max) > 0.0
    if use_geom:
        coords = full_data.coords.float()
        seed_coords = coords[seed_idx]
        r1 = seed_coords[:, 0, 2]
        r2 = seed_coords[:, 1, 2]
        z1 = seed_coords[:, 0, 4]
        z2 = seed_coords[:, 1, 4]
        p1 = seed_coords[:, 0, 3]
        p2 = seed_coords[:, 1, 3]
        denom = (r2 - r1).clamp_min(1e-6)
        neg = (r2 - r1) < 0
        denom = torch.where(neg, (r2 - r1).clamp_max(-1e-6), denom)
        dphi12 = _wrap_normalized_phi_diff_torch(p2 - p1)

    sim = centroids @ emb[cand_idx].t()
    sim = sim.masked_fill(cand_pred[None, :] == size2_ids[:, None], float("-inf"))
    if layer_presence is not None:
        shifted = cand_layers - int(layer_min)
        in_range = (shifted >= 0) & (shifted < layer_presence.shape[1])
        forbidden = torch.zeros((size2_rows.numel(), cand_idx.numel()), device=predicted.device, dtype=torch.bool)
        if bool(in_range.any()):
            cols = torch.nonzero(in_range, as_tuple=False).squeeze(1)
            forbidden[:, cols] = layer_presence[:, shifted[in_range]]
        sim = sim.masked_fill(forbidden, float("-inf"))
    if use_geom:
        cand_coords = coords[cand_idx]
        rc = cand_coords[:, 2][None, :]
        zc = cand_coords[:, 4][None, :]
        pc = cand_coords[:, 3][None, :]
        t = (rc - r1[:, None]) / denom[:, None]
        geom_bad = torch.zeros_like(sim, dtype=torch.bool)
        if float(geom_z_max) > 0.0:
            z_pred = z1[:, None] + (z2 - z1)[:, None] * t
            geom_bad |= (zc - z_pred).abs() > float(geom_z_max)
        if float(geom_phi_max) > 0.0:
            dphi1c = _wrap_normalized_phi_diff_torch(pc - p1[:, None])
            phi_res = _wrap_normalized_phi_diff_torch(dphi1c - dphi12[:, None] * t).abs()
            geom_bad |= phi_res > float(geom_phi_max)
        sim = sim.masked_fill(geom_bad, float("-inf"))

    best_vals, best_cols = sim.max(dim=1)
    row_ids = torch.arange(size2_rows.numel(), device=predicted.device, dtype=torch.long)
    keep = (best_cols >= 0) & (best_vals >= float(min_sim))
    padded = predicted.clone()
    if not bool(keep.any()):
        return padded
    cand_cols = best_cols[keep]
    cand_scores = best_vals[keep]
    row_ids = row_ids[keep]
    best_for_col = torch.full((cand_idx.numel(),), float("-inf"), device=predicted.device, dtype=cand_scores.dtype)
    best_for_col.scatter_reduce_(0, cand_cols, cand_scores, reduce="amax", include_self=True)
    winners = cand_scores >= best_for_col[cand_cols]
    if bool(winners.any()):
        padded[cand_idx[cand_cols[winners]]] = size2_ids[row_ids[winners]]
    return padded


@torch.no_grad()
def _merge_similar_clusters(
    predicted,
    full_data,
    full_emb,
    min_sim=0.9,
    small_cluster_size=2,
    max_merged_size=12,
    topk=4,
    require_unique_layer=False,
):
    """Union small predicted fragments with embedding-nearby clusters."""
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not active.any():
        return predicted

    active_ids, inv, counts = torch.unique(predicted[active], return_inverse=True, return_counts=True)
    k = int(active_ids.numel())
    if k <= 1:
        return predicted

    small_mask = counts <= int(small_cluster_size)
    if not small_mask.any():
        return predicted

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    emb = _l2_normalize(full_emb)
    centroids = scatter_mean(emb[active_idx], inv, dim=0, dim_size=k)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
    has_layer = bool(require_unique_layer and hasattr(full_data, "layer") and full_data.layer is not None)
    layer_sets = None
    if has_layer:
        inv_cpu = inv.detach().cpu().numpy()
        layers_cpu = full_data.layer[active_idx].detach().cpu().numpy()
        layer_sets = [set() for _ in range(k)]
        for cluster_i, layer in zip(inv_cpu, layers_cpu):
            layer_sets[int(cluster_i)].add(int(layer))

    small_rows = torch.nonzero(small_mask, as_tuple=False).squeeze(1)
    n_top = max(1, min(int(topk), k - 1))
    sim = centroids[small_rows] @ centroids.t()
    sim[torch.arange(small_rows.numel(), device=sim.device), small_rows] = float("-inf")
    vals, cols = sim.topk(n_top, dim=1)

    vals_cpu = vals.detach().float().cpu().numpy()
    cols_cpu = cols.detach().cpu().numpy()
    rows_cpu = small_rows.detach().cpu().numpy()
    pairs = []
    for row_i, cluster_i in enumerate(rows_cpu):
        for slot in range(n_top):
            score = float(vals_cpu[row_i, slot])
            if score >= float(min_sim):
                pairs.append((score, int(cluster_i), int(cols_cpu[row_i, slot])))
    if not pairs:
        return predicted

    parent = list(range(k))
    rank = [0] * k
    comp_size = [int(v) for v in counts.detach().cpu().tolist()]
    pairs.sort(reverse=True)
    max_merged_size = int(max_merged_size)
    for _score, a, b in pairs:
        root_a = _find_root(parent, a)
        root_b = _find_root(parent, b)
        if root_a == root_b:
            continue
        if layer_sets is not None and layer_sets[root_a] & layer_sets[root_b]:
            continue
        if comp_size[root_a] + comp_size[root_b] > max_merged_size:
            continue
        size_sum = comp_size[root_a] + comp_size[root_b]
        _union_roots(parent, rank, root_a, root_b)
        new_root = _find_root(parent, root_a)
        comp_size[new_root] = size_sum
        if layer_sets is not None:
            layer_sets[new_root] = layer_sets[root_a] | layer_sets[root_b]

    roots = torch.as_tensor(
        [_find_root(parent, i) for i in range(k)],
        device=predicted.device,
        dtype=torch.long,
    )
    if torch.equal(roots, torch.arange(k, device=predicted.device, dtype=torch.long)):
        return predicted
    out = predicted.clone()
    out[active] = active_ids[roots[inv]]
    return out


@torch.no_grad()
def _merge_similar_clusters_direct(
    predicted,
    full_data,
    full_emb,
    min_sim=0.9,
    small_cluster_size=2,
    max_merged_size=12,
    target_min_size=0,
    normalized_emb=None,
    use_bf16_sim=False,
    return_refine_state=False,
):
    """One-pass small-fragment merge without CPU union-find.

    This maps small clusters into embedding-nearby targets on GPU. When the
    target size floor allows small clusters, edges point only toward a larger
    cluster, or toward a same-size cluster with a smaller dense id; that keeps
    the remap acyclic while still recovering cheap small-small joins.
    """
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not active.any():
        if bool(return_refine_state):
            return predicted, None
        return predicted

    active_ids, inv, counts = torch.unique(predicted[active], return_inverse=True, return_counts=True)
    k = int(active_ids.numel())
    if k <= 1:
        if bool(return_refine_state):
            return predicted, None
        return predicted

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
    sums = torch.zeros(
        (k, int(emb.shape[1])),
        device=emb.device,
        dtype=emb.dtype,
    )
    sums.scatter_add_(0, inv[:, None].expand(-1, int(emb.shape[1])), emb[active_idx])
    centroids = sums / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
    identity_remap = torch.arange(k, device=predicted.device, dtype=torch.long)

    small_rows = torch.nonzero(counts <= int(small_cluster_size), as_tuple=False).squeeze(1)
    if small_rows.numel() == 0:
        if bool(return_refine_state):
            return predicted, {
                "active_idx": active_idx,
                "active_ids": active_ids,
                "inv": inv,
                "counts": counts,
                "sums": sums,
                "remap": identity_remap,
                "normalized_emb": emb,
            }
        return predicted

    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = int(small_cluster_size) + 1
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    target_rows = torch.nonzero(target_mask, as_tuple=False).squeeze(1)
    if target_rows.numel() == 0:
        if bool(return_refine_state):
            return predicted, {
                "active_idx": active_idx,
                "active_ids": active_ids,
                "inv": inv,
                "counts": counts,
                "sums": sums,
                "remap": identity_remap,
                "normalized_emb": emb,
            }
        return predicted

    small_centroids = centroids[small_rows]
    target_centroids = centroids[target_rows]
    if bool(use_bf16_sim) and centroids.is_cuda:
        sim = small_centroids.to(torch.bfloat16) @ target_centroids.to(torch.bfloat16).t()
    else:
        sim = small_centroids @ target_centroids.t()
    same = small_rows[:, None] == target_rows[None, :]
    sim = sim.masked_fill(same, float("-inf"))
    if target_min <= int(small_cluster_size):
        row_counts = counts[small_rows][:, None]
        target_counts = counts[target_rows][None, :]
        acyclic_target = (target_counts > row_counts) | (
            (target_counts == row_counts) & (target_rows[None, :] < small_rows[:, None])
        )
        sim = sim.masked_fill(~acyclic_target, float("-inf"))
    if int(max_merged_size) > 0:
        too_large = counts[small_rows][:, None] + counts[target_rows][None, :] > int(max_merged_size)
        sim = sim.masked_fill(too_large, float("-inf"))

    vals, col_pos = sim.max(dim=1)
    cols = target_rows[col_pos]
    keep = vals >= float(min_sim)
    if not bool(keep.any()):
        if bool(return_refine_state):
            return predicted, {
                "active_idx": active_idx,
                "active_ids": active_ids,
                "inv": inv,
                "counts": counts,
                "sums": sums,
                "remap": identity_remap,
                "normalized_emb": emb,
            }
        return predicted

    remap = identity_remap.clone()
    remap[small_rows[keep]] = cols[keep]
    for _ in range(4):
        remap = remap[remap]
    if int(max_merged_size) > 0:
        merged_sizes = torch.zeros(k, device=predicted.device, dtype=counts.dtype)
        merged_sizes.scatter_add_(0, remap, counts)
        oversized = merged_sizes[remap] > int(max_merged_size)
        if bool(oversized.any()):
            remap = torch.where(oversized, torch.arange(k, device=predicted.device, dtype=torch.long), remap)
            for _ in range(2):
                remap = remap[remap]
    out = predicted.clone()
    out[active] = active_ids[remap[inv]]
    if bool(return_refine_state):
        return out, {
            "active_idx": active_idx,
            "active_ids": active_ids,
            "inv": inv,
            "counts": counts,
            "sums": sums,
            "remap": remap,
            "normalized_emb": emb,
        }
    return out


@torch.no_grad()
def _merge_similar_clusters_direct_label_space(
    predicted,
    full_data,
    full_emb,
    min_sim=0.9,
    small_cluster_size=2,
    max_merged_size=12,
    target_min_size=0,
    normalized_emb=None,
    use_bf16_sim=False,
):
    """Direct small-fragment merge using decoder labels as dense-ish ids."""
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not active.any():
        return predicted

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    labels = predicted[active_idx].long()
    max_label = int(labels.max().item()) + 1
    if max_label <= 1:
        return predicted

    counts = torch.bincount(labels, minlength=max_label)
    active_rows = torch.nonzero(counts > 0, as_tuple=False).squeeze(1)
    if active_rows.numel() <= 1:
        return predicted

    emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
    sums = torch.zeros(
        (max_label, int(emb.shape[1])),
        device=emb.device,
        dtype=emb.dtype,
    )
    sums.scatter_add_(0, labels[:, None].expand(-1, int(emb.shape[1])), emb[active_idx])
    centroids = torch.zeros_like(sums)
    centroids[active_rows] = sums[active_rows] / counts[active_rows].to(emb.dtype).clamp_min(1).unsqueeze(1)
    centroids[active_rows] = F.normalize(centroids[active_rows], p=2, dim=1, eps=1e-12)

    small_rows = torch.nonzero((counts > 0) & (counts <= int(small_cluster_size)), as_tuple=False).squeeze(1)
    if small_rows.numel() == 0:
        return predicted

    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = int(small_cluster_size) + 1
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    rows_all = torch.arange(max_label, device=predicted.device, dtype=torch.long)
    target_rows = torch.nonzero(
        target_mask | ((rows_all == 0) & ~target_mask.any()),
        as_tuple=False,
    ).squeeze(1)
    target_valid = target_mask[target_rows]
    if target_rows.numel() == 0:
        return predicted

    small_centroids = centroids[small_rows]
    target_centroids = centroids[target_rows]
    if bool(use_bf16_sim) and centroids.is_cuda:
        sim = small_centroids.to(torch.bfloat16) @ target_centroids.to(torch.bfloat16).t()
    else:
        sim = small_centroids @ target_centroids.t()
    same = small_rows[:, None] == target_rows[None, :]
    sim = sim.masked_fill(same, float("-inf"))
    sim = sim.masked_fill(~target_valid[None, :], float("-inf"))
    if target_min <= int(small_cluster_size):
        row_counts = counts[small_rows][:, None]
        target_counts = counts[target_rows][None, :]
        acyclic_target = (target_counts > row_counts) | (
            (target_counts == row_counts) & (target_rows[None, :] < small_rows[:, None])
        )
        sim = sim.masked_fill(~acyclic_target, float("-inf"))
    if int(max_merged_size) > 0:
        too_large = counts[small_rows][:, None] + counts[target_rows][None, :] > int(max_merged_size)
        sim = sim.masked_fill(too_large, float("-inf"))

    vals, col_pos = sim.max(dim=1)
    cols = target_rows[col_pos]
    keep = vals >= float(min_sim)
    if not bool(keep.any()):
        return predicted

    remap = torch.arange(max_label, device=predicted.device, dtype=torch.long)
    remap[small_rows[keep]] = cols[keep]
    for _ in range(4):
        remap = remap[remap]
    if int(max_merged_size) > 0:
        merged_sizes = torch.zeros(max_label, device=predicted.device, dtype=counts.dtype)
        merged_sizes.scatter_add_(0, remap, counts)
        oversized = merged_sizes[remap] > int(max_merged_size)
        remap = torch.where(oversized, torch.arange(max_label, device=predicted.device, dtype=torch.long), remap)
        for _ in range(2):
            remap = remap[remap]
    out = predicted.clone()
    out[active_idx] = remap[labels]
    return out


def _merge_similar_clusters_direct_label_space_core(
    predicted,
    active_idx,
    labels,
    counts,
    emb,
    min_sim: float,
    small_cluster_size: int,
    max_merged_size: int,
    target_min_size: int,
    use_bf16_sim: bool,
):
    max_label = int(counts.shape[0])
    sums = torch.zeros(
        (max_label, int(emb.shape[1])),
        device=emb.device,
        dtype=emb.dtype,
    )
    sums.scatter_add_(0, labels[:, None].expand(-1, int(emb.shape[1])), emb[active_idx])
    centroids = sums / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)

    small_rows = torch.nonzero((counts > 0) & (counts <= int(small_cluster_size)), as_tuple=False).squeeze(1)
    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = int(small_cluster_size) + 1
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    target_rows = torch.nonzero(target_mask, as_tuple=False).squeeze(1)

    small_centroids = centroids[small_rows]
    target_centroids = centroids[target_rows]
    if bool(use_bf16_sim) and centroids.is_cuda:
        sim = small_centroids.to(torch.bfloat16) @ target_centroids.to(torch.bfloat16).t()
    else:
        sim = small_centroids @ target_centroids.t()
    same = small_rows[:, None] == target_rows[None, :]
    sim = sim.masked_fill(same, float("-inf"))
    if target_min <= int(small_cluster_size):
        row_counts = counts[small_rows][:, None]
        target_counts = counts[target_rows][None, :]
        acyclic_target = (target_counts > row_counts) | (
            (target_counts == row_counts) & (target_rows[None, :] < small_rows[:, None])
        )
        sim = sim.masked_fill(~acyclic_target, float("-inf"))
    if int(max_merged_size) > 0:
        too_large = counts[small_rows][:, None] + counts[target_rows][None, :] > int(max_merged_size)
        sim = sim.masked_fill(too_large, float("-inf"))

    vals, col_pos = sim.max(dim=1)
    cols = target_rows[col_pos]
    keep = vals >= float(min_sim)

    remap = torch.arange(max_label, device=predicted.device, dtype=torch.long)
    remap[small_rows[keep]] = cols[keep]
    for _ in range(4):
        remap = remap[remap]
    if int(max_merged_size) > 0:
        merged_sizes = torch.zeros(max_label, device=predicted.device, dtype=counts.dtype)
        merged_sizes.scatter_add_(0, remap, counts)
        oversized = merged_sizes[remap] > int(max_merged_size)
        remap = torch.where(oversized, torch.arange(max_label, device=predicted.device, dtype=torch.long), remap)
        for _ in range(2):
            remap = remap[remap]
    predicted[active_idx] = remap[labels]
    return predicted


_merge_similar_clusters_direct_label_space_core_compiled = torch.compile(
    _merge_similar_clusters_direct_label_space_core,
    dynamic=True,
)


def _merge_similar_clusters_direct_label_space_fast(
    predicted,
    full_data,
    full_emb,
    num_labels,
    min_sim=0.9,
    small_cluster_size=2,
    max_merged_size=12,
    target_min_size=0,
    normalized_emb=None,
    use_bf16_sim=False,
):
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    if active_idx.numel() == 0:
        return predicted
    labels = predicted[active_idx].long()
    max_label = int(num_labels)
    if max_label <= 1:
        return predicted
    counts = torch.bincount(labels, minlength=max_label)
    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = int(small_cluster_size) + 1
    small_mask = (counts > 0) & (counts <= int(small_cluster_size))
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
    return _merge_similar_clusters_direct_label_space_core_compiled(
        predicted,
        active_idx,
        labels,
        counts,
        emb,
        float(min_sim),
        int(small_cluster_size),
        int(max_merged_size),
        int(target_min_size),
        bool(use_bf16_sim),
    )


def _infer_decoder_label_count(pred_list, max_sub_events=0):
    if not pred_list:
        return 0
    first_masks = pred_list[0][0]
    if first_masks.dim() == 4 and len(pred_list) == 1:
        n_items = int(first_masks.shape[0])
        if int(max_sub_events) > 0:
            n_items = min(n_items, int(max_sub_events))
        return n_items * int(first_masks.shape[1])
    n_items = len(pred_list)
    if int(max_sub_events) > 0:
        n_items = min(n_items, int(max_sub_events))
    return n_items * int(first_masks.shape[1])


def _assign_merge_label_space_core(
    pred_masks,
    pred_logits,
    point_order,
    batch_all_idx,
    batch_valid_mask,
    full_valid_mask,
    clf_keep,
    emb,
    mask_thres: float,
    active_prob_power: float,
    min_sim: float,
    small_cluster_size: int,
    max_merged_size: int,
    target_min_size: int,
    use_bf16_sim: bool,
):
    n_items = int(pred_masks.shape[0])
    q = int(pred_masks.shape[1])
    n_total = int(full_valid_mask.shape[0])
    num_labels = n_items * q

    point_order = point_order[:n_items].to(device=pred_masks.device, dtype=torch.long)
    valid_sorted = batch_valid_mask[:n_items].gather(1, point_order)
    orig_sorted = batch_all_idx[:n_items].gather(1, point_order)

    scores = pred_masks[:n_items, ..., 0].to(torch.bfloat16).clamp_max(0)
    active_bias = -F.softplus((pred_logits[:n_items, ..., 1] - pred_logits[:n_items, ..., 0]).float())
    if float(active_prob_power) != 1.0:
        active_bias = active_bias * float(active_prob_power)
    scores = scores + active_bias.to(torch.bfloat16).unsqueeze(-1)
    scores = scores.masked_fill(~valid_sorted[:, None, :], float("-inf"))
    scores_max, idx_max = scores.max(dim=1)

    offsets = torch.arange(n_items, device=pred_masks.device, dtype=torch.long).mul_(q).unsqueeze(1)
    labels_sorted = idx_max.long() + offsets
    if float(mask_thres) > float("-inf"):
        labels_sorted = labels_sorted.masked_fill(scores_max.float() < float(mask_thres), -1)

    predicted = torch.full((n_total,), -1, device=pred_masks.device, dtype=torch.long)
    predicted[orig_sorted[valid_sorted].long()] = labels_sorted[valid_sorted].long()
    predicted[~clf_keep] = -1

    active = full_valid_mask & (predicted >= 0)
    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    labels = predicted[active_idx].long()
    counts = torch.bincount(labels, minlength=num_labels)

    active_rows = torch.nonzero(counts > 0, as_tuple=False).squeeze(1)
    sums = torch.zeros(
        (num_labels, int(emb.shape[1])),
        device=emb.device,
        dtype=emb.dtype,
    )
    sums.scatter_add_(0, labels[:, None].expand(-1, int(emb.shape[1])), emb[active_idx])
    centroids = torch.zeros_like(sums)
    centroids[active_rows] = sums[active_rows] / counts[active_rows].to(emb.dtype).clamp_min(1).unsqueeze(1)
    centroids[active_rows] = F.normalize(centroids[active_rows], p=2, dim=1, eps=1e-12)

    small_rows = torch.nonzero((counts > 0) & (counts <= int(small_cluster_size)), as_tuple=False).squeeze(1)
    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = int(small_cluster_size) + 1
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    rows_all = torch.arange(num_labels, device=pred_masks.device, dtype=torch.long)
    target_rows = torch.nonzero(
        target_mask | ((rows_all == 0) & ~target_mask.any()),
        as_tuple=False,
    ).squeeze(1)
    target_valid = target_mask[target_rows]

    small_centroids = centroids[small_rows]
    target_centroids = centroids[target_rows]
    if bool(use_bf16_sim) and centroids.is_cuda:
        sim = small_centroids.to(torch.bfloat16) @ target_centroids.to(torch.bfloat16).t()
    else:
        sim = small_centroids @ target_centroids.t()
    same = small_rows[:, None] == target_rows[None, :]
    sim = sim.masked_fill(same, float("-inf"))
    sim = sim.masked_fill(~target_valid[None, :], float("-inf"))
    if target_min <= int(small_cluster_size):
        row_counts = counts[small_rows][:, None]
        target_counts = counts[target_rows][None, :]
        acyclic_target = (target_counts > row_counts) | (
            (target_counts == row_counts) & (target_rows[None, :] < small_rows[:, None])
        )
        sim = sim.masked_fill(~acyclic_target, float("-inf"))
    if int(max_merged_size) > 0:
        too_large = counts[small_rows][:, None] + counts[target_rows][None, :] > int(max_merged_size)
        sim = sim.masked_fill(too_large, float("-inf"))

    vals, col_pos = sim.max(dim=1)
    cols = target_rows[col_pos]
    keep = vals >= float(min_sim)

    remap = torch.arange(num_labels, device=pred_masks.device, dtype=torch.long)
    remap[small_rows[keep]] = cols[keep]
    for _ in range(4):
        remap = remap[remap]
    if int(max_merged_size) > 0:
        merged_sizes = torch.zeros(num_labels, device=pred_masks.device, dtype=counts.dtype)
        merged_sizes.scatter_add_(0, remap, counts)
        oversized = merged_sizes[remap] > int(max_merged_size)
        remap = torch.where(oversized, torch.arange(num_labels, device=pred_masks.device, dtype=torch.long), remap)
        for _ in range(2):
            remap = remap[remap]
    out = predicted.clone()
    out[active_idx] = remap[labels]
    return out


_assign_merge_label_space_compiled = torch.compile(
    _assign_merge_label_space_core,
    dynamic=True,
)


def _assign_merge_label_space_fast(
    pred_list,
    full_data,
    clf_keep,
    full_emb,
    mask_thres=0.0,
    active_prob_power=1.0,
    min_sim=0.9,
    small_cluster_size=2,
    max_merged_size=12,
    target_min_size=0,
    use_bf16_sim=False,
    normalized_emb=None,
    max_sub_events=0,
):
    if bool(getattr(full_data, "decoder_overlap", True)):
        return None
    if len(pred_list) != 1:
        return None
    pred_masks, pred_logits, point_order = pred_list[0]
    if pred_masks.dim() != 4 or pred_logits.dim() != 3:
        return None
    if not hasattr(full_data, "decoder_sub_all_idx") or not hasattr(full_data, "decoder_sub_valid_mask"):
        return None
    n_items = int(pred_masks.shape[0])
    if int(max_sub_events) > 0:
        n_items = min(n_items, int(max_sub_events))
    if n_items <= 0:
        return None
    batch_all_idx = full_data.decoder_sub_all_idx[:n_items].to(device=pred_masks.device, dtype=torch.long)
    batch_valid_mask = full_data.decoder_sub_valid_mask[:n_items].to(device=pred_masks.device, dtype=torch.bool)
    if int(batch_all_idx.shape[1]) != int(pred_masks.shape[2]):
        return None
    if point_order is None:
        n = int(pred_masks.shape[2])
        point_order = torch.arange(n, device=pred_masks.device, dtype=torch.long).expand(n_items, n)
    elif int(point_order.shape[1]) != int(pred_masks.shape[2]):
        return None
    emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
    return _assign_merge_label_space_compiled(
        pred_masks[:n_items],
        pred_logits[:n_items],
        point_order[:n_items],
        batch_all_idx,
        batch_valid_mask,
        full_data.valid_mask.bool(),
        clf_keep,
        emb,
        float(mask_thres),
        float(active_prob_power),
        float(min_sim),
        int(small_cluster_size),
        int(max_merged_size),
        int(target_min_size),
        bool(use_bf16_sim),
    )


@torch.no_grad()
def _merge_same_query_fragments(
    predicted,
    full_data,
    queries_per_sub_event,
    small_cluster_size=2,
    target_min_size=3,
    max_merged_size=12,
):
    """Cheaply merge tiny fragments that reuse the same decoder query id."""
    q = int(queries_per_sub_event)
    if q <= 0:
        return predicted
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not active.any():
        return predicted
    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    labels = predicted[active_idx].long()
    max_label = int(labels.max().item()) + 1
    if max_label <= 1:
        return predicted

    counts_all = torch.bincount(labels, minlength=max_label)
    active_labels = torch.nonzero(counts_all > 0, as_tuple=False).squeeze(1)
    counts = counts_all[active_labels]
    queries = active_labels.remainder(q)
    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = int(small_cluster_size) + 1
    target = counts >= target_min
    if int(max_merged_size) > 0:
        target &= counts < int(max_merged_size)
    if not bool(target.any()):
        return predicted

    base = max_label
    encoded = counts.long() * base + (base - 1 - active_labels.long())
    best_encoded = torch.full((q,), -1, device=predicted.device, dtype=torch.long)
    best_encoded.scatter_reduce_(0, queries[target], encoded[target], reduce="amax", include_self=True)
    best_label = torch.where(
        best_encoded >= 0,
        base - 1 - best_encoded.remainder(base),
        torch.full_like(best_encoded, -1),
    )

    small = counts <= int(small_cluster_size)
    target_for_label = best_label[queries]
    keep = small & (target_for_label >= 0) & (target_for_label != active_labels)
    if int(max_merged_size) > 0:
        keep &= (counts + counts_all[target_for_label.clamp_min(0)]) <= int(max_merged_size)
    if not bool(keep.any()):
        return predicted

    remap = torch.arange(max_label, device=predicted.device, dtype=torch.long)
    remap[active_labels[keep]] = target_for_label[keep]
    out = predicted.clone()
    out[active_idx] = remap[labels]
    return out


@torch.no_grad()
def _kmeans_refine_assignments_from_direct_state(
    init_pred,
    state,
    iters,
    min_margin=0.0,
    max_refine_cluster_size=0,
):
    if state is None or int(iters) != 1:
        return init_pred
    active_idx = state["active_idx"]
    if active_idx.numel() == 0:
        return init_pred
    counts = state["counts"]
    sums = state["sums"]
    remap = state["remap"]
    active_ids = state["active_ids"]
    inv = state["inv"]
    emb = state["normalized_emb"]

    k = int(counts.numel())
    merged_counts = torch.zeros(k, device=counts.device, dtype=counts.dtype)
    merged_counts.scatter_add_(0, remap, counts)
    root_rows = torch.nonzero(merged_counts > 0, as_tuple=False).squeeze(1)
    if root_rows.numel() <= 1:
        return init_pred

    merged_sums = torch.zeros_like(sums)
    merged_sums.scatter_add_(0, remap[:, None].expand(-1, int(sums.shape[1])), sums)
    centroids = merged_sums[root_rows] / merged_counts[root_rows].to(sums.dtype).unsqueeze(1)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)

    root_pos = torch.full((k,), -1, device=counts.device, dtype=torch.long)
    root_pos[root_rows] = torch.arange(root_rows.numel(), device=counts.device, dtype=torch.long)
    current_root = remap[inv]
    current_pos = root_pos[current_root]
    if not bool((current_pos >= 0).all()):
        return init_pred

    refine_mask = torch.ones_like(current_root, dtype=torch.bool)
    if int(max_refine_cluster_size) > 0:
        refine_mask = merged_counts[current_root] <= int(max_refine_cluster_size)
    if not bool(refine_mask.any()):
        return init_pred

    points = emb[active_idx[refine_mask]]
    current_root_refine = current_root[refine_mask]
    current_pos_refine = current_pos[refine_mask]
    sim = points @ centroids.t()
    if float(min_margin) > 0.0:
        current_sim = sim.gather(1, current_pos_refine[:, None]).squeeze(1)
        best_sim, best_pos = sim.max(dim=1)
        move = (best_sim - current_sim) >= float(min_margin)
        assign_root = torch.where(move, root_rows[best_pos], current_root_refine)
    else:
        assign_root = root_rows[sim.argmax(dim=1)]

    refined = init_pred.clone()
    refined[active_idx[refine_mask]] = active_ids[assign_root]
    return refined


@torch.no_grad()
def _filter_clusters_by_decoder_score(
    predicted,
    full_data,
    hit_scores,
    max_size=3,
    mean_threshold=0.0,
    min_threshold=0.0,
):
    """Drop only small clusters whose decoder hit confidence is weak overall."""
    if hit_scores is None:
        return predicted
    if float(mean_threshold) == 0.0 and float(min_threshold) == 0.0:
        return predicted

    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0) & torch.isfinite(hit_scores)
    if not active.any():
        return predicted

    active_ids, inv, counts = torch.unique(predicted[active], return_inverse=True, return_counts=True)
    if int(max_size) > 0:
        candidate = counts <= int(max_size)
    else:
        candidate = torch.ones_like(counts, dtype=torch.bool)
    if not candidate.any():
        return predicted

    scores = hit_scores[active].float()
    mean_scores = scatter_mean(scores.unsqueeze(1), inv, dim=0, dim_size=active_ids.numel()).squeeze(1)
    drop = candidate & (mean_scores < float(mean_threshold))
    if float(min_threshold) > 0.0:
        min_scores = torch.full(
            (active_ids.numel(),),
            float("inf"),
            device=predicted.device,
            dtype=scores.dtype,
        )
        min_scores.scatter_reduce_(0, inv, scores, reduce="amin", include_self=True)
        drop |= candidate & (min_scores < float(min_threshold))

    if not drop.any():
        return predicted
    out = predicted.clone()
    drop_ids = active_ids[drop]
    out[torch.isin(out, drop_ids)] = -1
    return out


@torch.no_grad()
def _dedup_same_layer_by_decoder_score(
    predicted,
    full_data,
    hit_scores,
    min_cluster_size=4,
    min_size_after=3,
    min_score_gap=0.0,
):
    """For duplicate detector layers inside a cluster, keep the highest-score hit."""
    if hit_scores is None:
        return predicted
    if not hasattr(full_data, "layer") or full_data.layer is None:
        return predicted

    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0) & torch.isfinite(hit_scores)
    if not active.any():
        return predicted

    active_ids, inv, counts = torch.unique(predicted[active], return_inverse=True, return_counts=True)
    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    inv_cpu = inv.detach().cpu().numpy()
    layers_cpu = full_data.layer[active_idx].detach().cpu().numpy()
    scores_cpu = hit_scores[active_idx].detach().float().cpu().numpy()
    counts_cpu = counts.detach().cpu().numpy()

    groups = defaultdict(list)
    for local_i, (cluster_i, layer) in enumerate(zip(inv_cpu, layers_cpu)):
        groups[(int(cluster_i), int(layer))].append(local_i)

    planned = defaultdict(list)
    for (cluster_i, _layer), locs in groups.items():
        if len(locs) <= 1 or int(counts_cpu[cluster_i]) < int(min_cluster_size):
            continue
        best = max(locs, key=lambda idx: float(scores_cpu[idx]))
        best_score = float(scores_cpu[best])
        for loc in locs:
            if loc == best:
                continue
            gap = best_score - float(scores_cpu[loc])
            if gap >= float(min_score_gap):
                planned[cluster_i].append((gap, loc))

    drop_local = []
    for cluster_i, locs in planned.items():
        max_drop = max(0, int(counts_cpu[cluster_i]) - int(min_size_after))
        if max_drop <= 0:
            continue
        locs.sort(reverse=True)
        drop_local.extend(loc for _gap, loc in locs[:max_drop])

    if not drop_local:
        return predicted
    out = predicted.clone()
    drop_idx = active_idx[torch.as_tensor(drop_local, device=active_idx.device, dtype=torch.long)]
    out[drop_idx] = -1
    return out


@torch.no_grad()
def _prune_small_clusters(
    predicted,
    full_data,
    full_emb,
    hit_scores=None,
    max_size=5,
    min_size_after=3,
    max_drop=1,
    min_sim_gap=0.0,
    min_score_gap=0.0,
    require_duplicate_layer=False,
    duplicate_layer_only=False,
):
    """Remove low-confidence outlier hits from small clusters.

    This is a conservative fake-hit cleanup pass. It uses only embedding
    cohesion, optional decoder hit scores, and optional detector layer ids.
    """
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not bool(active.any()):
        return predicted

    active_ids, inv, counts = torch.unique(predicted[active], return_inverse=True, return_counts=True)
    candidate = (counts > int(min_size_after)) & (counts <= int(max_size))
    if not bool(candidate.any()):
        return predicted
    if float(min_sim_gap) <= 0.0 and (hit_scores is None or float(min_score_gap) <= 0.0):
        return predicted

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    emb = _l2_normalize(full_emb)
    scores_all = hit_scores.float() if hit_scores is not None else None
    if int(max_drop) == 1 and not bool(require_duplicate_layer) and not bool(duplicate_layer_only):
        points = emb[active_idx]
        centroids = scatter_mean(points, inv, dim=0, dim_size=active_ids.numel())
        centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
        sim = (points * centroids[inv]).sum(dim=1)
        scores = scores_all[active_idx] if scores_all is not None else None
        metric = sim if scores is None else (sim + 0.05 * scores)
        candidate_hit = candidate[inv]
        metric_masked = torch.where(candidate_hit, metric, torch.full_like(metric, float("inf")))
        min_metric = torch.full(
            (active_ids.numel(),),
            float("inf"),
            device=predicted.device,
            dtype=metric.dtype,
        )
        min_metric.scatter_reduce_(0, inv, metric_masked, reduce="amin", include_self=True)
        drop = candidate_hit & (metric <= (min_metric[inv] + 1e-12))
        if float(min_sim_gap) > 0.0:
            mean_sim = scatter_mean(sim.unsqueeze(1), inv, dim=0, dim_size=active_ids.numel()).squeeze(1)
            drop &= (mean_sim[inv] - sim) >= float(min_sim_gap)
        if scores is not None and float(min_score_gap) > 0.0:
            mean_score = scatter_mean(scores.unsqueeze(1), inv, dim=0, dim_size=active_ids.numel()).squeeze(1)
            score_drop = (mean_score[inv] - scores) >= float(min_score_gap)
            if float(min_sim_gap) > 0.0:
                drop |= candidate_hit & (metric <= (min_metric[inv] + 1e-12)) & score_drop
            else:
                drop &= score_drop
        if not bool(drop.any()):
            return predicted
        out = predicted.clone()
        out[active_idx[drop]] = -1
        return out

    has_layer = bool(hasattr(full_data, "layer") and full_data.layer is not None)
    if bool(require_duplicate_layer) and not has_layer:
        return predicted

    out = predicted.clone()
    for row_t in torch.nonzero(candidate, as_tuple=False).squeeze(1):
        row = int(row_t.item())
        hit_idx = active_idx[inv == row_t]
        n_hits = int(hit_idx.numel())
        if n_hits <= int(min_size_after):
            continue

        eligible = torch.ones(n_hits, device=predicted.device, dtype=torch.bool)
        if has_layer and (bool(require_duplicate_layer) or bool(duplicate_layer_only)):
            layers = full_data.layer[hit_idx].long()
            unique_layers, layer_inv, layer_counts = torch.unique(
                layers,
                return_inverse=True,
                return_counts=True,
            )
            del unique_layers
            dup_hit = layer_counts[layer_inv] > 1
            if bool(require_duplicate_layer) and not bool(dup_hit.any()):
                continue
            if bool(duplicate_layer_only):
                eligible &= dup_hit
        if not bool(eligible.any()):
            continue

        points = emb[hit_idx]
        centroid = F.normalize(points.mean(dim=0), p=2, dim=0, eps=1e-12)
        sim = points @ centroid
        scores = scores_all[hit_idx] if scores_all is not None else None
        order = torch.argsort(sim if scores is None else (sim + 0.05 * scores), descending=False)
        dropped = 0
        for loc_t in order.detach().cpu().tolist():
            loc = int(loc_t)
            if dropped >= int(max_drop) or n_hits - dropped <= int(min_size_after):
                break
            if not bool(eligible[loc]):
                continue
            keep_local = torch.ones(n_hits, device=predicted.device, dtype=torch.bool)
            keep_local[loc] = False
            drop = False
            if float(min_sim_gap) > 0.0:
                sim_gap = float((sim[keep_local].mean() - sim[loc]).item())
                drop |= sim_gap >= float(min_sim_gap)
            if scores is not None and float(min_score_gap) > 0.0:
                score_gap = float((scores[keep_local].mean() - scores[loc]).item())
                drop |= score_gap >= float(min_score_gap)
            if not drop:
                continue
            out[hit_idx[loc]] = -1
            dropped += 1
    return out


@torch.no_grad()
def _split_overmerged_clusters(
    predicted,
    full_data,
    full_emb,
    min_size=6,
    max_size=12,
    min_part_size=3,
    min_duplicate_layers=1,
    max_part_duplicate_layers=0,
    min_improve=0.04,
    max_centroid_sim=0.85,
    iters=4,
    max_clusters=0,
):
    """Split small over-merged clusters into two embedding-coherent pieces.

    This is a conservative repair for decoder queries that absorb two nearby
    tracks. It only uses embeddings and optional detector layer ids.
    """
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not active.any():
        return predicted

    active_ids, inv, counts = torch.unique(predicted[active], return_inverse=True, return_counts=True)
    candidate_mask = (counts >= int(min_size)) & (counts <= int(max_size))
    if not candidate_mask.any():
        return predicted

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    has_layer = hasattr(full_data, "layer") and full_data.layer is not None
    duplicate_counts = None
    if has_layer:
        hit_layers_all = full_data.layer[active_idx].long()
        layer_min = int(hit_layers_all.min().item())
        layer_span = int(hit_layers_all.max().item()) - layer_min + 1
        layer_span = max(1, layer_span)
        pair_keys = inv.long() * layer_span + (hit_layers_all - layer_min)
        unique_pair_clusters = torch.unique(pair_keys) // layer_span
        unique_layer_counts = torch.bincount(unique_pair_clusters, minlength=active_ids.numel())
        duplicate_counts = counts - unique_layer_counts.to(device=counts.device, dtype=counts.dtype)
        if int(min_duplicate_layers) > 0:
            candidate_mask &= duplicate_counts >= int(min_duplicate_layers)
    elif int(min_duplicate_layers) > 0:
        return predicted

    candidate_rows = torch.nonzero(candidate_mask, as_tuple=False).squeeze(1)
    if candidate_rows.numel() == 0:
        return predicted
    if int(max_clusters) > 0 and candidate_rows.numel() > int(max_clusters):
        if duplicate_counts is not None:
            priority = duplicate_counts[candidate_rows].long() * 1024 + counts[candidate_rows].long()
        else:
            priority = counts[candidate_rows].long()
        _, order = priority.topk(int(max_clusters), largest=True)
        candidate_rows = candidate_rows[order]

    emb = _l2_normalize(full_emb)
    out = predicted.clone()
    next_label = int(predicted[predicted >= 0].max().item()) + 1 if (predicted >= 0).any() else 0

    for row_t in candidate_rows:
        row = int(row_t.item())
        hit_idx = active_idx[inv == row]
        n_hits = int(hit_idx.numel())
        if n_hits < 2 * int(min_part_size):
            continue

        hit_layers = None
        if has_layer:
            hit_layers = full_data.layer[hit_idx]

        points = emb[hit_idx]
        sim = points @ points.t()
        flat_min = int(sim.argmin().item())
        a = flat_min // n_hits
        b = flat_min % n_hits
        if a == b:
            continue
        centroids = F.normalize(torch.stack([points[a], points[b]], dim=0), p=2, dim=1, eps=1e-12)
        assign = None
        for _ in range(max(1, int(iters))):
            assign = (points @ centroids.t()).argmax(dim=1)
            if int((assign == 0).sum().item()) == 0 or int((assign == 1).sum().item()) == 0:
                break
            c0 = F.normalize(points[assign == 0].mean(dim=0), p=2, dim=0, eps=1e-12)
            c1 = F.normalize(points[assign == 1].mean(dim=0), p=2, dim=0, eps=1e-12)
            new_centroids = torch.stack([c0, c1], dim=0)
            if torch.allclose(new_centroids, centroids, rtol=0.0, atol=1e-5):
                centroids = new_centroids
                break
            centroids = new_centroids
        if assign is None:
            continue

        part0 = assign == 0
        part1 = assign == 1
        n0 = int(part0.sum().item())
        n1 = int(part1.sum().item())
        if min(n0, n1) < int(min_part_size):
            continue
        if has_layer and int(max_part_duplicate_layers) >= 0:
            dup0 = n0 - int(torch.unique(hit_layers[part0]).numel())
            dup1 = n1 - int(torch.unique(hit_layers[part1]).numel())
            if dup0 > int(max_part_duplicate_layers) or dup1 > int(max_part_duplicate_layers):
                continue

        old_centroid = F.normalize(points.mean(dim=0), p=2, dim=0, eps=1e-12)
        old_score = (points @ old_centroid).mean()
        new_score = (
            (points[part0] @ centroids[0]).sum() + (points[part1] @ centroids[1]).sum()
        ) / float(n_hits)
        sep = float((centroids[0] @ centroids[1]).item())
        improve = float((new_score - old_score).item())
        if improve < float(min_improve) or sep > float(max_centroid_sim):
            continue

        new_part = part0 if n0 <= n1 else part1
        out[hit_idx[new_part]] = next_label
        next_label += 1

    return out


@torch.no_grad()
def _regroup_residual_hits(
    predicted,
    full_data,
    full_emb,
    full_clf_scores,
    clf_threshold=0.015,
    max_cluster_size=3,
    topk=32,
    seed_sim=0.5,
    pair_sim=0.1,
    min_group_size=3,
    max_group_size=4,
    require_unique_layer=True,
    clear_pool=True,
    pair_repair=False,
    pair_repair_sim=0.3,
    pair_repair_topk=16,
    max_hits=0,
    chunk_size=1024,
):
    """Regroup unassigned hits and small fragments using local embedding neighbors.

    This pass is inference-safe: it only reads model classifier scores, encoder
    embeddings, valid_mask, and optional detector layer ids. It creates small
    size-3/4 fragments from a residual pool, then optionally creates size-2
    pairs that can be promoted by the existing size-2 padding pass.
    """
    if full_clf_scores is None:
        return predicted

    valid_mask = full_data.valid_mask.bool()
    scores = full_clf_scores.squeeze(-1).float()
    candidate_mask = valid_mask & (scores >= float(clf_threshold))

    active = valid_mask & (predicted >= 0)
    residual_mask = candidate_mask & (predicted < 0)
    if active.any() and int(max_cluster_size) >= 0:
        active_ids, _, counts = torch.unique(
            predicted[active], return_inverse=True, return_counts=True
        )
        small_ids = active_ids[counts <= int(max_cluster_size)]
        if small_ids.numel() > 0:
            residual_mask |= candidate_mask & active & torch.isin(predicted, small_ids)

    residual_idx = torch.nonzero(residual_mask, as_tuple=False).squeeze(1)
    if int(max_hits) > 0 and residual_idx.numel() > int(max_hits):
        _, order = scores[residual_idx].topk(int(max_hits), largest=True)
        residual_idx = residual_idx[order]
    n_residual = int(residual_idx.numel())
    if n_residual < int(min_group_size):
        return predicted

    emb = _l2_normalize(full_emb)
    points = emb[residual_idx]
    score_vals = scores[residual_idx]
    has_layer = bool(require_unique_layer and hasattr(full_data, "layer") and full_data.layer is not None)
    layers = full_data.layer[residual_idx] if has_layer else None

    # Build candidate groups seed-by-seed from top-k local neighbors.
    n_top = max(1, min(int(topk), n_residual - 1))
    candidates = []
    chunk_size = max(1, int(chunk_size))
    for start in range(0, n_residual, chunk_size):
        end = min(start + chunk_size, n_residual)
        sim = points[start:end] @ points.t()
        rows = torch.arange(end - start, device=sim.device)
        sim[rows, torch.arange(start, end, device=sim.device)] = float("-inf")
        if has_layer:
            sim = sim.masked_fill(layers[start:end, None] == layers[None, :], float("-inf"))
        vals, cols = sim.topk(n_top, dim=1)

        vals_cpu = vals.detach().float().cpu().numpy()
        cols_cpu = cols.detach().cpu().numpy()
        for row in range(end - start):
            seed = start + row
            group = [seed]
            group_layers = set()
            if has_layer:
                group_layers.add(int(layers[seed].item()))
            cohesion = []
            for slot in range(n_top):
                sim_to_seed = float(vals_cpu[row, slot])
                if sim_to_seed < float(seed_sim):
                    break
                nbr = int(cols_cpu[row, slot])
                if nbr < 0 or nbr == seed:
                    continue
                if has_layer:
                    layer = int(layers[nbr].item())
                    if layer in group_layers:
                        continue
                group_tensor = torch.as_tensor(group, device=points.device, dtype=torch.long)
                min_pair = float((points[nbr] @ points[group_tensor].t()).min().item())
                if min_pair < float(pair_sim):
                    continue
                group.append(nbr)
                cohesion.append(min_pair)
                if has_layer:
                    group_layers.add(layer)
                if len(group) >= int(max_group_size):
                    break
            if len(group) >= int(min_group_size):
                g = torch.as_tensor(group, device=points.device, dtype=torch.long)
                # Prefer coherent, high-classifier, larger groups. Coefficients
                # are intentionally tiny for clf/size so similarity dominates.
                score = (
                    float(np.mean(cohesion)) if cohesion else 0.0
                ) + 0.01 * float(score_vals[g].mean().item()) + 0.001 * len(group)
                candidates.append((score, tuple(group)))

    if not candidates and not pair_repair:
        return predicted

    out = predicted.clone()
    if clear_pool:
        out[residual_idx] = -1
    next_label = int(predicted[predicted >= 0].max().item()) + 1 if (predicted >= 0).any() else 0
    used = torch.zeros(n_residual, device=predicted.device, dtype=torch.bool)
    candidates.sort(reverse=True)
    for _score, group in candidates:
        group_t = torch.as_tensor(group, device=predicted.device, dtype=torch.long)
        if bool(used[group_t].any()):
            continue
        hit_idx = residual_idx[group_t]
        out[hit_idx] = next_label
        used[group_t] = True
        next_label += 1

    if pair_repair:
        remaining = torch.nonzero(~used, as_tuple=False).squeeze(1)
        if remaining.numel() >= 2:
            pair_top = max(1, min(int(pair_repair_topk), int(remaining.numel()) - 1))
            rem_points = points[remaining]
            rem_layers = layers[remaining] if has_layer else None
            pair_candidates = []
            for start in range(0, int(remaining.numel()), chunk_size):
                end = min(start + chunk_size, int(remaining.numel()))
                sim = rem_points[start:end] @ rem_points.t()
                rows = torch.arange(end - start, device=sim.device)
                sim[rows, torch.arange(start, end, device=sim.device)] = float("-inf")
                if has_layer:
                    sim = sim.masked_fill(rem_layers[start:end, None] == rem_layers[None, :], float("-inf"))
                vals, cols = sim.topk(pair_top, dim=1)
                vals_cpu = vals.detach().float().cpu().numpy()
                cols_cpu = cols.detach().cpu().numpy()
                for row in range(end - start):
                    a = start + row
                    for slot in range(pair_top):
                        score = float(vals_cpu[row, slot])
                        if score < float(pair_repair_sim):
                            break
                        b = int(cols_cpu[row, slot])
                        if a < b:
                            pair_candidates.append((score, a, b))
            pair_used = torch.zeros(remaining.numel(), device=predicted.device, dtype=torch.bool)
            pair_candidates.sort(reverse=True)
            for _score, a, b in pair_candidates:
                pair_t = torch.as_tensor([a, b], device=predicted.device, dtype=torch.long)
                if bool(pair_used[pair_t].any()):
                    continue
                hit_idx = residual_idx[remaining[pair_t]]
                out[hit_idx] = next_label
                pair_used[pair_t] = True
                next_label += 1

    return out


@torch.no_grad()
def _dedup_same_layer_clusters(
    predicted,
    full_data,
    full_emb,
    min_cluster_size=4,
    min_size_after=3,
    min_sim_gap=0.0,
    normalized_emb=None,
):
    """Conservative duplicate-layer cleanup; disabled by default."""
    if not hasattr(full_data, "layer") or full_data.layer is None:
        return predicted

    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    if not active.any():
        return predicted

    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    labels = predicted[active_idx].long()
    max_label = int(labels.max().item()) + 1
    if max_label <= 0:
        return predicted
    counts = torch.bincount(labels, minlength=max_label)
    cluster_ok = counts >= int(min_cluster_size)
    if not bool(cluster_ok.any()):
        return predicted

    emb = normalized_emb if normalized_emb is not None else _l2_normalize(full_emb)
    sums = torch.zeros((max_label, int(emb.shape[1])), device=emb.device, dtype=emb.dtype)
    sums.scatter_add_(0, labels[:, None].expand(-1, int(emb.shape[1])), emb[active_idx])
    centroids = sums / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
    sim = (emb[active_idx] * centroids[labels]).sum(dim=1)

    layers = full_data.layer[active_idx].long()
    layer_min = int(layers.min().item())
    layer_span = max(1, int(layers.max().item()) - layer_min + 1)
    keys = labels * int(layer_span) + (layers - int(layer_min))
    max_key = int(keys.max().item()) + 1
    key_counts = torch.bincount(keys, minlength=max_key)
    group_best = torch.full((max_key,), float("-inf"), device=sim.device, dtype=sim.dtype)
    group_best.scatter_reduce_(0, keys, sim, reduce="amax", include_self=True)
    gap = group_best[keys] - sim
    candidate = (
        cluster_ok[labels]
        & (key_counts[keys] > 1)
        & (gap >= float(min_sim_gap))
    )
    cand_local = torch.nonzero(candidate, as_tuple=False).squeeze(1)
    if cand_local.numel() == 0:
        return predicted

    cand_labels = labels[cand_local]
    cand_gap = gap[cand_local]
    max_drop = (counts[cand_labels] - int(min_size_after)).clamp_min(0)
    if not bool((max_drop > 0).any()):
        return predicted

    same_cluster = cand_labels[:, None] == cand_labels[None, :]
    better = cand_gap[None, :] > cand_gap[:, None]
    tie_better = (cand_gap[None, :] == cand_gap[:, None]) & (cand_local[None, :] > cand_local[:, None])
    rank = ((better | tie_better) & same_cluster).sum(dim=1)
    drop_local = cand_local[rank < max_drop]
    if drop_local.numel() == 0:
        return predicted

    out = predicted.clone()
    out[active_idx[drop_local]] = -1
    return out


def _merge_geometric_small_active_core(
    predicted,
    active_idx,
    active_ids,
    inv,
    counts,
    coords,
    layers,
    min_small_size: int,
    max_small_size: int,
    z_max: float,
    phi_max: float,
    max_merged_size: int,
    target_min_size: int,
    require_unique_layer: bool,
):
    num_clusters = int(counts.shape[0])
    d_coord = int(coords.shape[1])
    active_coords = coords[active_idx].float()
    r = active_coords[:, 2]

    coord_sums = torch.zeros((num_clusters, d_coord), device=coords.device, dtype=torch.float32)
    coord_sums.scatter_add_(0, inv[:, None].expand(-1, d_coord), active_coords)
    coord_means = coord_sums / counts.to(torch.float32).clamp_min(1).unsqueeze(1)

    inf = torch.tensor(float("inf"), device=coords.device, dtype=torch.float32)
    min_r = torch.full((num_clusters,), inf, device=coords.device, dtype=torch.float32)
    max_r = torch.full((num_clusters,), -inf, device=coords.device, dtype=torch.float32)
    min_r.scatter_reduce_(0, inv, r, reduce="amin", include_self=True)
    max_r.scatter_reduce_(0, inv, r, reduce="amax", include_self=True)

    min_hit = (r - min_r[inv]).abs() <= 1e-6
    max_hit = (r - max_r[inv]).abs() <= 1e-6
    min_sums = torch.zeros_like(coord_sums)
    max_sums = torch.zeros_like(coord_sums)
    min_sums.scatter_add_(0, inv[:, None].expand(-1, d_coord), active_coords * min_hit.to(torch.float32).unsqueeze(1))
    max_sums.scatter_add_(0, inv[:, None].expand(-1, d_coord), active_coords * max_hit.to(torch.float32).unsqueeze(1))
    min_counts = torch.zeros((num_clusters,), device=coords.device, dtype=torch.float32)
    max_counts = torch.zeros((num_clusters,), device=coords.device, dtype=torch.float32)
    min_counts.scatter_add_(0, inv, min_hit.to(torch.float32))
    max_counts.scatter_add_(0, inv, max_hit.to(torch.float32))
    start_coords = min_sums / min_counts.clamp_min(1).unsqueeze(1)
    end_coords = max_sums / max_counts.clamp_min(1).unsqueeze(1)

    min_small = int(min_small_size)
    if min_small <= 0:
        min_small = 2
    small_rows = torch.nonzero(
        (counts >= min_small) & (counts <= int(max_small_size)) & ((max_r - min_r).abs() > 1e-6),
        as_tuple=False,
    ).squeeze(1)
    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = 1
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    target_rows = torch.nonzero(target_mask, as_tuple=False).squeeze(1)

    seed0 = start_coords[small_rows]
    seed1 = end_coords[small_rows]
    r0 = seed0[:, 2]
    r1 = seed1[:, 2]
    z0 = seed0[:, 4]
    z1 = seed1[:, 4]
    p0 = seed0[:, 3]
    p1 = seed1[:, 3]
    dr = r1 - r0
    denom = torch.where(dr >= 0, dr.clamp_min(1e-6), dr.clamp_max(-1e-6))
    dphi01 = _wrap_normalized_phi_diff_torch(p1 - p0)

    target_coords = coord_means[target_rows]
    rc = target_coords[:, 2][None, :]
    zc = target_coords[:, 4][None, :]
    pc = target_coords[:, 3][None, :]
    t = (rc - r0[:, None]) / denom[:, None]
    z_pred = z0[:, None] + (z1 - z0)[:, None] * t
    dphi0c = _wrap_normalized_phi_diff_torch(pc - p0[:, None])
    phi_res = _wrap_normalized_phi_diff_torch(dphi0c - dphi01[:, None] * t).abs()
    z_res = (zc - z_pred).abs()

    score = -(z_res / max(float(z_max), 1e-12) + phi_res / max(float(phi_max), 1e-12))
    bad = (z_res > float(z_max)) | (phi_res > float(phi_max))
    bad |= small_rows[:, None] == target_rows[None, :]
    if int(max_merged_size) > 0:
        bad |= counts[small_rows][:, None] + counts[target_rows][None, :] > int(max_merged_size)
    target_counts = counts[target_rows][None, :]
    row_counts = counts[small_rows][:, None]
    acyclic_target = (target_counts > row_counts) | (
        (target_counts == row_counts) & (target_rows[None, :] < small_rows[:, None])
    )
    bad |= ~acyclic_target
    if bool(require_unique_layer):
        layer_span = 16
        active_layers = layers[active_idx].long().clamp(0, layer_span - 1)
        presence = torch.zeros((num_clusters, layer_span), device=predicted.device, dtype=torch.float32)
        presence[inv, active_layers] = 1.0
        overlap = (presence[small_rows] @ presence[target_rows].t()) > 0
        bad |= overlap
    score = score.masked_fill(bad, float("-inf"))

    vals, col_pos = score.max(dim=1)
    cols = target_rows[col_pos]
    keep = torch.isfinite(vals)

    remap = torch.arange(num_clusters, device=predicted.device, dtype=torch.long)
    remap[small_rows[keep]] = cols[keep]
    for _ in range(4):
        remap = remap[remap]
    if int(max_merged_size) > 0:
        merged_sizes = torch.zeros(num_clusters, device=predicted.device, dtype=counts.dtype)
        merged_sizes.scatter_add_(0, remap, counts)
        oversized = merged_sizes[remap] > int(max_merged_size)
        remap = torch.where(
            oversized,
            torch.arange(num_clusters, device=predicted.device, dtype=torch.long),
            remap,
        )
        for _ in range(2):
            remap = remap[remap]
    out = predicted.clone()
    out[active_idx] = active_ids[remap[inv]]
    return out


_merge_geometric_small_active_compiled = torch.compile(
    _merge_geometric_small_active_core,
    dynamic=True,
    mode="reduce-overhead",
)


@torch.no_grad()
def _merge_geometric_small_clusters_fast(
    predicted,
    full_data,
    min_small_size=2,
    max_small_size=4,
    z_max=0.003,
    phi_max=0.03,
    max_merged_size=7,
    target_min_size=1,
    require_unique_layer=True,
):
    if float(z_max) <= 0.0 or float(phi_max) <= 0.0:
        return predicted
    if not hasattr(full_data, "layer") or full_data.layer is None:
        return predicted
    valid_mask = full_data.valid_mask.bool()
    active = valid_mask & (predicted >= 0)
    active_idx = torch.nonzero(active, as_tuple=False).squeeze(1)
    if active_idx.numel() == 0:
        return predicted
    labels = predicted[active_idx].long()
    active_ids, inv, counts = torch.unique(labels, return_inverse=True, return_counts=True)
    min_small = int(min_small_size)
    if min_small <= 0:
        min_small = 2
    small_mask = (counts >= min_small) & (counts <= int(max_small_size))
    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = 1
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    if not bool(small_mask.any()) or not bool(target_mask.any()):
        return predicted
    return _merge_geometric_small_active_compiled(
        predicted,
        active_idx,
        active_ids,
        inv,
        counts,
        full_data.coords.float(),
        full_data.layer.long(),
        int(min_small_size),
        int(max_small_size),
        float(z_max),
        float(phi_max),
        int(max_merged_size),
        int(target_min_size),
        bool(require_unique_layer),
    )


def _merge_geometric_endpoint_active_core(
    predicted,
    active_idx,
    active_ids,
    inv,
    counts,
    coords,
    layers,
    min_size: int,
    max_size: int,
    z_max: float,
    phi_max: float,
    r_overlap_max: float,
    max_merged_size: int,
    target_min_size: int,
    max_layer_overlap: int,
):
    num_clusters = int(counts.shape[0])
    d_coord = int(coords.shape[1])
    active_coords = coords[active_idx].float()
    r = active_coords[:, 2]

    inf = torch.tensor(float("inf"), device=coords.device, dtype=torch.float32)
    min_r = torch.full((num_clusters,), inf, device=coords.device, dtype=torch.float32)
    max_r = torch.full((num_clusters,), -inf, device=coords.device, dtype=torch.float32)
    min_r.scatter_reduce_(0, inv, r, reduce="amin", include_self=True)
    max_r.scatter_reduce_(0, inv, r, reduce="amax", include_self=True)

    min_hit = (r - min_r[inv]).abs() <= 1e-6
    max_hit = (r - max_r[inv]).abs() <= 1e-6
    min_sums = torch.zeros((num_clusters, d_coord), device=coords.device, dtype=torch.float32)
    max_sums = torch.zeros((num_clusters, d_coord), device=coords.device, dtype=torch.float32)
    min_sums.scatter_add_(0, inv[:, None].expand(-1, d_coord), active_coords * min_hit.to(torch.float32).unsqueeze(1))
    max_sums.scatter_add_(0, inv[:, None].expand(-1, d_coord), active_coords * max_hit.to(torch.float32).unsqueeze(1))
    min_counts = torch.zeros((num_clusters,), device=coords.device, dtype=torch.float32)
    max_counts = torch.zeros((num_clusters,), device=coords.device, dtype=torch.float32)
    min_counts.scatter_add_(0, inv, min_hit.to(torch.float32))
    max_counts.scatter_add_(0, inv, max_hit.to(torch.float32))
    start_coords = min_sums / min_counts.clamp_min(1).unsqueeze(1)
    end_coords = max_sums / max_counts.clamp_min(1).unsqueeze(1)

    row_mask = (counts >= int(min_size)) & (counts <= int(max_size)) & ((max_r - min_r).abs() > 1e-6)
    rows = torch.nonzero(row_mask, as_tuple=False).squeeze(1)
    target_min = int(target_min_size)
    if target_min <= 0:
        target_min = 1
    target_mask = counts >= target_min
    if int(max_merged_size) > 0:
        target_mask &= counts < int(max_merged_size)
    targets = torch.nonzero(target_mask, as_tuple=False).squeeze(1)

    row_start = start_coords[rows]
    row_end = end_coords[rows]
    tgt_start = start_coords[targets]
    tgt_end = end_coords[targets]

    def residual(seed0, seed1, target):
        r0 = seed0[:, 2]
        r1 = seed1[:, 2]
        z0 = seed0[:, 4]
        z1 = seed1[:, 4]
        p0 = seed0[:, 3]
        p1 = seed1[:, 3]
        rt = target[:, 2][None, :]
        zt = target[:, 4][None, :]
        pt = target[:, 3][None, :]
        dr = r1 - r0
        denom = torch.where(dr >= 0, dr.clamp_min(1e-6), dr.clamp_max(-1e-6))
        t = (rt - r0[:, None]) / denom[:, None]
        z_pred = z0[:, None] + (z1 - z0)[:, None] * t
        dphi01 = _wrap_normalized_phi_diff_torch(p1 - p0)
        dphi0t = _wrap_normalized_phi_diff_torch(pt - p0[:, None])
        phi_res = _wrap_normalized_phi_diff_torch(dphi0t - dphi01[:, None] * t).abs()
        z_res = (zt - z_pred).abs()
        return z_res, phi_res

    z_hi, phi_hi = residual(row_start, row_end, tgt_start)
    z_lo, phi_lo = residual(row_end, row_start, tgt_end)
    hi_order = tgt_start[:, 2][None, :] >= (row_end[:, 2][:, None] - float(r_overlap_max))
    lo_order = tgt_end[:, 2][None, :] <= (row_start[:, 2][:, None] + float(r_overlap_max))
    hi_bad = (~hi_order) | (z_hi > float(z_max)) | (phi_hi > float(phi_max))
    lo_bad = (~lo_order) | (z_lo > float(z_max)) | (phi_lo > float(phi_max))
    hi_score = z_hi / max(float(z_max), 1e-12) + phi_hi / max(float(phi_max), 1e-12)
    lo_score = z_lo / max(float(z_max), 1e-12) + phi_lo / max(float(phi_max), 1e-12)
    score = torch.minimum(hi_score.masked_fill(hi_bad, float("inf")), lo_score.masked_fill(lo_bad, float("inf")))

    bad = rows[:, None] == targets[None, :]
    if int(max_merged_size) > 0:
        bad |= counts[rows][:, None] + counts[targets][None, :] > int(max_merged_size)
    target_counts = counts[targets][None, :]
    row_counts = counts[rows][:, None]
    acyclic_target = (target_counts > row_counts) | (
        (target_counts == row_counts) & (targets[None, :] < rows[:, None])
    )
    bad |= ~acyclic_target
    if int(max_layer_overlap) >= 0:
        layer_span = 16
        active_layers = layers[active_idx].long().clamp(0, layer_span - 1)
        presence = torch.zeros((num_clusters, layer_span), device=predicted.device, dtype=torch.float32)
        presence[inv, active_layers] = 1.0
        overlap_count = presence[rows] @ presence[targets].t()
        bad |= overlap_count > float(max_layer_overlap)
    score = score.masked_fill(bad, float("inf"))

    vals, col_pos = score.min(dim=1)
    cols = targets[col_pos]
    keep = torch.isfinite(vals)

    remap = torch.arange(num_clusters, device=predicted.device, dtype=torch.long)
    remap[rows[keep]] = cols[keep]
    for _ in range(4):
        remap = remap[remap]
    if int(max_merged_size) > 0:
        merged_sizes = torch.zeros(num_clusters, device=predicted.device, dtype=counts.dtype)
        merged_sizes.scatter_add_(0, remap, counts)
        oversized = merged_sizes[remap] > int(max_merged_size)
        remap = torch.where(
            oversized,
            torch.arange(num_clusters, device=predicted.device, dtype=torch.long),
            remap,
        )
        for _ in range(2):
            remap = remap[remap]
    out = predicted.clone()
    out[active_idx] = active_ids[remap[inv]]
    return out


_merge_geometric_endpoint_active_compiled = torch.compile(
    _merge_geometric_endpoint_active_core,
    dynamic=True,
    mode="reduce-overhead",
)


