def _dedup_same_layer_label_space_core(
    predicted,
    active_idx,
    labels,
    counts,
    emb,
    layers,
    layer_min: int,
    layer_span: int,
    min_cluster_size: int,
    min_size_after: int,
    min_sim_gap: float,
):
    max_label = int(counts.shape[0])
    sums = torch.zeros((max_label, int(emb.shape[1])), device=emb.device, dtype=emb.dtype)
    sums.scatter_add_(0, labels[:, None].expand(-1, int(emb.shape[1])), emb[active_idx])
    centroids = sums / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
    sim = (emb[active_idx] * centroids[labels]).sum(dim=1)

    layer_shift = (layers[active_idx].long() - int(layer_min)).clamp(0, int(layer_span) - 1)
    keys = labels * int(layer_span) + layer_shift
    key_counts = torch.bincount(keys, minlength=max_label * int(layer_span))
    group_best = torch.full((max_label * int(layer_span),), float("-inf"), device=sim.device, dtype=sim.dtype)
    group_best.scatter_reduce_(0, keys, sim, reduce="amax", include_self=True)
    gap = group_best[keys] - sim
    candidate = (
        (counts[labels] >= int(min_cluster_size))
        & (key_counts[keys] > 1)
        & (gap >= float(min_sim_gap))
    )
    cand_local = torch.nonzero(candidate, as_tuple=False).squeeze(1)
    cand_labels = labels[cand_local]
    cand_gap = gap[cand_local]
    max_drop = (counts[cand_labels] - int(min_size_after)).clamp_min(0)

    same_cluster = cand_labels[:, None] == cand_labels[None, :]
    better = cand_gap[None, :] > cand_gap[:, None]
    tie_better = (cand_gap[None, :] == cand_gap[:, None]) & (cand_local[None, :] > cand_local[:, None])
    rank = ((better | tie_better) & same_cluster).sum(dim=1)
    drop_local = cand_local[(rank < max_drop) & (max_drop > 0)]

    out = predicted.clone()
    out[active_idx[drop_local]] = -1
    return out


_dedup_same_layer_label_space_core_compiled = torch.compile(
    _dedup_same_layer_label_space_core,
    dynamic=True,
)


def _codex_fast_same_query_core(
    predicted,
    valid_mask,
    emb,
    layers,
    num_labels: int,
):
    n_total = int(predicted.shape[0])
    feat_dim = int(emb.shape[1])
    n_labels = int(num_labels)
    active_cap = _CODEX_ACTIVE_CAP
    label_cap = _CODEX_LABEL_CAP
    layer_span = 18
    q_same = max(1, int(_CODEX_SAME_QUERY_Q))

    dummy_pred = torch.full((1,), n_labels, device=predicted.device, dtype=predicted.dtype)
    dummy_bool = torch.zeros((1,), device=predicted.device, dtype=torch.bool)
    dummy_emb = torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)
    dummy_layer = torch.zeros((1,), device=layers.device, dtype=layers.dtype)
    pred_pad = torch.cat([predicted, dummy_pred], dim=0)
    emb_pad = torch.cat([emb, dummy_emb], dim=0)
    layer_pad = torch.cat([layers, dummy_layer], dim=0)

    active_mask = valid_mask.bool() & (predicted >= 0)
    active_idx = torch.nonzero_static(active_mask, size=active_cap, fill_value=n_total).squeeze(1)
    active_valid = active_idx < n_total
    labels = pred_pad[active_idx].long().clamp(0, n_labels)
    points_all = emb_pad[active_idx]
    point_weight = active_valid.to(emb.dtype)

    counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
    counts.scatter_add_(0, labels, active_valid.to(torch.long))
    sums_full = torch.zeros((n_labels + 1, feat_dim), device=emb.device, dtype=emb.dtype)
    sums_full.scatter_add_(0, labels[:, None].expand(-1, feat_dim), points_all * point_weight[:, None])
    out = predicted

    if _CODEX_DO_SAME_QUERY:
        same_rows = torch.nonzero_static(
            (counts[:n_labels] > 0) & (counts[:n_labels] < int(_CODEX_SAME_QUERY_MAX_MERGED)),
            size=label_cap,
            fill_value=n_labels,
        ).squeeze(1)
        same_valid = same_rows < n_labels
        same_safe = same_rows.clamp(0, n_labels)
        same_query = same_rows.clamp(0, n_labels - 1).remainder(q_same)
        same_counts = counts[same_safe]
        base = n_labels + 1
        target_candidate = same_valid & (same_counts >= int(_CODEX_SAME_QUERY_TARGET_MIN))
        encoded = same_counts.long() * base + (base - 1 - same_safe.long())
        encoded = torch.where(target_candidate, encoded, torch.full_like(encoded, -1))
        best_encoded = torch.full((q_same,), -1, device=predicted.device, dtype=torch.long)
        best_encoded.scatter_reduce_(0, same_query, encoded, reduce="amax", include_self=True)
        best_label = torch.where(
            best_encoded >= 0,
            base - 1 - best_encoded.remainder(base),
            torch.full_like(best_encoded, n_labels),
        )
        target_for_row = best_label[same_query]
        keep = (
            same_valid
            & (same_counts <= int(_CODEX_SAME_QUERY_SMALL))
            & (target_for_row < n_labels)
            & (target_for_row != same_rows)
            & (
                same_counts + counts[target_for_row.clamp(0, n_labels)]
                <= int(_CODEX_SAME_QUERY_MAX_MERGED)
            )
        )
        remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        remap[same_rows] = torch.where(keep, target_for_row, remap[same_rows])
        for _ in range(2):
            remap = remap[remap]
        merged_sizes = torch.zeros_like(counts)
        merged_sizes.scatter_add_(0, remap, counts)
        base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        remap = torch.where(merged_sizes[remap] > int(_CODEX_SAME_QUERY_MAX_MERGED), base_remap, remap)
        for _ in range(2):
            remap = remap[remap]
        labels = remap[labels].long().clamp(0, n_labels)
        out_pad = pred_pad.clone()
        out_pad[active_idx] = labels
        out = out_pad[:n_total]

        merged_counts = torch.zeros_like(counts)
        merged_counts.scatter_add_(0, remap, counts)
        merged_sums = torch.zeros_like(sums_full)
        merged_sums.scatter_add_(0, remap[:, None].expand(-1, feat_dim), sums_full)
        counts = merged_counts
        sums_full = merged_sums

    if _CODEX_DO_DEDUP:
        if _CODEX_DEDUP_BY_HIT_SCORE:
            hit_sim = torch.where(
                active_valid,
                hit_score_pad[active_idx].to(emb.dtype),
                torch.full((active_cap,), float("-inf"), device=emb.device, dtype=emb.dtype),
            )
            dedup_gap = float(_CODEX_DEDUP_SCORE_GAP)
        else:
            centroids_full = sums_full / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
            centroids_full = F.normalize(centroids_full, p=2, dim=1, eps=1e-12)
            hit_sim = (points_all * centroids_full[labels]).sum(dim=1)
            dedup_gap = 0.10
        layer_shift = layer_pad[active_idx].long().clamp(0, layer_span - 1)
        keys = labels * layer_span + layer_shift
        key_counts = torch.zeros((n_labels + 1) * layer_span, device=predicted.device, dtype=torch.long)
        key_counts.scatter_add_(0, keys, active_valid.to(torch.long))
        group_best = torch.full(
            ((n_labels + 1) * layer_span,),
            float("-inf"),
            device=hit_sim.device,
            dtype=hit_sim.dtype,
        )
        group_best.scatter_reduce_(0, keys, hit_sim, reduce="amax", include_self=True)
        gap = group_best[keys] - hit_sim
        candidate = active_valid & (counts[labels] >= 4) & (key_counts[keys] > 1) & (gap >= dedup_gap)
        drop = candidate & ((counts[labels] - 3) > 0)
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = torch.where(drop, torch.full_like(labels, -1), out_pad[active_idx])
        out = out_pad[:n_total]

    return out


def _codex_nomask_target_core(
    predicted,
    valid_mask,
    emb,
    clf_scores,
    layers,
    coords,
    decoder_hit_scores,
    num_labels: int,
):
    # Static-shape version of the ref32 target path:
    # pre-kmeans(2, ref<=32) -> merge -> same-layer dedup -> size-2 pad.
    if (
        _CODEX_FAST_SAME_QUERY
        and (not _CODEX_DO_PRE_REFINE)
        and (not _CODEX_DO_SEMANTIC_MERGE)
        and (not _CODEX_DO_GEO_MERGE)
        and (not _CODEX_DO_ENDPOINT_MERGE)
        and (not _CODEX_DO_PAD)
    ):
        return _codex_fast_same_query_core(
            predicted,
            valid_mask,
            emb,
            layers,
            int(num_labels),
        )

    n_total = int(predicted.shape[0])
    feat_dim = int(emb.shape[1])
    n_labels = int(num_labels)
    active_cap = _CODEX_ACTIVE_CAP
    refine_cap = _CODEX_REFINE_CAP
    label_cap = _CODEX_LABEL_CAP
    small_cap = _CODEX_SMALL_CAP
    target_cap = _CODEX_TARGET_CAP
    size2_cap = _CODEX_SIZE2_CAP
    pad_cluster_cap = _CODEX_PAD_CLUSTER_CAP
    pad_cand_cap = _CODEX_PAD_CAND_CAP
    layer_span = 18

    dummy_pred = torch.full((1,), n_labels, device=predicted.device, dtype=predicted.dtype)
    dummy_bool = torch.zeros((1,), device=predicted.device, dtype=torch.bool)
    dummy_emb = torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)
    dummy_layer = torch.zeros((1,), device=layers.device, dtype=layers.dtype)
    dummy_coords = torch.zeros((1, int(coords.shape[1])), device=coords.device, dtype=coords.dtype)
    dummy_clf = torch.full((1,), float("-inf"), device=clf_scores.device, dtype=clf_scores.dtype)
    dummy_hit_score = torch.full((1,), float("inf"), device=decoder_hit_scores.device, dtype=decoder_hit_scores.dtype)
    pred_pad = torch.cat([predicted, dummy_pred], dim=0)
    valid_pad = torch.cat([valid_mask.bool(), dummy_bool], dim=0)
    emb_pad = torch.cat([emb, dummy_emb], dim=0)
    layer_pad = torch.cat([layers, dummy_layer], dim=0)
    coords_pad = torch.cat([coords, dummy_coords], dim=0)
    clf_pad = torch.cat([clf_scores, dummy_clf], dim=0)
    hit_score_pad = torch.cat([decoder_hit_scores.float(), dummy_hit_score], dim=0)

    active_mask = valid_mask.bool() & (predicted >= 0)
    active_idx = torch.nonzero_static(active_mask, size=active_cap, fill_value=n_total).squeeze(1)
    active_valid = active_idx < n_total
    labels = pred_pad[active_idx].long().clamp(0, n_labels)
    points_all = emb_pad[active_idx]
    point_weight = active_valid.to(emb.dtype)

    counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
    counts.scatter_add_(0, labels, active_valid.to(torch.long))
    if _CODEX_LABEL_BY_COUNT:
        active_vals, active_ids = counts[:n_labels].topk(label_cap, largest=True)
        active_id_valid = active_vals > 0
    else:
        active_ids = torch.nonzero_static(counts[:n_labels] > 0, size=label_cap, fill_value=n_labels).squeeze(1)
        active_id_valid = active_ids < n_labels
    row_map = torch.full((n_labels + 1,), label_cap - 1, device=predicted.device, dtype=torch.long)
    row_map[active_ids] = torch.arange(label_cap, device=predicted.device, dtype=torch.long)
    inv = row_map[labels]
    label_selected = active_id_valid[inv] & (active_ids[inv] == labels)
    counts_init = counts[active_ids].to(emb.dtype)

    sums = torch.zeros((label_cap, feat_dim), device=emb.device, dtype=emb.dtype)
    selected_weight = (active_valid & label_selected).to(emb.dtype)
    sums.scatter_add_(0, inv[:, None].expand(-1, feat_dim), points_all * selected_weight[:, None])
    centroids = sums / counts_init.clamp_min(1).unsqueeze(1)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
    centroids = torch.where(active_id_valid[:, None], centroids, torch.zeros_like(centroids))

    refine_mask = active_valid & label_selected & (counts[labels] <= _CODEX_REFINE_MAX_SIZE)
    if _CODEX_REFINE_SCORE_MAX < 1.0e8:
        refine_mask = refine_mask & (hit_score_pad[active_idx] <= float(_CODEX_REFINE_SCORE_MAX))
    if not _CODEX_DO_PRE_REFINE:
        refine_mask = active_valid & torch.zeros_like(active_valid, dtype=torch.bool)
    if _CODEX_REFINE_BY_SMALL_SIZE:
        refine_priority = torch.where(
            refine_mask,
            -counts[labels].to(torch.float32),
            torch.full((active_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
        )
        refine_vals, refine_pos = refine_priority.topk(refine_cap, largest=True)
    else:
        refine_vals = torch.zeros((refine_cap,), device=predicted.device, dtype=torch.float32)
        refine_pos = torch.nonzero_static(refine_mask, size=refine_cap, fill_value=active_cap).squeeze(1)
    points_pad = torch.cat([points_all, torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)], dim=0)
    inv_pad = torch.cat([inv, torch.full((1,), label_cap - 1, device=predicted.device, dtype=torch.long)], dim=0)
    refine_valid = (refine_pos < active_cap) & torch.isfinite(refine_vals)
    points = points_pad[refine_pos]
    assign = inv_pad[refine_pos]
    label_col_valid = active_id_valid
    refine_steps = max(1, int(_CODEX_REFINE_STEPS))
    moved_once = torch.zeros_like(refine_valid)
    step2_cap = int(_CODEX_REFINE_STEP2_CAP)
    for step in range(refine_steps):
        use_step_cap = (step > 0) and (step2_cap > 0)
        if use_step_cap:
            step_mask = refine_valid
            if _CODEX_REFINE_STEP2_MOVED_ONLY:
                step_mask = step_mask & moved_once
            if _CODEX_REFINE_STEP2_BY_SMALL_SIZE:
                step_assign_labels = active_ids[assign.clamp(0, label_cap - 1)].clamp(0, n_labels)
                step_priority = torch.where(
                    step_mask,
                    -counts[step_assign_labels].to(torch.float32),
                    torch.full((refine_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
                )
                step_vals, step_pos = step_priority.topk(step2_cap, largest=True)
            else:
                step_vals = torch.zeros((step2_cap,), device=predicted.device, dtype=torch.float32)
                step_pos = torch.nonzero_static(step_mask, size=step2_cap, fill_value=refine_cap).squeeze(1)
            points_step_pad = torch.cat(
                [points, torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)],
                dim=0,
            )
            assign_step_pad = torch.cat(
                [
                    assign,
                    torch.full((1,), label_cap - 1, device=predicted.device, dtype=torch.long),
                ],
                dim=0,
            )
            points_step = points_step_pad[step_pos]
            assign_step = assign_step_pad[step_pos]
            refine_valid_step = (step_pos < refine_cap) & torch.isfinite(step_vals)
        else:
            points_step = points
            assign_step = assign
            refine_valid_step = refine_valid
        if _CODEX_REFINE_GROUPED_SUBEVENT:
            q_same = max(1, int(_CODEX_SAME_QUERY_Q))
            group_count = max(1, (n_labels + q_same - 1) // q_same)
            group_label_cap = int(_CODEX_REFINE_GROUP_LABEL_CAP)
            group_point_cap = int(_CODEX_REFINE_GROUP_POINT_CAP)
            if use_step_cap and int(_CODEX_REFINE_GROUP_POINT_CAP_STEP2) > 0:
                group_point_cap = int(_CODEX_REFINE_GROUP_POINT_CAP_STEP2)
            label_group = torch.div(active_ids.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
            point_group = label_group[assign_step.clamp(0, label_cap - 1)]
            centroids_group_pad = torch.cat(
                [centroids, torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)],
                dim=0,
            )
            points_step_group_pad = torch.cat(
                [points_step, torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)],
                dim=0,
            )
            assign_step_group_pad = torch.cat(
                [
                    assign_step,
                    torch.full((1,), label_cap, device=predicted.device, dtype=torch.long),
                ],
                dim=0,
            )
            assign_update_pad = torch.cat(
                [
                    assign_step,
                    torch.full((1,), label_cap - 1, device=predicted.device, dtype=torch.long),
                ],
                dim=0,
            )
            moved_pad = torch.cat(
                [
                    torch.zeros_like(refine_valid_step),
                    torch.zeros((1,), device=predicted.device, dtype=torch.bool),
                ],
                dim=0,
            )
            step_len = int(points_step.shape[0])
            group_col_arange = torch.arange(group_label_cap, device=predicted.device, dtype=torch.long)
            for group_id in range(group_count):
                col_mask = label_col_valid & (label_group == group_id)
                col_pos = torch.nonzero_static(
                    col_mask,
                    size=group_label_cap,
                    fill_value=label_cap,
                ).squeeze(1)
                col_valid = col_pos < label_cap
                col_safe = torch.where(col_valid, col_pos, torch.full_like(col_pos, label_cap))
                row_mask = refine_valid_step & (point_group == group_id)
                row_pos = torch.nonzero_static(
                    row_mask,
                    size=group_point_cap,
                    fill_value=step_len,
                ).squeeze(1)
                row_valid = row_pos < step_len
                row_safe = torch.where(row_valid, row_pos, torch.full_like(row_pos, step_len))
                points_g = points_step_group_pad[row_safe]
                assign_g = assign_step_group_pad[row_safe]
                centroids_g = centroids_group_pad[col_safe]
                sim_g = points_g.to(torch.float16) @ centroids_g.to(torch.float16).t()
                sim_g = sim_g.masked_fill(~(row_valid[:, None] & col_valid[None, :]), float("-inf"))
                local_col = torch.full(
                    (label_cap + 1,),
                    group_label_cap,
                    device=predicted.device,
                    dtype=torch.long,
                )
                local_col[col_safe] = group_col_arange
                assign_local = local_col[assign_g.clamp(0, label_cap)]
                assign_in_cols = assign_local < group_label_cap
                assign_local_safe = assign_local.clamp(0, group_label_cap - 1)
                current_sim = sim_g.gather(1, assign_local_safe[:, None]).squeeze(1)
                best_sim, best_col = sim_g.max(dim=1)
                best_assign = col_safe[best_col].clamp_max(label_cap - 1)
                move_g = row_valid & assign_in_cols & ((best_sim - current_sim) >= float(_CODEX_REFINE_MARGIN))
                chosen = torch.where(move_g, best_assign, assign_g.clamp_max(label_cap - 1))
                assign_update_pad[row_safe] = chosen
                moved_pad[row_safe] = move_g
            assign_step = assign_update_pad[:step_len]
            move = moved_pad[:step_len]
        else:
            sim = points_step.to(torch.float16) @ centroids.to(torch.float16).t()
            sim = sim.masked_fill(~label_col_valid[None, :], float("-inf"))
            if _CODEX_REFINE_SAME_SUBEVENT_ONLY:
                q_same = max(1, int(_CODEX_SAME_QUERY_Q))
                label_group = torch.div(active_ids.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
                point_group = label_group[assign_step.clamp(0, label_cap - 1)]
                sim = sim.masked_fill(label_group[None, :] != point_group[:, None], float("-inf"))
            current_sim = sim.gather(1, assign_step[:, None]).squeeze(1)
            best_sim, best_assign = sim.max(dim=1)
            move = refine_valid_step & ((best_sim - current_sim) >= float(_CODEX_REFINE_MARGIN))
            assign_step = torch.where(move, best_assign, assign_step)
        if use_step_cap:
            assign_full_pad = torch.cat(
                [
                    assign,
                    torch.full((1,), label_cap - 1, device=predicted.device, dtype=torch.long),
                ],
                dim=0,
            )
            assign_full_pad[step_pos] = assign_step
            assign = assign_full_pad[:refine_cap]
        else:
            assign = assign_step
            if step == 0:
                moved_once = move
        if step + 1 >= refine_steps:
            continue
        inv_update_pad = inv_pad.clone()
        inv_update_pad[refine_pos] = assign
        inv_updated = inv_update_pad[:active_cap]
        new_sums = torch.zeros_like(sums)
        new_sums.scatter_add_(0, inv_updated[:, None].expand(-1, feat_dim), points_all * selected_weight[:, None])
        new_counts = torch.zeros((label_cap,), device=emb.device, dtype=emb.dtype)
        new_counts.scatter_add_(0, inv_updated, selected_weight)
        new_centroids = F.normalize(new_sums, p=2, dim=1, eps=1e-12)
        centroids = torch.where((new_counts > 0)[:, None] & active_id_valid[:, None], new_centroids, centroids)

    out_pad = pred_pad.clone()
    hit_idx = torch.cat([active_idx, torch.full((1,), n_total, device=predicted.device, dtype=torch.long)], dim=0)
    out_pad[hit_idx[refine_pos]] = active_ids[assign]
    out = out_pad[:n_total]

    active_idx = torch.nonzero_static(valid_mask.bool() & (out >= 0), size=active_cap, fill_value=n_total).squeeze(1)
    active_valid = active_idx < n_total
    out_pad = torch.cat([out, dummy_pred], dim=0)
    labels = out_pad[active_idx].long().clamp(0, n_labels)
    points_all = emb_pad[active_idx]
    point_weight = active_valid.to(emb.dtype)
    counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
    counts.scatter_add_(0, labels, active_valid.to(torch.long))
    sums_full = torch.zeros((n_labels + 1, feat_dim), device=emb.device, dtype=emb.dtype)
    sums_full.scatter_add_(0, labels[:, None].expand(-1, feat_dim), points_all * point_weight[:, None])
    centroids_full = sums_full / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
    centroids_full = F.normalize(centroids_full, p=2, dim=1, eps=1e-12)
    cluster_clf_for_rank = torch.zeros(n_labels + 1, device=predicted.device, dtype=clf_pad.dtype)
    if _CODEX_TARGET_BY_CLF:
        cluster_clf_sum = torch.zeros_like(cluster_clf_for_rank)
        clf_active_for_rank = clf_pad[active_idx]
        cluster_clf_sum.scatter_add_(
            0,
            labels,
            torch.where(active_valid, clf_active_for_rank, torch.zeros_like(clf_active_for_rank)),
        )
        cluster_clf_for_rank = cluster_clf_sum / counts.to(cluster_clf_sum.dtype).clamp_min(1)

    if _CODEX_DO_SEMANTIC_MERGE:
        small_rows = torch.nonzero_static(
            (counts[:n_labels] > 0) & (counts[:n_labels] <= int(_CODEX_SEMANTIC_MAX_SIZE)),
            size=small_cap,
            fill_value=n_labels,
        ).squeeze(1)
        max_merged_size = int(_CODEX_MAX_MERGED_SIZE)
        target_mask_for_rank = (counts[:n_labels] >= 1) & (counts[:n_labels] < max_merged_size)
        if _CODEX_TARGET_BY_CLF:
            target_scores_for_rank = cluster_clf_for_rank[:n_labels].masked_fill(
                ~target_mask_for_rank,
                float("-inf"),
            )
            target_vals_for_rank, target_rows = target_scores_for_rank.topk(target_cap, largest=True)
        else:
            target_vals_for_rank = torch.zeros((target_cap,), device=predicted.device, dtype=cluster_clf_for_rank.dtype)
            target_rows = torch.nonzero_static(
                target_mask_for_rank,
                size=target_cap,
                fill_value=n_labels,
            ).squeeze(1)
        small_valid = small_rows < n_labels
        target_valid = (target_rows < n_labels) & torch.isfinite(target_vals_for_rank)
        small_centroids = centroids_full[small_rows]
        target_centroids = centroids_full[target_rows]
        merge_sim = small_centroids @ target_centroids.t()
        merge_sim = merge_sim.masked_fill(~(small_valid[:, None] & target_valid[None, :]), float("-inf"))
        merge_sim = merge_sim.masked_fill(small_rows[:, None] == target_rows[None, :], float("-inf"))
        row_counts = counts[small_rows][:, None]
        target_counts = counts[target_rows][None, :]
        acyclic_target = (target_counts > row_counts) | (
            (target_counts == row_counts) & (target_rows[None, :] < small_rows[:, None])
        )
        merge_sim = merge_sim.masked_fill(~acyclic_target, float("-inf"))
        merge_sim = merge_sim.masked_fill(row_counts + target_counts > max_merged_size, float("-inf"))
        vals, col_pos = merge_sim.max(dim=1)
        cols = target_rows[col_pos]
        keep = small_valid & (vals >= float(_CODEX_SEMANTIC_MIN_SIM))
        remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        remap[small_rows] = torch.where(keep, cols, remap[small_rows])
        for _ in range(4):
            remap = remap[remap]
        merged_sizes = torch.zeros(n_labels + 1, device=predicted.device, dtype=counts.dtype)
        merged_sizes.scatter_add_(0, remap, counts)
        base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        remap = torch.where(merged_sizes[remap] > max_merged_size, base_remap, remap)
        for _ in range(2):
            remap = remap[remap]
        labels = remap[labels].long().clamp(0, n_labels)
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = labels
        out = out_pad[:n_total]

        merged_counts = torch.zeros_like(counts)
        merged_counts.scatter_add_(0, remap, counts)
        merged_sums = torch.zeros_like(sums_full)
        merged_sums.scatter_add_(0, remap[:, None].expand(-1, feat_dim), sums_full)
        counts = merged_counts
        sums_full = merged_sums

    # Geometry-only recovery for small fragments whose endpoints extrapolate
    # into a nearby compatible fragment.
    d_coord = int(coords.shape[1])
    geo_small_cap = _CODEX_GEO_SMALL_CAP
    geo_endpoint_cap = _CODEX_GEO_ENDPOINT_CAP
    geo_target_cap = _CODEX_GEO_TARGET_CAP
    geo_layer_span = 16
    active_coords = coords_pad[active_idx].float()
    active_r = active_coords[:, 2]
    inf32 = torch.tensor(float("inf"), device=coords.device, dtype=torch.float32)
    neg_inf32 = torch.tensor(float("-inf"), device=coords.device, dtype=torch.float32)

    coord_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
    coord_sums.scatter_add_(
        0,
        labels[:, None].expand(-1, d_coord),
        active_coords * active_valid.to(torch.float32)[:, None],
    )
    coord_means = coord_sums / counts.to(torch.float32).clamp_min(1).unsqueeze(1)
    min_r = torch.full((n_labels + 1,), inf32, device=coords.device, dtype=torch.float32)
    max_r = torch.full((n_labels + 1,), neg_inf32, device=coords.device, dtype=torch.float32)
    min_r.scatter_reduce_(
        0,
        labels,
        torch.where(active_valid, active_r, torch.full_like(active_r, float("inf"))),
        reduce="amin",
        include_self=True,
    )
    max_r.scatter_reduce_(
        0,
        labels,
        torch.where(active_valid, active_r, torch.full_like(active_r, float("-inf"))),
        reduce="amax",
        include_self=True,
    )
    min_hit = active_valid & ((active_r - min_r[labels]).abs() <= 1e-6)
    max_hit = active_valid & ((active_r - max_r[labels]).abs() <= 1e-6)
    min_sums = torch.zeros_like(coord_sums)
    max_sums = torch.zeros_like(coord_sums)
    min_sums.scatter_add_(
        0,
        labels[:, None].expand(-1, d_coord),
        active_coords * min_hit.to(torch.float32)[:, None],
    )
    max_sums.scatter_add_(
        0,
        labels[:, None].expand(-1, d_coord),
        active_coords * max_hit.to(torch.float32)[:, None],
    )
    min_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
    max_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
    min_counts.scatter_add_(0, labels, min_hit.to(torch.float32))
    max_counts.scatter_add_(0, labels, max_hit.to(torch.float32))
    start_coords = min_sums / min_counts.clamp_min(1).unsqueeze(1)
    end_coords = max_sums / max_counts.clamp_min(1).unsqueeze(1)

    layer_keys = labels * geo_layer_span + layer_pad[active_idx].long().clamp(0, geo_layer_span - 1)
    presence_flat = torch.zeros((n_labels + 1) * geo_layer_span, device=predicted.device, dtype=torch.float32)
    presence_flat.scatter_add_(0, layer_keys, active_valid.to(torch.float32))
    geo_presence = presence_flat.reshape(n_labels + 1, geo_layer_span).clamp_max(1.0)
    if _CODEX_TARGET_BY_CLF:
        cluster_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=clf_pad.dtype)
        clf_active_for_rank = clf_pad[active_idx]
        cluster_clf_sum.scatter_add_(
            0,
            labels,
            torch.where(active_valid, clf_active_for_rank, torch.zeros_like(clf_active_for_rank)),
        )
        cluster_clf_for_rank = cluster_clf_sum / counts.to(cluster_clf_sum.dtype).clamp_min(1)

    if _CODEX_DO_GEO_MERGE:
        geo_small_rows = torch.nonzero_static(
            (counts[:n_labels] >= int(_CODEX_GEO_MIN_SIZE))
            & (counts[:n_labels] <= int(_CODEX_GEO_MAX_SIZE))
            & ((max_r[:n_labels] - min_r[:n_labels]).abs() > 1e-6),
            size=geo_small_cap,
            fill_value=n_labels,
        ).squeeze(1)
        geo_target_mask = (counts[:n_labels] >= 1) & (counts[:n_labels] < 14)
        if _CODEX_TARGET_BY_CLF:
            geo_target_scores = cluster_clf_for_rank[:n_labels].masked_fill(~geo_target_mask, float("-inf"))
            geo_target_vals, geo_target_rows = geo_target_scores.topk(geo_target_cap, largest=True)
        else:
            geo_target_vals = torch.zeros((geo_target_cap,), device=predicted.device, dtype=cluster_clf_for_rank.dtype)
            geo_target_rows = torch.nonzero_static(
                geo_target_mask,
                size=geo_target_cap,
                fill_value=n_labels,
            ).squeeze(1)
        geo_small_valid = geo_small_rows < n_labels
        geo_target_valid = (geo_target_rows < n_labels) & torch.isfinite(geo_target_vals)
        if _CODEX_GROUPED_GEO_MERGE and _CODEX_GEO_SAME_SUBEVENT_ONLY:
            q_same = max(1, int(_CODEX_SAME_QUERY_Q))
            group_count = max(1, (n_labels + q_same - 1) // q_same)
            group_small_cap = int(_CODEX_GEO_GROUP_SMALL_CAP)
            group_target_cap = int(_CODEX_GEO_GROUP_TARGET_CAP)
            small_group = torch.div(geo_small_rows.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
            target_group = torch.div(geo_target_rows.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
            small_rows_pad = torch.cat(
                [
                    geo_small_rows,
                    torch.full((1,), n_labels, device=predicted.device, dtype=torch.long),
                ],
                dim=0,
            )
            target_rows_pad = torch.cat(
                [
                    geo_target_rows,
                    torch.full((1,), n_labels, device=predicted.device, dtype=torch.long),
                ],
                dim=0,
            )
            geo_vals = torch.full((geo_small_cap,), float("-inf"), device=predicted.device, dtype=torch.float32)
            geo_cols = torch.full((geo_small_cap,), n_labels, device=predicted.device, dtype=torch.long)
            vals_pad = torch.cat([geo_vals, torch.full((1,), float("-inf"), device=predicted.device, dtype=torch.float32)])
            cols_pad = torch.cat([geo_cols, torch.full((1,), n_labels, device=predicted.device, dtype=torch.long)])
            for group_id in range(group_count):
                group_small_pos = torch.nonzero_static(
                    geo_small_valid & (small_group == group_id),
                    size=group_small_cap,
                    fill_value=geo_small_cap,
                ).squeeze(1)
                group_target_pos = torch.nonzero_static(
                    geo_target_valid & (target_group == group_id),
                    size=group_target_cap,
                    fill_value=geo_target_cap,
                ).squeeze(1)
                group_small_valid = group_small_pos < geo_small_cap
                group_target_valid = group_target_pos < geo_target_cap
                small_pos_safe = group_small_pos.clamp_max(geo_small_cap)
                target_pos_safe = group_target_pos.clamp_max(geo_target_cap)
                small_rows_g = small_rows_pad[small_pos_safe]
                target_rows_g = target_rows_pad[target_pos_safe]
                seed0 = start_coords[small_rows_g]
                seed1 = end_coords[small_rows_g]
                r0 = seed0[:, 2]
                r1g = seed1[:, 2]
                z0 = seed0[:, 4]
                z1g = seed1[:, 4]
                p0 = seed0[:, 3]
                p1g = seed1[:, 3]
                dr = r1g - r0
                denom = torch.where(dr >= 0, dr.clamp_min(1e-6), dr.clamp_max(-1e-6))
                target_coords = coord_means[target_rows_g]
                rc = target_coords[:, 2][None, :]
                zc = target_coords[:, 4][None, :]
                pc = target_coords[:, 3][None, :]
                t = (rc - r0[:, None]) / denom[:, None]
                z_pred = z0[:, None] + (z1g - z0)[:, None] * t
                dphi01 = _wrap_normalized_phi_diff_torch(p1g - p0)
                dphi0c = _wrap_normalized_phi_diff_torch(pc - p0[:, None])
                phi_res = _wrap_normalized_phi_diff_torch(dphi0c - dphi01[:, None] * t).abs()
                z_res = (zc - z_pred).abs()
                geo_score = -(z_res / float(_CODEX_GEO_Z_MAX) + phi_res / float(_CODEX_GEO_PHI_MAX))
                geo_bad = (z_res > float(_CODEX_GEO_Z_MAX)) | (phi_res > float(_CODEX_GEO_PHI_MAX))
                geo_bad |= ~(group_small_valid[:, None] & group_target_valid[None, :])
                geo_bad |= small_rows_g[:, None] == target_rows_g[None, :]
                geo_row_counts = counts[small_rows_g][:, None]
                geo_target_counts = counts[target_rows_g][None, :]
                geo_bad |= geo_row_counts + geo_target_counts > 14
                geo_acyclic = (geo_target_counts > geo_row_counts) | (
                    (geo_target_counts == geo_row_counts) & (target_rows_g[None, :] < small_rows_g[:, None])
                )
                geo_bad |= ~geo_acyclic
                geo_overlap = geo_presence[small_rows_g] @ geo_presence[target_rows_g].t()
                geo_bad |= geo_overlap > int(_CODEX_GEO_MAX_LAYER_OVERLAP)
                geo_score = geo_score.masked_fill(geo_bad, float("-inf"))
                vals_g, col_pos_g = geo_score.max(dim=1)
                cols_g = target_rows_g[col_pos_g]
                keep_g = group_small_valid & torch.isfinite(vals_g)
                old_vals_g = vals_pad[small_pos_safe]
                old_cols_g = cols_pad[small_pos_safe]
                vals_pad[small_pos_safe] = torch.where(keep_g, vals_g, old_vals_g)
                cols_pad[small_pos_safe] = torch.where(keep_g, cols_g, old_cols_g)
            geo_vals = vals_pad[:geo_small_cap]
            geo_cols = cols_pad[:geo_small_cap]
        else:
            seed0 = start_coords[geo_small_rows]
            seed1 = end_coords[geo_small_rows]
            r0 = seed0[:, 2]
            r1g = seed1[:, 2]
            z0 = seed0[:, 4]
            z1g = seed1[:, 4]
            p0 = seed0[:, 3]
            p1g = seed1[:, 3]
            dr = r1g - r0
            denom = torch.where(dr >= 0, dr.clamp_min(1e-6), dr.clamp_max(-1e-6))
            target_coords = coord_means[geo_target_rows]
            rc = target_coords[:, 2][None, :]
            zc = target_coords[:, 4][None, :]
            pc = target_coords[:, 3][None, :]
            t = (rc - r0[:, None]) / denom[:, None]
            z_pred = z0[:, None] + (z1g - z0)[:, None] * t
            dphi01 = _wrap_normalized_phi_diff_torch(p1g - p0)
            dphi0c = _wrap_normalized_phi_diff_torch(pc - p0[:, None])
            phi_res = _wrap_normalized_phi_diff_torch(dphi0c - dphi01[:, None] * t).abs()
            z_res = (zc - z_pred).abs()
            geo_score = -(z_res / float(_CODEX_GEO_Z_MAX) + phi_res / float(_CODEX_GEO_PHI_MAX))
            geo_bad = (z_res > float(_CODEX_GEO_Z_MAX)) | (phi_res > float(_CODEX_GEO_PHI_MAX))
            geo_bad |= ~(geo_small_valid[:, None] & geo_target_valid[None, :])
            geo_bad |= geo_small_rows[:, None] == geo_target_rows[None, :]
            geo_row_counts = counts[geo_small_rows][:, None]
            geo_target_counts = counts[geo_target_rows][None, :]
            geo_bad |= geo_row_counts + geo_target_counts > 14
            geo_acyclic = (geo_target_counts > geo_row_counts) | (
                (geo_target_counts == geo_row_counts) & (geo_target_rows[None, :] < geo_small_rows[:, None])
            )
            geo_bad |= ~geo_acyclic
            if _CODEX_GEO_SAME_SUBEVENT_ONLY:
                q_same = max(1, int(_CODEX_SAME_QUERY_Q))
                geo_small_group = torch.div(geo_small_rows.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
                geo_target_group = torch.div(geo_target_rows.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
                geo_bad |= geo_small_group[:, None] != geo_target_group[None, :]
            geo_overlap = geo_presence[geo_small_rows] @ geo_presence[geo_target_rows].t()
            geo_bad |= geo_overlap > int(_CODEX_GEO_MAX_LAYER_OVERLAP)
            geo_score = geo_score.masked_fill(geo_bad, float("-inf"))
            geo_vals, geo_col_pos = geo_score.max(dim=1)
            geo_cols = geo_target_rows[geo_col_pos]
        geo_keep = geo_small_valid & torch.isfinite(geo_vals)
        geo_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        geo_remap[geo_small_rows] = torch.where(geo_keep, geo_cols, geo_remap[geo_small_rows])
        for _ in range(4):
            geo_remap = geo_remap[geo_remap]
        geo_merged_sizes = torch.zeros(n_labels + 1, device=predicted.device, dtype=counts.dtype)
        geo_merged_sizes.scatter_add_(0, geo_remap, counts)
        base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        geo_remap = torch.where(geo_merged_sizes[geo_remap] > 14, base_remap, geo_remap)
        for _ in range(2):
            geo_remap = geo_remap[geo_remap]
        labels = geo_remap[labels].long().clamp(0, n_labels)
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = labels
        out = out_pad[:n_total]
        counts_before_geo = counts
        counts_after_geo = torch.zeros_like(counts)
        counts_after_geo.scatter_add_(0, geo_remap, counts)
        sums_after_geo = torch.zeros_like(sums_full)
        sums_after_geo.scatter_add_(0, geo_remap[:, None].expand(-1, feat_dim), sums_full)
        counts = counts_after_geo
        sums_full = sums_after_geo

        if _CODEX_DO_ENDPOINT_MERGE:
            if _CODEX_CLUSTER_GEOM_UPDATE:
                old_counts_for_geom = counts_before_geo
                coord_sums_after = torch.zeros_like(coord_sums)
                coord_sums_after.scatter_add_(0, geo_remap[:, None].expand(-1, d_coord), coord_sums)
                min_r_after = torch.full_like(min_r, float("inf"))
                max_r_after = torch.full_like(max_r, float("-inf"))
                min_r_after.scatter_reduce_(
                    0,
                    geo_remap,
                    torch.where(old_counts_for_geom > 0, min_r, torch.full_like(min_r, float("inf"))),
                    reduce="amin",
                    include_self=True,
                )
                max_r_after.scatter_reduce_(
                    0,
                    geo_remap,
                    torch.where(old_counts_for_geom > 0, max_r, torch.full_like(max_r, float("-inf"))),
                    reduce="amax",
                    include_self=True,
                )
                source_min = old_counts_for_geom > 0
                source_max = source_min
                source_min = source_min & ((min_r - min_r_after[geo_remap]).abs() <= 1e-6)
                source_max = source_max & ((max_r - max_r_after[geo_remap]).abs() <= 1e-6)
                min_sums_after = torch.zeros_like(min_sums)
                max_sums_after = torch.zeros_like(max_sums)
                min_sums_after.scatter_add_(
                    0,
                    geo_remap[:, None].expand(-1, d_coord),
                    min_sums * source_min.to(torch.float32)[:, None],
                )
                max_sums_after.scatter_add_(
                    0,
                    geo_remap[:, None].expand(-1, d_coord),
                    max_sums * source_max.to(torch.float32)[:, None],
                )
                min_counts_after = torch.zeros_like(min_counts)
                max_counts_after = torch.zeros_like(max_counts)
                min_counts_after.scatter_add_(0, geo_remap, min_counts * source_min.to(torch.float32))
                max_counts_after.scatter_add_(0, geo_remap, max_counts * source_max.to(torch.float32))
                start_coords = min_sums_after / min_counts_after.clamp_min(1).unsqueeze(1)
                end_coords = max_sums_after / max_counts_after.clamp_min(1).unsqueeze(1)
                presence_after = torch.zeros_like(geo_presence)
                presence_after.scatter_add_(0, geo_remap[:, None].expand(-1, geo_layer_span), geo_presence)
                geo_presence = presence_after.clamp_max(1.0)
                coord_sums = coord_sums_after
                min_r = min_r_after
                max_r = max_r_after
                min_sums = min_sums_after
                max_sums = max_sums_after
                min_counts = min_counts_after
                max_counts = max_counts_after
                if _CODEX_TARGET_BY_CLF:
                    old_clf_sum = cluster_clf_for_rank * old_counts_for_geom.to(cluster_clf_for_rank.dtype)
                    cluster_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=clf_pad.dtype)
                    cluster_clf_sum.scatter_add_(0, geo_remap, old_clf_sum)
                    cluster_clf_for_rank = cluster_clf_sum / counts.to(cluster_clf_sum.dtype).clamp_min(1)
            else:
                active_coords = coords_pad[active_idx].float()
                active_r = active_coords[:, 2]
                coord_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
                coord_sums.scatter_add_(
                    0,
                    labels[:, None].expand(-1, d_coord),
                    active_coords * active_valid.to(torch.float32)[:, None],
                )
                min_r = torch.full((n_labels + 1,), inf32, device=coords.device, dtype=torch.float32)
                max_r = torch.full((n_labels + 1,), neg_inf32, device=coords.device, dtype=torch.float32)
                min_r.scatter_reduce_(
                    0,
                    labels,
                    torch.where(active_valid, active_r, torch.full_like(active_r, float("inf"))),
                    reduce="amin",
                    include_self=True,
                )
                max_r.scatter_reduce_(
                    0,
                    labels,
                    torch.where(active_valid, active_r, torch.full_like(active_r, float("-inf"))),
                    reduce="amax",
                    include_self=True,
                )
                min_hit = active_valid & ((active_r - min_r[labels]).abs() <= 1e-6)
                max_hit = active_valid & ((active_r - max_r[labels]).abs() <= 1e-6)
                min_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
                max_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
                min_sums.scatter_add_(
                    0,
                    labels[:, None].expand(-1, d_coord),
                    active_coords * min_hit.to(torch.float32)[:, None],
                )
                max_sums.scatter_add_(
                    0,
                    labels[:, None].expand(-1, d_coord),
                    active_coords * max_hit.to(torch.float32)[:, None],
                )
                min_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
                max_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
                min_counts.scatter_add_(0, labels, min_hit.to(torch.float32))
                max_counts.scatter_add_(0, labels, max_hit.to(torch.float32))
                start_coords = min_sums / min_counts.clamp_min(1).unsqueeze(1)
                end_coords = max_sums / max_counts.clamp_min(1).unsqueeze(1)
                layer_keys = labels * geo_layer_span + layer_pad[active_idx].long().clamp(0, geo_layer_span - 1)
                presence_flat = torch.zeros((n_labels + 1) * geo_layer_span, device=predicted.device, dtype=torch.float32)
                presence_flat.scatter_add_(0, layer_keys, active_valid.to(torch.float32))
                geo_presence = presence_flat.reshape(n_labels + 1, geo_layer_span).clamp_max(1.0)
                if _CODEX_TARGET_BY_CLF:
                    cluster_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=clf_pad.dtype)
                    clf_active_for_rank = clf_pad[active_idx]
                    cluster_clf_sum.scatter_add_(
                        0,
                        labels,
                        torch.where(active_valid, clf_active_for_rank, torch.zeros_like(clf_active_for_rank)),
                    )
                    cluster_clf_for_rank = cluster_clf_sum / counts.to(cluster_clf_sum.dtype).clamp_min(1)

    if _CODEX_DO_ENDPOINT_MERGE:
        endpoint_rows = torch.nonzero_static(
            (counts[:n_labels] >= int(_CODEX_ENDPOINT_MIN_SIZE))
            & (counts[:n_labels] <= int(_CODEX_ENDPOINT_MAX_SIZE))
            & ((max_r[:n_labels] - min_r[:n_labels]).abs() > 1e-6),
            size=geo_endpoint_cap,
            fill_value=n_labels,
        ).squeeze(1)
        endpoint_target_mask = (counts[:n_labels] >= 1) & (counts[:n_labels] < 14)
        if _CODEX_TARGET_BY_CLF:
            endpoint_target_scores = cluster_clf_for_rank[:n_labels].masked_fill(
                ~endpoint_target_mask,
                float("-inf"),
            )
            endpoint_target_vals, endpoint_targets = endpoint_target_scores.topk(geo_target_cap, largest=True)
        else:
            endpoint_target_vals = torch.zeros((geo_target_cap,), device=predicted.device, dtype=cluster_clf_for_rank.dtype)
            endpoint_targets = torch.nonzero_static(
                endpoint_target_mask,
                size=geo_target_cap,
                fill_value=n_labels,
            ).squeeze(1)
        endpoint_valid = endpoint_rows < n_labels
        endpoint_target_valid = (endpoint_targets < n_labels) & torch.isfinite(endpoint_target_vals)
        row_start = start_coords[endpoint_rows]
        row_end = end_coords[endpoint_rows]
        tgt_start = start_coords[endpoint_targets]
        tgt_end = end_coords[endpoint_targets]

        er0 = row_start[:, 2]
        er1 = row_end[:, 2]
        ez0 = row_start[:, 4]
        ez1 = row_end[:, 4]
        ep0 = row_start[:, 3]
        ep1 = row_end[:, 3]
        etr = tgt_start[:, 2][None, :]
        etz = tgt_start[:, 4][None, :]
        etp = tgt_start[:, 3][None, :]
        edr = er1 - er0
        edenom = torch.where(edr >= 0, edr.clamp_min(1e-6), edr.clamp_max(-1e-6))
        et = (etr - er0[:, None]) / edenom[:, None]
        ez_pred = ez0[:, None] + (ez1 - ez0)[:, None] * et
        edphi01 = _wrap_normalized_phi_diff_torch(ep1 - ep0)
        edphi0t = _wrap_normalized_phi_diff_torch(etp - ep0[:, None])
        ephi_hi = _wrap_normalized_phi_diff_torch(edphi0t - edphi01[:, None] * et).abs()
        ez_hi = (etz - ez_pred).abs()
        hi_order = tgt_start[:, 2][None, :] >= (row_end[:, 2][:, None] - float(_CODEX_ENDPOINT_ORDER_TOL))
        hi_bad = (~hi_order) | (ez_hi > float(_CODEX_ENDPOINT_Z_MAX)) | (ephi_hi > float(_CODEX_ENDPOINT_PHI_MAX))
        hi_score = ez_hi / float(_CODEX_ENDPOINT_Z_MAX) + ephi_hi / float(_CODEX_ENDPOINT_PHI_MAX)

        er0b = row_end[:, 2]
        er1b = row_start[:, 2]
        ez0b = row_end[:, 4]
        ez1b = row_start[:, 4]
        ep0b = row_end[:, 3]
        ep1b = row_start[:, 3]
        etrb = tgt_end[:, 2][None, :]
        etzb = tgt_end[:, 4][None, :]
        etpb = tgt_end[:, 3][None, :]
        edrb = er1b - er0b
        edenomb = torch.where(edrb >= 0, edrb.clamp_min(1e-6), edrb.clamp_max(-1e-6))
        etb = (etrb - er0b[:, None]) / edenomb[:, None]
        ez_pred_b = ez0b[:, None] + (ez1b - ez0b)[:, None] * etb
        edphi01b = _wrap_normalized_phi_diff_torch(ep1b - ep0b)
        edphi0tb = _wrap_normalized_phi_diff_torch(etpb - ep0b[:, None])
        ephi_lo = _wrap_normalized_phi_diff_torch(edphi0tb - edphi01b[:, None] * etb).abs()
        ez_lo = (etzb - ez_pred_b).abs()
        lo_order = tgt_end[:, 2][None, :] <= (row_start[:, 2][:, None] + float(_CODEX_ENDPOINT_ORDER_TOL))
        lo_bad = (~lo_order) | (ez_lo > float(_CODEX_ENDPOINT_Z_MAX)) | (ephi_lo > float(_CODEX_ENDPOINT_PHI_MAX))
        lo_score = ez_lo / float(_CODEX_ENDPOINT_Z_MAX) + ephi_lo / float(_CODEX_ENDPOINT_PHI_MAX)
        endpoint_score = torch.minimum(
            hi_score.masked_fill(hi_bad, float("inf")),
            lo_score.masked_fill(lo_bad, float("inf")),
        )
        endpoint_bad = ~(endpoint_valid[:, None] & endpoint_target_valid[None, :])
        endpoint_bad |= endpoint_rows[:, None] == endpoint_targets[None, :]
        endpoint_row_counts = counts[endpoint_rows][:, None]
        endpoint_target_counts = counts[endpoint_targets][None, :]
        endpoint_bad |= endpoint_row_counts + endpoint_target_counts > 14
        endpoint_acyclic = (endpoint_target_counts > endpoint_row_counts) | (
            (endpoint_target_counts == endpoint_row_counts)
            & (endpoint_targets[None, :] < endpoint_rows[:, None])
        )
        endpoint_bad |= ~endpoint_acyclic
        if _CODEX_ENDPOINT_SAME_SUBEVENT_ONLY:
            q_same = max(1, int(_CODEX_SAME_QUERY_Q))
            endpoint_group = torch.div(endpoint_rows.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
            endpoint_target_group = torch.div(endpoint_targets.clamp_max(n_labels - 1), q_same, rounding_mode="floor")
            endpoint_bad |= endpoint_group[:, None] != endpoint_target_group[None, :]
        endpoint_overlap = geo_presence[endpoint_rows] @ geo_presence[endpoint_targets].t()
        endpoint_bad |= endpoint_overlap > int(_CODEX_ENDPOINT_MAX_LAYER_OVERLAP)
        endpoint_score = endpoint_score.masked_fill(endpoint_bad, float("inf"))
        endpoint_vals, endpoint_col_pos = endpoint_score.min(dim=1)
        endpoint_cols = endpoint_targets[endpoint_col_pos]
        endpoint_keep = endpoint_valid & torch.isfinite(endpoint_vals)
        endpoint_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        endpoint_remap[endpoint_rows] = torch.where(
            endpoint_keep,
            endpoint_cols,
            endpoint_remap[endpoint_rows],
        )
        for _ in range(4):
            endpoint_remap = endpoint_remap[endpoint_remap]
        endpoint_merged_sizes = torch.zeros(n_labels + 1, device=predicted.device, dtype=counts.dtype)
        endpoint_merged_sizes.scatter_add_(0, endpoint_remap, counts)
        base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        endpoint_remap = torch.where(endpoint_merged_sizes[endpoint_remap] > 14, base_remap, endpoint_remap)
        for _ in range(2):
            endpoint_remap = endpoint_remap[endpoint_remap]
        labels = endpoint_remap[labels].long().clamp(0, n_labels)
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = labels
        out = out_pad[:n_total]
        counts_after_endpoint = torch.zeros_like(counts)
        counts_after_endpoint.scatter_add_(0, endpoint_remap, counts)
        sums_after_endpoint = torch.zeros_like(sums_full)
        sums_after_endpoint.scatter_add_(0, endpoint_remap[:, None].expand(-1, feat_dim), sums_full)
        counts = counts_after_endpoint
        sums_full = sums_after_endpoint

    if _CODEX_DO_SINGLETON_GEO_MERGE:
        active_coords = coords_pad[active_idx].float()
        active_r = active_coords[:, 2]
        coord_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
        coord_sums.scatter_add_(
            0,
            labels[:, None].expand(-1, d_coord),
            active_coords * active_valid.to(torch.float32)[:, None],
        )
        coord_means = coord_sums / counts.to(torch.float32).clamp_min(1).unsqueeze(1)
        min_r = torch.full((n_labels + 1,), inf32, device=coords.device, dtype=torch.float32)
        max_r = torch.full((n_labels + 1,), neg_inf32, device=coords.device, dtype=torch.float32)
        min_r.scatter_reduce_(
            0,
            labels,
            torch.where(active_valid, active_r, torch.full_like(active_r, float("inf"))),
            reduce="amin",
            include_self=True,
        )
        max_r.scatter_reduce_(
            0,
            labels,
            torch.where(active_valid, active_r, torch.full_like(active_r, float("-inf"))),
            reduce="amax",
            include_self=True,
        )
        min_hit = active_valid & ((active_r - min_r[labels]).abs() <= 1e-6)
        max_hit = active_valid & ((active_r - max_r[labels]).abs() <= 1e-6)
        min_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
        max_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
        min_sums.scatter_add_(
            0,
            labels[:, None].expand(-1, d_coord),
            active_coords * min_hit.to(torch.float32)[:, None],
        )
        max_sums.scatter_add_(
            0,
            labels[:, None].expand(-1, d_coord),
            active_coords * max_hit.to(torch.float32)[:, None],
        )
        min_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
        max_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
        min_counts.scatter_add_(0, labels, min_hit.to(torch.float32))
        max_counts.scatter_add_(0, labels, max_hit.to(torch.float32))
        start_coords = min_sums / min_counts.clamp_min(1).unsqueeze(1)
        end_coords = max_sums / max_counts.clamp_min(1).unsqueeze(1)
        layer_keys = labels * geo_layer_span + layer_pad[active_idx].long().clamp(0, geo_layer_span - 1)
        presence_flat = torch.zeros((n_labels + 1) * geo_layer_span, device=predicted.device, dtype=torch.float32)
        presence_flat.scatter_add_(0, layer_keys, active_valid.to(torch.float32))
        geo_presence = presence_flat.reshape(n_labels + 1, geo_layer_span).clamp_max(1.0)

        singleton_cap = int(_CODEX_SINGLETON_GEO_CAP)
        singleton_target_cap = int(_CODEX_SINGLETON_GEO_TARGET_CAP)
        singleton_rows = torch.nonzero_static(
            counts[:n_labels] == 1,
            size=singleton_cap,
            fill_value=n_labels,
        ).squeeze(1)
        singleton_target_mask = (
            (counts[:n_labels] >= 2)
            & (counts[:n_labels] < 14)
            & ((max_r[:n_labels] - min_r[:n_labels]).abs() > 1e-6)
        )
        singleton_targets = torch.nonzero_static(
            singleton_target_mask,
            size=singleton_target_cap,
            fill_value=n_labels,
        ).squeeze(1)
        singleton_valid = singleton_rows < n_labels
        singleton_target_valid = singleton_targets < n_labels

        single_coords = coord_means[singleton_rows]
        target_start = start_coords[singleton_targets]
        target_end = end_coords[singleton_targets]
        sr = single_coords[:, 2]
        sz = single_coords[:, 4]
        sp = single_coords[:, 3]
        tr0 = target_start[:, 2]
        tr1 = target_end[:, 2]
        tz0 = target_start[:, 4]
        tz1 = target_end[:, 4]
        tp0 = target_start[:, 3]
        tp1 = target_end[:, 3]
        tdr = tr1 - tr0
        tdenom = torch.where(tdr >= 0, tdr.clamp_min(1e-6), tdr.clamp_max(-1e-6))
        st = (sr[:, None] - tr0[None, :]) / tdenom[None, :]
        z_pred = tz0[None, :] + (tz1 - tz0)[None, :] * st
        dphi01 = _wrap_normalized_phi_diff_torch(tp1 - tp0)
        dphi0s = _wrap_normalized_phi_diff_torch(sp[:, None] - tp0[None, :])
        phi_res = _wrap_normalized_phi_diff_torch(dphi0s - dphi01[None, :] * st).abs()
        z_res = (sz[:, None] - z_pred).abs()
        centroids_full = sums_full / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
        centroids_full = F.normalize(centroids_full, p=2, dim=1, eps=1e-12)
        sem_sim = centroids_full[singleton_rows].to(torch.float16) @ centroids_full[singleton_targets].to(torch.float16).t()
        singleton_score = z_res / float(_CODEX_SINGLETON_GEO_Z_MAX) + phi_res / float(_CODEX_SINGLETON_GEO_PHI_MAX)
        singleton_bad = ~(singleton_valid[:, None] & singleton_target_valid[None, :])
        singleton_bad |= singleton_rows[:, None] == singleton_targets[None, :]
        singleton_bad |= counts[singleton_rows][:, None] + counts[singleton_targets][None, :] > 14
        singleton_bad |= geo_presence[singleton_rows] @ geo_presence[singleton_targets].t() > 0
        singleton_bad |= z_res > float(_CODEX_SINGLETON_GEO_Z_MAX)
        singleton_bad |= phi_res > float(_CODEX_SINGLETON_GEO_PHI_MAX)
        singleton_bad |= sem_sim.float() < float(_CODEX_SINGLETON_GEO_MIN_SIM)
        singleton_bad |= st < float(_CODEX_SINGLETON_GEO_T_MIN)
        singleton_bad |= st > float(_CODEX_SINGLETON_GEO_T_MAX)
        singleton_score = singleton_score.masked_fill(singleton_bad, float("inf"))
        singleton_vals, singleton_col_pos = singleton_score.min(dim=1)
        singleton_cols = singleton_targets[singleton_col_pos]
        singleton_keep = singleton_valid & torch.isfinite(singleton_vals)
        singleton_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        singleton_remap[singleton_rows] = torch.where(
            singleton_keep,
            singleton_cols,
            singleton_remap[singleton_rows],
        )
        for _ in range(4):
            singleton_remap = singleton_remap[singleton_remap]
        singleton_merged_sizes = torch.zeros(n_labels + 1, device=predicted.device, dtype=counts.dtype)
        singleton_merged_sizes.scatter_add_(0, singleton_remap, counts)
        base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        singleton_remap = torch.where(singleton_merged_sizes[singleton_remap] > 14, base_remap, singleton_remap)
        for _ in range(2):
            singleton_remap = singleton_remap[singleton_remap]
        labels = singleton_remap[labels].long().clamp(0, n_labels)
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = labels
        out = out_pad[:n_total]
        counts_after_singleton = torch.zeros_like(counts)
        counts_after_singleton.scatter_add_(0, singleton_remap, counts)
        sums_after_singleton = torch.zeros_like(sums_full)
        sums_after_singleton.scatter_add_(0, singleton_remap[:, None].expand(-1, feat_dim), sums_full)
        counts = counts_after_singleton
        sums_full = sums_after_singleton

    if _CODEX_DO_SPLIT_OVERMERGED:
        split_cap = int(_CODEX_SPLIT_CAP)
        split_point_cap = max(2, int(_CODEX_SPLIT_MAX_SIZE))
        layer_shift_all = layer_pad[active_idx].long().clamp(0, layer_span - 1)
        split_keys = labels * layer_span + layer_shift_all
        split_presence_flat = torch.zeros((n_labels + 1) * layer_span, device=predicted.device, dtype=torch.float32)
        split_presence_flat.scatter_add_(0, split_keys, active_valid.to(torch.float32))
        split_presence = split_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0)
        split_unique_layers = split_presence.sum(dim=1).to(counts.dtype)
        split_dup = counts - split_unique_layers
        split_candidate = (
            (counts[:n_labels] >= int(_CODEX_SPLIT_MIN_SIZE))
            & (counts[:n_labels] <= int(_CODEX_SPLIT_MAX_SIZE))
            & (split_dup[:n_labels] >= int(_CODEX_SPLIT_MIN_DUPLICATE_LAYERS))
        )
        split_priority = torch.where(
            split_candidate,
            split_dup[:n_labels].to(torch.float32) * 1024.0 + counts[:n_labels].to(torch.float32),
            torch.full((n_labels,), float("-inf"), device=predicted.device, dtype=torch.float32),
        )
        split_vals, split_rows = split_priority.topk(split_cap, largest=True)
        split_valid = torch.isfinite(split_vals)
        free_rows = torch.nonzero_static(counts[:n_labels] == 0, size=split_cap, fill_value=n_labels).squeeze(1)
        free_valid = free_rows < n_labels

        active_arange = torch.arange(active_cap, device=predicted.device, dtype=torch.long)
        points_all_pad = torch.cat(
            [points_all, torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)],
            dim=0,
        )
        layer_shift_pad = torch.cat(
            [layer_shift_all, torch.zeros((1,), device=predicted.device, dtype=torch.long)],
            dim=0,
        )
        split_update = torch.full((active_cap + 1,), n_labels, device=predicted.device, dtype=torch.long)
        point_ids = torch.arange(split_point_cap, device=predicted.device, dtype=torch.long)
        for split_i in range(split_cap):
            row = split_rows[split_i]
            new_row = free_rows[split_i]
            hit_pos = torch.nonzero_static(
                active_valid & (labels == row),
                size=split_point_cap,
                fill_value=active_cap,
            ).squeeze(1)
            hit_valid = (hit_pos < active_cap) & split_valid[split_i] & free_valid[split_i]
            split_points = points_all_pad[hit_pos.clamp(0, active_cap)]
            split_layers = layer_shift_pad[hit_pos.clamp(0, active_cap)]
            split_pair_sim = (split_points.to(torch.float16) @ split_points.to(torch.float16).t()).float()
            pair_valid = hit_valid[:, None] & hit_valid[None, :] & (point_ids[:, None] != point_ids[None, :])
            split_pair_sim = split_pair_sim.masked_fill(~pair_valid, float("inf"))
            seed_flat = split_pair_sim.reshape(split_point_cap * split_point_cap).argmin()
            seed_a = torch.div(seed_flat, split_point_cap, rounding_mode="floor")
            seed_b = seed_flat.remainder(split_point_cap)
            seed_a_idx = seed_a.reshape(1, 1).expand(1, feat_dim)
            seed_b_idx = seed_b.reshape(1, 1).expand(1, feat_dim)
            cent0 = F.normalize(split_points.gather(0, seed_a_idx).squeeze(0), p=2, dim=0, eps=1e-12)
            cent1 = F.normalize(split_points.gather(0, seed_b_idx).squeeze(0), p=2, dim=0, eps=1e-12)
            assign1 = torch.zeros((split_point_cap,), device=predicted.device, dtype=torch.bool)
            for _ in range(max(1, int(_CODEX_SPLIT_ITERS))):
                sim0 = (split_points * cent0[None, :]).sum(dim=1)
                sim1 = (split_points * cent1[None, :]).sum(dim=1)
                assign1 = hit_valid & (sim1 > sim0)
                part0 = hit_valid & (~assign1)
                part1 = hit_valid & assign1
                n0f = part0.to(emb.dtype).sum().clamp_min(1)
                n1f = part1.to(emb.dtype).sum().clamp_min(1)
                cent0 = F.normalize((split_points * part0.to(emb.dtype)[:, None]).sum(dim=0) / n0f, p=2, dim=0, eps=1e-12)
                cent1 = F.normalize((split_points * part1.to(emb.dtype)[:, None]).sum(dim=0) / n1f, p=2, dim=0, eps=1e-12)

            part0 = hit_valid & (~assign1)
            part1 = hit_valid & assign1
            n0 = part0.sum()
            n1 = part1.sum()
            layer_onehot = F.one_hot(split_layers.clamp(0, layer_span - 1), num_classes=layer_span).to(torch.bool)
            uniq0 = (layer_onehot & part0[:, None]).any(dim=0).sum()
            uniq1 = (layer_onehot & part1[:, None]).any(dim=0).sum()
            dup0 = n0 - uniq0
            dup1 = n1 - uniq1
            old_count = hit_valid.to(emb.dtype).sum().clamp_min(1)
            old_cent = F.normalize((split_points * hit_valid.to(emb.dtype)[:, None]).sum(dim=0) / old_count, p=2, dim=0, eps=1e-12)
            old_score = ((split_points * old_cent[None, :]).sum(dim=1) * hit_valid.to(emb.dtype)).sum() / old_count
            new_score = (
                ((split_points * cent0[None, :]).sum(dim=1) * part0.to(emb.dtype)).sum()
                + ((split_points * cent1[None, :]).sum(dim=1) * part1.to(emb.dtype)).sum()
            ) / old_count
            split_keep = (
                (n0 >= int(_CODEX_SPLIT_MIN_PART_SIZE))
                & (n1 >= int(_CODEX_SPLIT_MIN_PART_SIZE))
                & ((new_score - old_score) >= float(_CODEX_SPLIT_MIN_IMPROVE))
                & ((cent0 * cent1).sum() <= float(_CODEX_SPLIT_MAX_CENTROID_SIM))
            )
            if int(_CODEX_SPLIT_MAX_PART_DUPLICATE_LAYERS) >= 0:
                split_keep = split_keep & (dup0 <= int(_CODEX_SPLIT_MAX_PART_DUPLICATE_LAYERS)) & (
                    dup1 <= int(_CODEX_SPLIT_MAX_PART_DUPLICATE_LAYERS)
                )
            move = torch.where(n1 <= n0, part1, part0) & split_keep
            split_update.scatter_(
                0,
                hit_pos.clamp(0, active_cap),
                torch.where(move, new_row.expand_as(hit_pos), torch.full_like(hit_pos, n_labels)),
            )
        split_update[active_cap] = n_labels
        new_labels = split_update[active_arange]
        labels = torch.where(new_labels < n_labels, new_labels, labels)
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = labels
        out = out_pad[:n_total]
        counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        counts.scatter_add_(0, labels, active_valid.to(torch.long))
        sums_full = torch.zeros((n_labels + 1, feat_dim), device=emb.device, dtype=emb.dtype)
        sums_full.scatter_add_(0, labels[:, None].expand(-1, feat_dim), points_all * active_valid.to(emb.dtype)[:, None])

    if _CODEX_DO_STEAL_POINT and (not _CODEX_STEAL_AFTER_PAD):
        steal_target_cap = int(_CODEX_STEAL_TARGET_CAP)
        steal_cand_cap = int(_CODEX_STEAL_CAND_CAP)
        steal_centroids = sums_full / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
        steal_centroids = F.normalize(steal_centroids, p=2, dim=1, eps=1e-12)
        source_sim_all = (points_all * steal_centroids[labels]).sum(dim=1)

        steal_target_mask = (
            (counts[:n_labels] >= int(_CODEX_STEAL_TARGET_MIN_SIZE))
            & (counts[:n_labels] <= int(_CODEX_STEAL_TARGET_MAX_SIZE))
        )
        if _CODEX_STEAL_TARGET_BY_CLF:
            steal_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=clf_pad.dtype)
            steal_clf_active = clf_pad[active_idx]
            steal_clf_sum.scatter_add_(
                0,
                labels,
                torch.where(active_valid, steal_clf_active, torch.zeros_like(steal_clf_active)),
            )
            steal_cluster_clf = steal_clf_sum / counts.to(steal_clf_sum.dtype).clamp_min(1)
            steal_target_scores = steal_cluster_clf[:n_labels].masked_fill(~steal_target_mask, float("-inf"))
            steal_target_vals, steal_targets = steal_target_scores.topk(steal_target_cap, largest=True)
            steal_target_valid = torch.isfinite(steal_target_vals)
        else:
            steal_targets = torch.nonzero_static(
                steal_target_mask,
                size=steal_target_cap,
                fill_value=n_labels,
            ).squeeze(1)
            steal_target_valid = steal_targets < n_labels

        layer_active = layer_pad[active_idx].long().clamp(0, layer_span - 1)
        source_sizes = counts[labels]
        steal_cand_mask = (
            active_valid
            & (source_sizes >= int(_CODEX_STEAL_SOURCE_MIN_SIZE))
            & (source_sizes <= int(_CODEX_STEAL_SOURCE_MAX_SIZE))
        )
        if int(_CODEX_STEAL_CAND_ACTIVE_OFFSET) >= 0:
            steal_cand_pos = (
                torch.arange(steal_cand_cap, device=predicted.device, dtype=torch.long)
                + int(_CODEX_STEAL_CAND_ACTIVE_OFFSET)
            ).clamp_max(active_cap)
            steal_cand_valid = (steal_cand_pos < active_cap) & steal_cand_mask[steal_cand_pos.clamp_max(active_cap - 1)]
        elif int(_CODEX_STEAL_CAND_RANK_OFFSET) > 0:
            cand_rank = steal_cand_mask.to(torch.long).cumsum(0) - 1
            cand_window = (
                steal_cand_mask
                & (cand_rank >= int(_CODEX_STEAL_CAND_RANK_OFFSET))
                & (cand_rank < int(_CODEX_STEAL_CAND_RANK_OFFSET) + int(steal_cand_cap))
            )
            steal_cand_pos = torch.nonzero_static(
                cand_window,
                size=steal_cand_cap,
                fill_value=active_cap,
            ).squeeze(1)
            steal_cand_valid = steal_cand_pos < active_cap
        elif _CODEX_STEAL_CAND_STRIDED:
            cand_cum = steal_cand_mask.to(torch.long).cumsum(0)
            num_cands = cand_cum[-1].clamp_min(1)
            cand_arange = torch.arange(steal_cand_cap, device=predicted.device, dtype=torch.long)
            cand_ranks = ((cand_arange * num_cands) // int(steal_cand_cap) + 1).clamp_max(num_cands)
            steal_cand_pos = torch.searchsorted(cand_cum, cand_ranks).clamp_max(active_cap - 1)
            steal_cand_valid = cand_arange < cand_cum[-1]
        elif _CODEX_STEAL_CAND_BY_LAYER_LOW_SOURCE:
            per_layer = max(1, int(_CODEX_STEAL_CAND_PER_LAYER))
            cand_pos_chunks = []
            cand_valid_chunks = []
            for layer_i in range(layer_span):
                steal_cand_scores = torch.where(
                    steal_cand_mask & (layer_active == layer_i),
                    -source_sim_all.float(),
                    torch.full((active_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
                )
                steal_cand_vals_i, steal_cand_pos_i = steal_cand_scores.topk(per_layer, largest=True)
                cand_pos_chunks.append(steal_cand_pos_i)
                cand_valid_chunks.append(torch.isfinite(steal_cand_vals_i))
            steal_cand_pos = torch.cat(cand_pos_chunks, dim=0)
            steal_cand_valid = torch.cat(cand_valid_chunks, dim=0)
            steal_cand_cap = int(steal_cand_pos.shape[0])
        elif _CODEX_STEAL_CAND_BY_LOW_SOURCE_SIM:
            steal_cand_scores = torch.where(
                steal_cand_mask,
                -source_sim_all.float(),
                torch.full((active_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
            )
            steal_cand_vals, steal_cand_pos = steal_cand_scores.topk(steal_cand_cap, largest=True)
            steal_cand_valid = torch.isfinite(steal_cand_vals)
        elif _CODEX_STEAL_CAND_BY_CLF:
            steal_cand_clf = clf_pad[active_idx].float()
            steal_cand_scores = torch.where(
                steal_cand_mask,
                steal_cand_clf,
                torch.full((active_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
            )
            steal_cand_vals, steal_cand_pos = steal_cand_scores.topk(steal_cand_cap, largest=True)
            steal_cand_valid = torch.isfinite(steal_cand_vals)
        else:
            steal_cand_pos = torch.nonzero_static(
                steal_cand_mask,
                size=steal_cand_cap,
                fill_value=active_cap,
            ).squeeze(1)
            steal_cand_valid = steal_cand_pos < active_cap

        points_active_pad = torch.cat(
            [points_all, torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)],
            dim=0,
        )
        labels_active_pad = torch.cat(
            [labels, torch.full((1,), n_labels, device=predicted.device, dtype=torch.long)],
            dim=0,
        )
        layer_active_pad = torch.cat(
            [layer_active, torch.zeros((1,), device=predicted.device, dtype=torch.long)],
            dim=0,
        )
        coords_active_pad = torch.cat(
            [active_coords, torch.zeros((1, d_coord), device=coords.device, dtype=torch.float32)],
            dim=0,
        )
        source_sim_pad = torch.cat(
            [
                source_sim_all,
                torch.full((1,), float("inf"), device=emb.device, dtype=source_sim_all.dtype),
            ],
            dim=0,
        )

        steal_target_centroids = steal_centroids[steal_targets]
        steal_cand_points = points_active_pad[steal_cand_pos]
        steal_sim = steal_target_centroids.to(torch.float16) @ steal_cand_points.to(torch.float16).t()

        if _CODEX_STEAL_CHECK_LAYER:
            steal_layer_keys = labels * layer_span + layer_active
            steal_presence_flat = torch.zeros((n_labels + 1) * layer_span, device=predicted.device, dtype=torch.float32)
            steal_presence_flat.scatter_add_(0, steal_layer_keys, active_valid.to(torch.float32))
            steal_presence = steal_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0)
            steal_cand_layers = layer_active_pad[steal_cand_pos]
            steal_forbidden = steal_presence[steal_targets][:, steal_cand_layers] > 0
        else:
            steal_forbidden = torch.zeros_like(steal_sim, dtype=torch.bool)

        if _CODEX_STEAL_USE_GEOM:
            steal_coord_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
            steal_coord_sums.scatter_add_(
                0,
                labels[:, None].expand(-1, d_coord),
                active_coords * active_valid.to(torch.float32)[:, None],
            )
            steal_min_r = torch.full((n_labels + 1,), inf32, device=coords.device, dtype=torch.float32)
            steal_max_r = torch.full((n_labels + 1,), neg_inf32, device=coords.device, dtype=torch.float32)
            steal_min_r.scatter_reduce_(
                0,
                labels,
                torch.where(active_valid, active_r, torch.full_like(active_r, float("inf"))),
                reduce="amin",
                include_self=True,
            )
            steal_max_r.scatter_reduce_(
                0,
                labels,
                torch.where(active_valid, active_r, torch.full_like(active_r, float("-inf"))),
                reduce="amax",
                include_self=True,
            )
            steal_min_hit = active_valid & ((active_r - steal_min_r[labels]).abs() <= 1e-6)
            steal_max_hit = active_valid & ((active_r - steal_max_r[labels]).abs() <= 1e-6)
            steal_min_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
            steal_max_sums = torch.zeros((n_labels + 1, d_coord), device=coords.device, dtype=torch.float32)
            steal_min_sums.scatter_add_(
                0,
                labels[:, None].expand(-1, d_coord),
                active_coords * steal_min_hit.to(torch.float32)[:, None],
            )
            steal_max_sums.scatter_add_(
                0,
                labels[:, None].expand(-1, d_coord),
                active_coords * steal_max_hit.to(torch.float32)[:, None],
            )
            steal_min_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
            steal_max_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
            steal_min_counts.scatter_add_(0, labels, steal_min_hit.to(torch.float32))
            steal_max_counts.scatter_add_(0, labels, steal_max_hit.to(torch.float32))
            steal_start = steal_min_sums / steal_min_counts.clamp_min(1).unsqueeze(1)
            steal_end = steal_max_sums / steal_max_counts.clamp_min(1).unsqueeze(1)

            steal_target_start = steal_start[steal_targets]
            steal_target_end = steal_end[steal_targets]
            steal_cand_coords = coords_active_pad[steal_cand_pos]
            sr = steal_cand_coords[:, 2]
            sz = steal_cand_coords[:, 4]
            sp = steal_cand_coords[:, 3]
            tr0 = steal_target_start[:, 2]
            tr1 = steal_target_end[:, 2]
            tz0 = steal_target_start[:, 4]
            tz1 = steal_target_end[:, 4]
            tp0 = steal_target_start[:, 3]
            tp1 = steal_target_end[:, 3]
            tdr = tr1 - tr0
            tdenom = torch.where(tdr >= 0, tdr.clamp_min(1e-6), tdr.clamp_max(-1e-6))
            st = (sr[None, :] - tr0[:, None]) / tdenom[:, None]
            z_pred = tz0[:, None] + (tz1 - tz0)[:, None] * st
            dphi01 = _wrap_normalized_phi_diff_torch(tp1 - tp0)
            dphi0s = _wrap_normalized_phi_diff_torch(sp[None, :] - tp0[:, None])
            steal_phi_res = _wrap_normalized_phi_diff_torch(dphi0s - dphi01[:, None] * st).abs()
            steal_z_res = (sz[None, :] - z_pred).abs()
            steal_geom_bad = (steal_z_res > float(_CODEX_STEAL_Z_MAX)) | (
                steal_phi_res > float(_CODEX_STEAL_PHI_MAX)
            )
            steal_geom_bad |= st < float(_CODEX_STEAL_T_MIN)
            steal_geom_bad |= st > float(_CODEX_STEAL_T_MAX)
        else:
            steal_geom_bad = torch.zeros_like(steal_sim, dtype=torch.bool)

        steal_cand_labels = labels_active_pad[steal_cand_pos]
        steal_source_sim = source_sim_pad[steal_cand_pos]
        steal_bad = ~(steal_target_valid[:, None] & steal_cand_valid[None, :])
        steal_bad |= steal_targets[:, None] == steal_cand_labels[None, :]
        steal_bad |= steal_forbidden
        steal_bad |= counts[steal_targets][:, None] >= 14
        steal_bad |= steal_geom_bad
        steal_bad |= steal_sim.float() < float(_CODEX_STEAL_MIN_SIM)
        steal_bad |= (steal_sim.float() - steal_source_sim[None, :].float()) < float(_CODEX_STEAL_MARGIN)
        steal_sim = steal_sim.masked_fill(steal_bad, float("-inf"))

        steal_best_vals, steal_best_cols = steal_sim.max(dim=1)
        steal_keep = steal_target_valid & torch.isfinite(steal_best_vals)
        steal_best_for_col = torch.full(
            (steal_cand_cap,),
            float("-inf"),
            device=predicted.device,
            dtype=steal_best_vals.dtype,
        )
        steal_best_for_col.scatter_reduce_(
            0,
            steal_best_cols,
            torch.where(steal_keep, steal_best_vals, torch.full_like(steal_best_vals, float("-inf"))),
            reduce="amax",
            include_self=True,
        )
        steal_winners = steal_keep & (steal_best_vals >= steal_best_for_col[steal_best_cols])
        steal_target_for_col = torch.full(
            (steal_cand_cap,),
            n_labels,
            device=predicted.device,
            dtype=torch.long,
        )
        steal_target_for_col.scatter_reduce_(
            0,
            steal_best_cols,
            torch.where(steal_winners, steal_targets, torch.full_like(steal_targets, n_labels)),
            reduce="amin",
            include_self=True,
        )
        steal_cand_old_labels = labels_active_pad[steal_cand_pos].long().clamp(0, n_labels)
        steal_cand_new_labels = torch.where(
            steal_target_for_col < n_labels,
            steal_target_for_col,
            torch.full_like(steal_target_for_col, n_labels),
        )
        steal_moved = steal_cand_new_labels < n_labels
        if _CODEX_STEAL_DEBUG:
            print(
                "[steal-pre] "
                f"targets={int(steal_target_valid.sum().item())} "
                f"cands={int(steal_cand_valid.sum().item())} "
                f"keep={int(steal_keep.sum().item())} "
                f"winners={int(steal_winners.sum().item())} "
                f"moved={int(steal_moved.sum().item())}"
            )
        steal_labels_pad = labels_active_pad.clone()
        steal_labels_pad[steal_cand_pos] = torch.where(
            steal_moved,
            steal_cand_new_labels,
            steal_labels_pad[steal_cand_pos],
        )
        labels = steal_labels_pad[:active_cap]
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = labels
        out = out_pad[:n_total]
        moved_counts = steal_moved.to(torch.long)
        count_delta = torch.zeros_like(counts)
        count_delta.scatter_add_(0, steal_cand_old_labels, -moved_counts)
        count_delta.scatter_add_(0, steal_cand_new_labels.clamp(0, n_labels), moved_counts)
        counts = counts + count_delta
        if _CODEX_DO_DEDUP:
            moved_points = points_active_pad[steal_cand_pos] * steal_moved.to(emb.dtype)[:, None]
            sums_delta = torch.zeros_like(sums_full)
            sums_delta.scatter_add_(
                0,
                steal_cand_old_labels[:, None].expand(-1, feat_dim),
                -moved_points,
            )
            sums_delta.scatter_add_(
                0,
                steal_cand_new_labels.clamp(0, n_labels)[:, None].expand(-1, feat_dim),
                moved_points,
            )
            sums_full = sums_full + sums_delta

    if _CODEX_DO_DEDUP:
        centroids_full = sums_full / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
        centroids_full = F.normalize(centroids_full, p=2, dim=1, eps=1e-12)
        hit_sim = (points_all * centroids_full[labels]).sum(dim=1)
        layer_shift = layer_pad[active_idx].long().clamp(0, layer_span - 1)
        keys = labels * layer_span + layer_shift
        key_counts = torch.zeros((n_labels + 1) * layer_span, device=predicted.device, dtype=torch.long)
        key_counts.scatter_add_(0, keys, active_valid.to(torch.long))
        group_best = torch.full(
            ((n_labels + 1) * layer_span,),
            float("-inf"),
            device=hit_sim.device,
            dtype=hit_sim.dtype,
        )
        group_best.scatter_reduce_(0, keys, hit_sim, reduce="amax", include_self=True)
        gap = group_best[keys] - hit_sim
        candidate = (
            active_valid
            & (counts[labels] >= int(_CODEX_DEDUP_MIN_CLUSTER_SIZE))
            & (key_counts[keys] > 1)
            & (gap >= float(_CODEX_DEDUP_MIN_SIM_GAP))
        )
        drop = candidate & ((counts[labels] - int(_CODEX_DEDUP_MIN_SIZE_AFTER)) > 0)
        out_pad = torch.cat([out, dummy_pred], dim=0)
        out_pad[active_idx] = torch.where(drop, torch.full_like(labels, -1), out_pad[active_idx])
        out = out_pad[:n_total]

        active_valid = active_valid & (~drop)
        drop_counts = torch.zeros_like(counts)
        drop_counts.scatter_add_(0, labels, drop.to(torch.long))
        counts = counts - drop_counts

    if not _CODEX_DO_PAD:
        return out

    out_pad = torch.cat([out, dummy_pred], dim=0)
    clf_active = clf_pad[active_idx]
    cluster_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=clf_active.dtype)
    cluster_sum.scatter_add_(0, labels, torch.where(active_valid, clf_active, torch.zeros_like(clf_active)))
    cluster_clf = cluster_sum / counts.to(cluster_sum.dtype).clamp_min(1)
    size2_all = torch.nonzero_static(counts[:n_labels] == 2, size=size2_cap, fill_value=n_labels).squeeze(1)
    size2_scores = cluster_clf[size2_all].masked_fill(size2_all >= n_labels, float("-inf"))
    _, size2_order = size2_scores.topk(pad_cluster_cap, largest=True)
    size2_rows = size2_all[size2_order]
    size2_valid = size2_rows < n_labels

    hit_sizes = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
    hit_sizes = counts
    hit_size_full = torch.zeros(n_total + 1, device=predicted.device, dtype=torch.long)
    hit_size_full[active_idx] = hit_sizes[labels]
    if _CODEX_PAD_UNASSIGNED_ONLY:
        candidate_mask = valid_pad & (out_pad < 0)
    else:
        candidate_mask = valid_pad & ((out_pad < 0) | ((out_pad >= 0) & (hit_size_full <= 2)))
    cand_scores_full = clf_pad.masked_fill(~candidate_mask, float("-inf"))
    if _CODEX_PAD_CAND_BY_LAYER_CLF:
        per_layer = max(1, int(_CODEX_PAD_CAND_PER_LAYER))
        cand_idx_chunks = []
        cand_valid_chunks = []
        layer_all = layer_pad.long().clamp(0, layer_span - 1)
        for layer_i in range(layer_span):
            cand_scores_i = torch.where(
                layer_all == layer_i,
                cand_scores_full,
                torch.full_like(cand_scores_full, float("-inf")),
            )
            cand_vals_i, cand_idx_i = cand_scores_i.topk(per_layer, largest=True)
            cand_idx_chunks.append(cand_idx_i)
            cand_valid_chunks.append(torch.isfinite(cand_vals_i) & (cand_idx_i < n_total))
        cand_idx = torch.cat(cand_idx_chunks, dim=0)
        cand_valid = torch.cat(cand_valid_chunks, dim=0)
        pad_cand_cap = int(cand_idx.shape[0])
    else:
        _, cand_idx = cand_scores_full.topk(pad_cand_cap, largest=True)
        cand_valid = cand_idx < n_total

    row_map2 = torch.full((n_labels + 1,), pad_cluster_cap, device=predicted.device, dtype=torch.long)
    row_map2[size2_rows] = torch.arange(pad_cluster_cap, device=predicted.device, dtype=torch.long)
    size2_inv = row_map2[labels]
    active_size2 = active_valid & (size2_inv < pad_cluster_cap)
    size2_inv_safe = size2_inv.clamp(0, pad_cluster_cap - 1)
    seed_a = torch.full((pad_cluster_cap,), n_total, device=predicted.device, dtype=torch.long)
    seed_b = torch.zeros((pad_cluster_cap,), device=predicted.device, dtype=torch.long)
    seed_a.scatter_reduce_(0, size2_inv_safe, torch.where(active_size2, active_idx, torch.full_like(active_idx, n_total)), reduce="amin", include_self=True)
    seed_b.scatter_reduce_(0, size2_inv_safe, torch.where(active_size2, active_idx, torch.zeros_like(active_idx)), reduce="amax", include_self=True)
    seed_idx = torch.stack([seed_a, seed_b], dim=1)
    seed_emb = emb_pad[seed_idx]
    centroids = F.normalize(seed_emb.sum(dim=1) * 0.5, p=2, dim=1, eps=1e-12)

    seed_layers = layer_pad[seed_idx].long().clamp(0, layer_span - 1)
    layer_presence = torch.zeros((pad_cluster_cap, layer_span), device=predicted.device, dtype=torch.bool)
    row_ids2 = torch.arange(pad_cluster_cap, device=predicted.device, dtype=torch.long)
    layer_presence[row_ids2, seed_layers[:, 0]] = size2_valid
    layer_presence[row_ids2, seed_layers[:, 1]] = size2_valid
    cand_layers = layer_pad[cand_idx].long().clamp(0, layer_span - 1)
    forbidden = layer_presence[:, cand_layers]
    seed_coords = coords_pad[seed_idx].float()
    r1 = seed_coords[:, 0, 2]
    r2 = seed_coords[:, 1, 2]
    z1 = seed_coords[:, 0, 4]
    z2 = seed_coords[:, 1, 4]
    p1 = seed_coords[:, 0, 3]
    p2 = seed_coords[:, 1, 3]
    denom_raw = r2 - r1
    denom = denom_raw.clamp_min(1e-6)
    denom = torch.where(denom_raw < 0, denom_raw.clamp_max(-1e-6), denom)
    cand_coords = coords_pad[cand_idx].float()
    rc = cand_coords[:, 2][None, :]
    zc = cand_coords[:, 4][None, :]
    pc = cand_coords[:, 3][None, :]
    t = (rc - r1[:, None]) / denom[:, None]
    z_pred = z1[:, None] + (z2 - z1)[:, None] * t
    z_res = (zc - z_pred).abs()
    dphi12 = _wrap_normalized_phi_diff_torch(p2 - p1)
    dphi1c = _wrap_normalized_phi_diff_torch(pc - p1[:, None])
    phi_res = _wrap_normalized_phi_diff_torch(dphi1c - dphi12[:, None] * t).abs()
    geom_bad = (z_res > float(_CODEX_PAD_Z_MAX)) | (phi_res > float(_CODEX_PAD_PHI_MAX))
    geom_bad |= t < float(_CODEX_PAD_T_MIN)
    geom_bad |= t > float(_CODEX_PAD_T_MAX)
    pad_bad = ~(size2_valid[:, None] & cand_valid[None, :])
    pad_bad |= out_pad[cand_idx][None, :] == size2_rows[:, None]
    pad_bad |= forbidden | geom_bad
    pad_geom_topk = int(_CODEX_PAD_GEOM_TOPK)
    if pad_geom_topk > 0:
        geom_score = -(
            z_res / float(_CODEX_PAD_Z_MAX)
            + phi_res / float(_CODEX_PAD_PHI_MAX)
        )
        geom_score = geom_score.masked_fill(pad_bad, float("-inf"))
        geom_vals, geom_cols = geom_score.topk(pad_geom_topk, dim=1, largest=True)
        local_cand_idx = cand_idx[geom_cols]
        local_emb = emb_pad[local_cand_idx]
        local_sim = (local_emb.to(torch.float16) * centroids[:, None, :].to(torch.float16)).sum(dim=2)
        local_sim = local_sim.masked_fill(~torch.isfinite(geom_vals), float("-inf"))
        best_vals, best_local_cols = local_sim.max(dim=1)
        best_cols = geom_cols.gather(1, best_local_cols[:, None]).squeeze(1)
        top2_vals = local_sim.topk(2, dim=1).values
    else:
        sim = centroids @ emb_pad[cand_idx].t()
        sim = sim.masked_fill(pad_bad, float("-inf"))
        best_vals, best_cols = sim.max(dim=1)
        top2_vals = sim.topk(2, dim=1).values
    pad_margin = top2_vals[:, 0] - top2_vals[:, 1]
    keep = size2_valid & (best_vals >= float(_CODEX_PAD_MIN_SIM)) & (
        pad_margin >= float(_CODEX_PAD_MIN_MARGIN)
    )
    cand_cols = best_cols
    cand_scores = best_vals.masked_fill(~keep, float("-inf"))
    best_for_col = torch.full((pad_cand_cap,), float("-inf"), device=predicted.device, dtype=cand_scores.dtype)
    best_for_col.scatter_reduce_(0, cand_cols, cand_scores, reduce="amax", include_self=True)
    winners = keep & (cand_scores >= best_for_col[cand_cols])
    target_for_col = torch.full((pad_cand_cap,), n_labels, device=predicted.device, dtype=torch.long)
    target_for_col.scatter_reduce_(
        0,
        cand_cols,
        torch.where(winners, size2_rows, torch.full_like(size2_rows, n_labels)),
        reduce="amin",
        include_self=True,
    )
    chosen = target_for_col
    out_pad = torch.cat([out, dummy_pred], dim=0)
    out_pad[cand_idx] = torch.where(chosen < n_labels, chosen, out_pad[cand_idx])
    if _CODEX_DO_STEAL_POINT and _CODEX_STEAL_AFTER_PAD:
        steal_target_cap = int(_CODEX_STEAL_TARGET_CAP)
        steal_cand_cap = int(_CODEX_STEAL_CAND_CAP)
        steal_centroids = sums_full / counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
        steal_centroids = F.normalize(steal_centroids, p=2, dim=1, eps=1e-12)
        source_sim_all = (points_all * steal_centroids[labels]).sum(dim=1)

        steal_target_mask = (
            (counts[:n_labels] >= int(_CODEX_STEAL_TARGET_MIN_SIZE))
            & (counts[:n_labels] <= int(_CODEX_STEAL_TARGET_MAX_SIZE))
        )
        if _CODEX_STEAL_TARGET_BY_CLF:
            steal_target_scores = cluster_clf[:n_labels].masked_fill(~steal_target_mask, float("-inf"))
            steal_target_vals, steal_targets = steal_target_scores.topk(steal_target_cap, largest=True)
            steal_target_valid = torch.isfinite(steal_target_vals)
        else:
            steal_targets = torch.nonzero_static(
                steal_target_mask,
                size=steal_target_cap,
                fill_value=n_labels,
            ).squeeze(1)
            steal_target_valid = steal_targets < n_labels

        layer_active = layer_pad[active_idx].long().clamp(0, layer_span - 1)
        source_sizes = counts[labels]
        steal_cand_mask = (
            active_valid
            & (source_sizes >= int(_CODEX_STEAL_SOURCE_MIN_SIZE))
            & (source_sizes <= int(_CODEX_STEAL_SOURCE_MAX_SIZE))
        )
        if int(_CODEX_STEAL_CAND_ACTIVE_OFFSET) >= 0:
            steal_cand_pos = (
                torch.arange(steal_cand_cap, device=predicted.device, dtype=torch.long)
                + int(_CODEX_STEAL_CAND_ACTIVE_OFFSET)
            ).clamp_max(active_cap)
            steal_cand_valid = (steal_cand_pos < active_cap) & steal_cand_mask[steal_cand_pos.clamp_max(active_cap - 1)]
        elif int(_CODEX_STEAL_CAND_RANK_OFFSET) > 0:
            cand_rank = steal_cand_mask.to(torch.long).cumsum(0) - 1
            cand_window = (
                steal_cand_mask
                & (cand_rank >= int(_CODEX_STEAL_CAND_RANK_OFFSET))
                & (cand_rank < int(_CODEX_STEAL_CAND_RANK_OFFSET) + int(steal_cand_cap))
            )
            steal_cand_pos = torch.nonzero_static(
                cand_window,
                size=steal_cand_cap,
                fill_value=active_cap,
            ).squeeze(1)
            steal_cand_valid = steal_cand_pos < active_cap
        elif _CODEX_STEAL_CAND_STRIDED:
            cand_cum = steal_cand_mask.to(torch.long).cumsum(0)
            num_cands = cand_cum[-1].clamp_min(1)
            cand_arange = torch.arange(steal_cand_cap, device=predicted.device, dtype=torch.long)
            cand_ranks = ((cand_arange * num_cands) // int(steal_cand_cap) + 1).clamp_max(num_cands)
            steal_cand_pos = torch.searchsorted(cand_cum, cand_ranks).clamp_max(active_cap - 1)
            steal_cand_valid = cand_arange < cand_cum[-1]
        elif _CODEX_STEAL_CAND_BY_LAYER_LOW_SOURCE:
            per_layer = max(1, int(_CODEX_STEAL_CAND_PER_LAYER))
            cand_pos_chunks = []
            cand_valid_chunks = []
            for layer_i in range(layer_span):
                steal_cand_scores = torch.where(
                    steal_cand_mask & (layer_active == layer_i),
                    -source_sim_all.float(),
                    torch.full((active_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
                )
                steal_cand_vals_i, steal_cand_pos_i = steal_cand_scores.topk(per_layer, largest=True)
                cand_pos_chunks.append(steal_cand_pos_i)
                cand_valid_chunks.append(torch.isfinite(steal_cand_vals_i))
            steal_cand_pos = torch.cat(cand_pos_chunks, dim=0)
            steal_cand_valid = torch.cat(cand_valid_chunks, dim=0)
            steal_cand_cap = int(steal_cand_pos.shape[0])
        elif _CODEX_STEAL_CAND_BY_LOW_SOURCE_SIM:
            steal_cand_scores = torch.where(
                steal_cand_mask,
                -source_sim_all.float(),
                torch.full((active_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
            )
            steal_cand_vals, steal_cand_pos = steal_cand_scores.topk(steal_cand_cap, largest=True)
            steal_cand_valid = torch.isfinite(steal_cand_vals)
        elif _CODEX_STEAL_CAND_BY_CLF:
            steal_cand_clf = clf_pad[active_idx].float()
            steal_cand_scores = torch.where(
                steal_cand_mask,
                steal_cand_clf,
                torch.full((active_cap,), float("-inf"), device=predicted.device, dtype=torch.float32),
            )
            steal_cand_vals, steal_cand_pos = steal_cand_scores.topk(steal_cand_cap, largest=True)
            steal_cand_valid = torch.isfinite(steal_cand_vals)
        else:
            steal_cand_pos = torch.nonzero_static(
                steal_cand_mask,
                size=steal_cand_cap,
                fill_value=active_cap,
            ).squeeze(1)
            steal_cand_valid = steal_cand_pos < active_cap

        points_active_pad = torch.cat(
            [points_all, torch.zeros((1, feat_dim), device=emb.device, dtype=emb.dtype)],
            dim=0,
        )
        labels_active_pad = torch.cat(
            [labels, torch.full((1,), n_labels, device=predicted.device, dtype=torch.long)],
            dim=0,
        )
        layer_active_pad = torch.cat(
            [layer_active, torch.zeros((1,), device=predicted.device, dtype=torch.long)],
            dim=0,
        )
        source_sim_pad = torch.cat(
            [
                source_sim_all,
                torch.full((1,), float("inf"), device=emb.device, dtype=source_sim_all.dtype),
            ],
            dim=0,
        )

        steal_target_centroids = steal_centroids[steal_targets]
        steal_cand_points = points_active_pad[steal_cand_pos]
        steal_sim = steal_target_centroids.to(torch.float16) @ steal_cand_points.to(torch.float16).t()

        if _CODEX_STEAL_CHECK_LAYER:
            steal_layer_keys = labels * layer_span + layer_active
            steal_presence_flat = torch.zeros((n_labels + 1) * layer_span, device=predicted.device, dtype=torch.float32)
            steal_presence_flat.scatter_add_(0, steal_layer_keys, active_valid.to(torch.float32))
            steal_presence = steal_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0)
            steal_cand_layers = layer_active_pad[steal_cand_pos]
            steal_forbidden = steal_presence[steal_targets][:, steal_cand_layers] > 0
        else:
            steal_forbidden = torch.zeros_like(steal_sim, dtype=torch.bool)

        steal_cand_labels = labels_active_pad[steal_cand_pos]
        steal_source_sim = source_sim_pad[steal_cand_pos]
        steal_bad = ~(steal_target_valid[:, None] & steal_cand_valid[None, :])
        steal_bad |= steal_targets[:, None] == steal_cand_labels[None, :]
        steal_bad |= steal_forbidden
        steal_bad |= counts[steal_targets][:, None] >= 14
        steal_bad |= steal_sim.float() < float(_CODEX_STEAL_MIN_SIM)
        steal_bad |= (steal_sim.float() - steal_source_sim[None, :].float()) < float(_CODEX_STEAL_MARGIN)
        steal_sim = steal_sim.masked_fill(steal_bad, float("-inf"))

        steal_best_vals, steal_best_cols = steal_sim.max(dim=1)
        steal_keep = steal_target_valid & torch.isfinite(steal_best_vals)
        steal_best_for_col = torch.full(
            (steal_cand_cap,),
            float("-inf"),
            device=predicted.device,
            dtype=steal_best_vals.dtype,
        )
        steal_best_for_col.scatter_reduce_(
            0,
            steal_best_cols,
            torch.where(steal_keep, steal_best_vals, torch.full_like(steal_best_vals, float("-inf"))),
            reduce="amax",
            include_self=True,
        )
        steal_winners = steal_keep & (steal_best_vals >= steal_best_for_col[steal_best_cols])
        steal_target_for_col = torch.full(
            (steal_cand_cap,),
            n_labels,
            device=predicted.device,
            dtype=torch.long,
        )
        steal_target_for_col.scatter_reduce_(
            0,
            steal_best_cols,
            torch.where(steal_winners, steal_targets, torch.full_like(steal_targets, n_labels)),
            reduce="amin",
            include_self=True,
        )
        if _CODEX_STEAL_DEBUG:
            steal_moved = steal_target_for_col < n_labels
            print(
                "[steal-post] "
                f"targets={int(steal_target_valid.sum().item())} "
                f"cands={int(steal_cand_valid.sum().item())} "
                f"keep={int(steal_keep.sum().item())} "
                f"winners={int(steal_winners.sum().item())} "
                f"moved={int(steal_moved.sum().item())}"
            )
        after_pad_labels = out_pad[active_idx].long().clamp(0, n_labels)
        after_pad_labels_pad = torch.cat(
            [after_pad_labels, torch.full((1,), n_labels, device=predicted.device, dtype=torch.long)],
            dim=0,
        )
        after_pad_labels_pad[steal_cand_pos] = torch.where(
            steal_target_for_col < n_labels,
            steal_target_for_col,
            after_pad_labels_pad[steal_cand_pos],
        )
        out_pad[active_idx] = after_pad_labels_pad[:active_cap]
    if _CODEX_DO_POSTPAD_SAME_QUERY:
        post_same_active_idx = torch.nonzero_static(
            valid_pad.bool() & (out_pad >= 0),
            size=active_cap,
            fill_value=n_total,
        ).squeeze(1)
        post_same_active_valid = post_same_active_idx < n_total
        post_same_labels = out_pad[post_same_active_idx].long().clamp(0, n_labels)
        post_same_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_same_counts.scatter_add_(0, post_same_labels, post_same_active_valid.to(torch.long))
        post_same_cap = n_labels
        post_same_rows = torch.nonzero_static(
            (post_same_counts[:n_labels] > 0)
            & (post_same_counts[:n_labels] < int(_CODEX_POSTPAD_SAME_QUERY_MAX_MERGED)),
            size=post_same_cap,
            fill_value=n_labels,
        ).squeeze(1)
        post_same_valid = post_same_rows < n_labels
        post_same_safe = post_same_rows.clamp(0, n_labels)
        post_same_q = max(1, int(_CODEX_SAME_QUERY_Q))
        post_same_query = post_same_rows.clamp(0, n_labels - 1).remainder(post_same_q)
        post_same_row_counts = post_same_counts[post_same_safe]
        post_same_base = n_labels + 1
        post_same_target_candidate = (
            post_same_valid
            & (post_same_row_counts >= int(_CODEX_POSTPAD_SAME_QUERY_TARGET_MIN))
        )
        post_same_encoded = post_same_row_counts.long() * post_same_base + (
            post_same_base - 1 - post_same_safe.long()
        )
        post_same_encoded = torch.where(
            post_same_target_candidate,
            post_same_encoded,
            torch.full_like(post_same_encoded, -1),
        )
        post_same_best_encoded = torch.full(
            (post_same_q,),
            -1,
            device=predicted.device,
            dtype=torch.long,
        )
        post_same_best_encoded.scatter_reduce_(
            0,
            post_same_query,
            post_same_encoded,
            reduce="amax",
            include_self=True,
        )
        post_same_best_label = torch.where(
            post_same_best_encoded >= 0,
            post_same_base - 1 - post_same_best_encoded.remainder(post_same_base),
            torch.full_like(post_same_best_encoded, n_labels),
        )
        post_same_target_for_row = post_same_best_label[post_same_query]
        post_same_target_counts = post_same_counts[post_same_target_for_row.clamp(0, n_labels)]
        post_same_keep = (
            post_same_valid
            & (post_same_row_counts <= int(_CODEX_POSTPAD_SAME_QUERY_SMALL))
            & (post_same_target_for_row < n_labels)
            & (post_same_target_for_row != post_same_rows)
            & (
                post_same_row_counts + post_same_target_counts
                <= int(_CODEX_POSTPAD_SAME_QUERY_MAX_MERGED)
            )
        )
        if _CODEX_POSTPAD_SAME_QUERY_REQUIRE_LARGER:
            post_same_keep = post_same_keep & (post_same_target_counts > post_same_row_counts)
        else:
            post_same_keep = post_same_keep & (
                (post_same_target_counts > post_same_row_counts)
                | (
                    (post_same_target_counts == post_same_row_counts)
                    & (post_same_target_for_row < post_same_rows)
                )
            )
        post_same_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_same_remap[post_same_rows] = torch.where(
            post_same_keep,
            post_same_target_for_row,
            post_same_remap[post_same_rows],
        )
        for _ in range(4):
            post_same_remap = post_same_remap[post_same_remap]
        post_same_merged_sizes = torch.zeros_like(post_same_counts)
        post_same_merged_sizes.scatter_add_(0, post_same_remap, post_same_counts)
        post_same_base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_same_remap = torch.where(
            post_same_merged_sizes[post_same_remap] > int(_CODEX_POSTPAD_SAME_QUERY_MAX_MERGED),
            post_same_base_remap,
            post_same_remap,
        )
        for _ in range(2):
            post_same_remap = post_same_remap[post_same_remap]
        post_same_labels = post_same_remap[post_same_labels].long().clamp(0, n_labels)
        out_pad[post_same_active_idx] = post_same_labels
    if _CODEX_DO_POSTPAD_GEOM_PRUNE:
        prune_active_idx = torch.nonzero_static(
            valid_pad.bool() & (out_pad >= 0),
            size=active_cap,
            fill_value=n_total,
        ).squeeze(1)
        prune_active_valid = prune_active_idx < n_total
        prune_labels = out_pad[prune_active_idx].long().clamp(0, n_labels)
        prune_coords = coords_pad[prune_active_idx].float()
        prune_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        prune_counts.scatter_add_(0, prune_labels, prune_active_valid.to(torch.long))
        prune_d_coord = int(coords.shape[1])
        prune_r = prune_coords[:, 2]
        prune_min_r = torch.full((n_labels + 1,), float("inf"), device=coords.device, dtype=torch.float32)
        prune_max_r = torch.full((n_labels + 1,), float("-inf"), device=coords.device, dtype=torch.float32)
        prune_min_r.scatter_reduce_(
            0,
            prune_labels,
            torch.where(prune_active_valid, prune_r, torch.full_like(prune_r, float("inf"))),
            reduce="amin",
            include_self=True,
        )
        prune_max_r.scatter_reduce_(
            0,
            prune_labels,
            torch.where(prune_active_valid, prune_r, torch.full_like(prune_r, float("-inf"))),
            reduce="amax",
            include_self=True,
        )
        prune_min_hit = prune_active_valid & ((prune_r - prune_min_r[prune_labels]).abs() <= 1e-6)
        prune_max_hit = prune_active_valid & ((prune_r - prune_max_r[prune_labels]).abs() <= 1e-6)
        prune_min_sums = torch.zeros((n_labels + 1, prune_d_coord), device=coords.device, dtype=torch.float32)
        prune_max_sums = torch.zeros_like(prune_min_sums)
        prune_min_sums.scatter_add_(
            0,
            prune_labels[:, None].expand(-1, prune_d_coord),
            prune_coords * prune_min_hit.to(torch.float32)[:, None],
        )
        prune_max_sums.scatter_add_(
            0,
            prune_labels[:, None].expand(-1, prune_d_coord),
            prune_coords * prune_max_hit.to(torch.float32)[:, None],
        )
        prune_min_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
        prune_max_counts = torch.zeros_like(prune_min_counts)
        prune_min_counts.scatter_add_(0, prune_labels, prune_min_hit.to(torch.float32))
        prune_max_counts.scatter_add_(0, prune_labels, prune_max_hit.to(torch.float32))
        prune_start = prune_min_sums / prune_min_counts.clamp_min(1).unsqueeze(1)
        prune_end = prune_max_sums / prune_max_counts.clamp_min(1).unsqueeze(1)
        prune_seed0 = prune_start[prune_labels]
        prune_seed1 = prune_end[prune_labels]
        prune_r0 = prune_seed0[:, 2]
        prune_r1 = prune_seed1[:, 2]
        prune_z0 = prune_seed0[:, 4]
        prune_z1 = prune_seed1[:, 4]
        prune_p0 = prune_seed0[:, 3]
        prune_p1 = prune_seed1[:, 3]
        prune_dr = prune_r1 - prune_r0
        prune_denom = torch.where(prune_dr >= 0, prune_dr.clamp_min(1e-6), prune_dr.clamp_max(-1e-6))
        prune_t = (prune_r - prune_r0) / prune_denom
        prune_z_pred = prune_z0 + (prune_z1 - prune_z0) * prune_t
        prune_z_res = (prune_coords[:, 4] - prune_z_pred).abs()
        prune_dphi01 = _wrap_normalized_phi_diff_torch(prune_p1 - prune_p0)
        prune_dphi0 = _wrap_normalized_phi_diff_torch(prune_coords[:, 3] - prune_p0)
        prune_phi_res = _wrap_normalized_phi_diff_torch(prune_dphi0 - prune_dphi01 * prune_t).abs()
        prune_score = (
            prune_z_res / float(_CODEX_POSTPAD_GEOM_PRUNE_Z_MAX)
            + prune_phi_res / float(_CODEX_POSTPAD_GEOM_PRUNE_PHI_MAX)
        )
        prune_sizes = prune_counts[prune_labels]
        prune_candidate = (
            prune_active_valid
            & (prune_sizes >= int(_CODEX_POSTPAD_GEOM_PRUNE_MIN_SIZE))
            & (prune_sizes <= int(_CODEX_POSTPAD_GEOM_PRUNE_MAX_SIZE))
            & (prune_score >= float(_CODEX_POSTPAD_GEOM_PRUNE_SCORE))
        )
        if float(_CODEX_POSTPAD_GEOM_PRUNE_CLF_MEAN_MAX) > 0.0:
            prune_clf = clf_pad[prune_active_idx].float()
            prune_clf_sum = torch.zeros(
                n_labels + 1,
                device=predicted.device,
                dtype=torch.float32,
            )
            prune_clf_sum.scatter_add_(
                0,
                prune_labels,
                torch.where(prune_active_valid, prune_clf, torch.zeros_like(prune_clf)),
            )
            prune_clf_mean = prune_clf_sum / prune_counts.to(torch.float32).clamp_min(1.0)
            prune_candidate = prune_candidate & (
                prune_clf_mean[prune_labels] <= float(_CODEX_POSTPAD_GEOM_PRUNE_CLF_MEAN_MAX)
            )
        if int(_CODEX_POSTPAD_GEOM_PRUNE_MIN_DUP) >= 0:
            prune_layers = layer_pad[prune_active_idx].long().clamp(0, layer_span - 1)
            prune_layer_keys = prune_labels * layer_span + prune_layers
            prune_presence_flat = torch.zeros(
                (n_labels + 1) * layer_span,
                device=predicted.device,
                dtype=torch.float32,
            )
            prune_presence_flat.scatter_add_(0, prune_layer_keys, prune_active_valid.to(torch.float32))
            prune_presence = prune_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0)
            prune_dup = prune_counts - prune_presence.sum(dim=1).to(prune_counts.dtype)
            prune_candidate = prune_candidate & (
                prune_dup[prune_labels] >= int(_CODEX_POSTPAD_GEOM_PRUNE_MIN_DUP)
            )
        prune_best_score = torch.full((n_labels + 1,), float("-inf"), device=predicted.device, dtype=torch.float32)
        prune_best_score.scatter_reduce_(
            0,
            prune_labels,
            torch.where(prune_candidate, prune_score, torch.full_like(prune_score, float("-inf"))),
            reduce="amax",
            include_self=True,
        )
        prune_drop = prune_candidate & (prune_score >= prune_best_score[prune_labels] - 1e-6)
        out_pad[prune_active_idx] = torch.where(
            prune_drop,
            torch.full_like(out_pad[prune_active_idx], -1),
            out_pad[prune_active_idx],
        )
    if _CODEX_DO_POSTPAD_SEMANTIC_PRUNE:
        sem_active_idx = torch.nonzero_static(
            valid_pad.bool() & (out_pad >= 0),
            size=active_cap,
            fill_value=n_total,
        ).squeeze(1)
        sem_active_valid = sem_active_idx < n_total
        sem_labels = out_pad[sem_active_idx].long().clamp(0, n_labels)
        sem_points = emb_pad[sem_active_idx].to(torch.float32)
        sem_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        sem_counts.scatter_add_(0, sem_labels, sem_active_valid.to(torch.long))
        sem_dim = int(emb.shape[1])
        sem_sums = torch.zeros((n_labels + 1, sem_dim), device=predicted.device, dtype=torch.float32)
        sem_sums.scatter_add_(
            0,
            sem_labels[:, None].expand(-1, sem_dim),
            sem_points * sem_active_valid.to(torch.float32)[:, None],
        )
        sem_centroids = F.normalize(
            sem_sums / sem_counts.to(torch.float32).clamp_min(1.0).unsqueeze(1),
            p=2,
            dim=1,
            eps=1e-12,
        )
        sem_sim = (sem_points * sem_centroids[sem_labels]).sum(dim=1)
        sem_sizes = sem_counts[sem_labels]
        sem_min_sim = torch.full(
            (n_labels + 1,),
            float("inf"),
            device=predicted.device,
            dtype=torch.float32,
        )
        sem_min_sim.scatter_reduce_(
            0,
            sem_labels,
            torch.where(sem_active_valid, sem_sim, torch.full_like(sem_sim, float("inf"))),
            reduce="amin",
            include_self=True,
        )
        sem_mean_sim_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.float32)
        sem_mean_sim_sum.scatter_add_(
            0,
            sem_labels,
            torch.where(sem_active_valid, sem_sim, torch.zeros_like(sem_sim)),
        )
        sem_mean_sim = sem_mean_sim_sum / sem_counts.to(torch.float32).clamp_min(1.0)
        sem_candidate = (
            sem_active_valid
            & (sem_sizes >= int(_CODEX_POSTPAD_SEMANTIC_PRUNE_MIN_SIZE))
            & (sem_sizes <= int(_CODEX_POSTPAD_SEMANTIC_PRUNE_MAX_SIZE))
            & (sem_sim <= sem_min_sim[sem_labels] + 1e-6)
            & (sem_min_sim[sem_labels] <= float(_CODEX_POSTPAD_SEMANTIC_PRUNE_SIM_MIN))
        )
        if float(_CODEX_POSTPAD_SEMANTIC_PRUNE_SIM_GAP) > 0.0:
            sem_candidate = sem_candidate & (
                (sem_mean_sim[sem_labels] - sem_min_sim[sem_labels])
                >= float(_CODEX_POSTPAD_SEMANTIC_PRUNE_SIM_GAP)
            )
        if float(_CODEX_POSTPAD_SEMANTIC_PRUNE_CLF_MEAN_MAX) > 0.0:
            sem_clf = clf_pad[sem_active_idx].float()
            sem_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.float32)
            sem_clf_sum.scatter_add_(
                0,
                sem_labels,
                torch.where(sem_active_valid, sem_clf, torch.zeros_like(sem_clf)),
            )
            sem_clf_mean = sem_clf_sum / sem_counts.to(torch.float32).clamp_min(1.0)
            sem_candidate = sem_candidate & (
                sem_clf_mean[sem_labels] <= float(_CODEX_POSTPAD_SEMANTIC_PRUNE_CLF_MEAN_MAX)
            )
        if int(_CODEX_POSTPAD_SEMANTIC_PRUNE_MIN_DUP) >= 0:
            sem_layers = layer_pad[sem_active_idx].long().clamp(0, layer_span - 1)
            sem_layer_keys = sem_labels * layer_span + sem_layers
            sem_presence_flat = torch.zeros(
                (n_labels + 1) * layer_span,
                device=predicted.device,
                dtype=torch.float32,
            )
            sem_presence_flat.scatter_add_(0, sem_layer_keys, sem_active_valid.to(torch.float32))
            sem_presence = sem_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0)
            sem_dup = sem_counts - sem_presence.sum(dim=1).to(sem_counts.dtype)
            sem_candidate = sem_candidate & (
                sem_dup[sem_labels] >= int(_CODEX_POSTPAD_SEMANTIC_PRUNE_MIN_DUP)
            )
        out_pad[sem_active_idx] = torch.where(
            sem_candidate,
            torch.full_like(out_pad[sem_active_idx], -1),
            out_pad[sem_active_idx],
        )
    if _CODEX_DO_POSTPAD_GEO_MERGE:
        post_geo_small_cap = int(_CODEX_POSTPAD_GEO_SMALL_CAP)
        post_geo_target_cap = int(_CODEX_POSTPAD_GEO_TARGET_CAP)
        post_geo_max_merged = int(_CODEX_POSTPAD_GEO_MAX_MERGED_SIZE)
        post_geo_active_idx = torch.nonzero_static(
            valid_pad.bool() & (out_pad >= 0),
            size=active_cap,
            fill_value=n_total,
        ).squeeze(1)
        post_geo_active_valid = post_geo_active_idx < n_total
        post_geo_labels = out_pad[post_geo_active_idx].long().clamp(0, n_labels)
        post_geo_points = emb_pad[post_geo_active_idx]
        post_geo_coords = coords_pad[post_geo_active_idx].float()
        post_geo_weight = post_geo_active_valid.to(torch.float32)

        post_geo_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_geo_counts.scatter_add_(0, post_geo_labels, post_geo_active_valid.to(torch.long))
        post_geo_sums = torch.zeros((n_labels + 1, feat_dim), device=emb.device, dtype=emb.dtype)
        post_geo_sums.scatter_add_(
            0,
            post_geo_labels[:, None].expand(-1, feat_dim),
            post_geo_points * post_geo_active_valid.to(emb.dtype)[:, None],
        )
        post_geo_centroids = post_geo_sums / post_geo_counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
        post_geo_centroids = F.normalize(post_geo_centroids, p=2, dim=1, eps=1e-12)

        post_geo_d_coord = int(coords.shape[1])
        post_geo_coord_sums = torch.zeros((n_labels + 1, post_geo_d_coord), device=coords.device, dtype=torch.float32)
        post_geo_coord_sums.scatter_add_(
            0,
            post_geo_labels[:, None].expand(-1, post_geo_d_coord),
            post_geo_coords * post_geo_weight[:, None],
        )
        post_geo_coord_means = post_geo_coord_sums / post_geo_counts.to(torch.float32).clamp_min(1).unsqueeze(1)
        post_geo_active_r = post_geo_coords[:, 2]
        post_geo_min_r = torch.full((n_labels + 1,), float("inf"), device=coords.device, dtype=torch.float32)
        post_geo_max_r = torch.full((n_labels + 1,), float("-inf"), device=coords.device, dtype=torch.float32)
        post_geo_min_r.scatter_reduce_(
            0,
            post_geo_labels,
            torch.where(post_geo_active_valid, post_geo_active_r, torch.full_like(post_geo_active_r, float("inf"))),
            reduce="amin",
            include_self=True,
        )
        post_geo_max_r.scatter_reduce_(
            0,
            post_geo_labels,
            torch.where(post_geo_active_valid, post_geo_active_r, torch.full_like(post_geo_active_r, float("-inf"))),
            reduce="amax",
            include_self=True,
        )
        post_geo_min_hit = post_geo_active_valid & ((post_geo_active_r - post_geo_min_r[post_geo_labels]).abs() <= 1e-6)
        post_geo_max_hit = post_geo_active_valid & ((post_geo_active_r - post_geo_max_r[post_geo_labels]).abs() <= 1e-6)
        post_geo_min_sums = torch.zeros_like(post_geo_coord_sums)
        post_geo_max_sums = torch.zeros_like(post_geo_coord_sums)
        post_geo_min_sums.scatter_add_(
            0,
            post_geo_labels[:, None].expand(-1, post_geo_d_coord),
            post_geo_coords * post_geo_min_hit.to(torch.float32)[:, None],
        )
        post_geo_max_sums.scatter_add_(
            0,
            post_geo_labels[:, None].expand(-1, post_geo_d_coord),
            post_geo_coords * post_geo_max_hit.to(torch.float32)[:, None],
        )
        post_geo_min_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
        post_geo_max_counts = torch.zeros((n_labels + 1,), device=coords.device, dtype=torch.float32)
        post_geo_min_counts.scatter_add_(0, post_geo_labels, post_geo_min_hit.to(torch.float32))
        post_geo_max_counts.scatter_add_(0, post_geo_labels, post_geo_max_hit.to(torch.float32))
        post_geo_start = post_geo_min_sums / post_geo_min_counts.clamp_min(1).unsqueeze(1)
        post_geo_end = post_geo_max_sums / post_geo_max_counts.clamp_min(1).unsqueeze(1)

        post_geo_small_rows = torch.nonzero_static(
            (post_geo_counts[:n_labels] >= int(_CODEX_POSTPAD_GEO_MIN_SIZE))
            & (post_geo_counts[:n_labels] <= int(_CODEX_POSTPAD_GEO_MAX_SIZE)),
            size=post_geo_small_cap,
            fill_value=n_labels,
        ).squeeze(1)
        post_geo_target_mask = (
            (post_geo_counts[:n_labels] >= int(_CODEX_POSTPAD_GEO_TARGET_MIN_SIZE))
            & (post_geo_counts[:n_labels] < post_geo_max_merged)
            & ((post_geo_max_r[:n_labels] - post_geo_min_r[:n_labels]).abs() > 1e-6)
        )
        post_geo_target_rows = torch.nonzero_static(
            post_geo_target_mask,
            size=post_geo_target_cap,
            fill_value=n_labels,
        ).squeeze(1)
        post_geo_small_valid = post_geo_small_rows < n_labels
        post_geo_target_valid = post_geo_target_rows < n_labels

        post_geo_source_coords = post_geo_coord_means[post_geo_small_rows]
        post_geo_source_start = post_geo_start[post_geo_small_rows]
        post_geo_source_end = post_geo_end[post_geo_small_rows]
        post_geo_target_start = post_geo_start[post_geo_target_rows]
        post_geo_target_end = post_geo_end[post_geo_target_rows]
        post_geo_r0 = post_geo_target_start[:, 2]
        post_geo_r1 = post_geo_target_end[:, 2]
        post_geo_z0 = post_geo_target_start[:, 4]
        post_geo_z1 = post_geo_target_end[:, 4]
        post_geo_p0 = post_geo_target_start[:, 3]
        post_geo_p1 = post_geo_target_end[:, 3]
        post_geo_dr = post_geo_r1 - post_geo_r0
        post_geo_denom = torch.where(post_geo_dr >= 0, post_geo_dr.clamp_min(1e-6), post_geo_dr.clamp_max(-1e-6))
        post_geo_dphi01 = _wrap_normalized_phi_diff_torch(post_geo_p1 - post_geo_p0)
        if _CODEX_POSTPAD_GEO_USE_ENDPOINTS:
            post_geo_rs0 = post_geo_source_start[:, 2][:, None]
            post_geo_zs0 = post_geo_source_start[:, 4][:, None]
            post_geo_ps0 = post_geo_source_start[:, 3][:, None]
            post_geo_rs1 = post_geo_source_end[:, 2][:, None]
            post_geo_zs1 = post_geo_source_end[:, 4][:, None]
            post_geo_ps1 = post_geo_source_end[:, 3][:, None]
            post_geo_t0 = (post_geo_rs0 - post_geo_r0[None, :]) / post_geo_denom[None, :]
            post_geo_t1 = (post_geo_rs1 - post_geo_r0[None, :]) / post_geo_denom[None, :]
            post_geo_z_pred0 = post_geo_z0[None, :] + (post_geo_z1 - post_geo_z0)[None, :] * post_geo_t0
            post_geo_z_pred1 = post_geo_z0[None, :] + (post_geo_z1 - post_geo_z0)[None, :] * post_geo_t1
            post_geo_z_res0 = (post_geo_zs0 - post_geo_z_pred0).abs()
            post_geo_z_res1 = (post_geo_zs1 - post_geo_z_pred1).abs()
            post_geo_dphi0s0 = _wrap_normalized_phi_diff_torch(post_geo_ps0 - post_geo_p0[None, :])
            post_geo_dphi0s1 = _wrap_normalized_phi_diff_torch(post_geo_ps1 - post_geo_p0[None, :])
            post_geo_phi_res0 = _wrap_normalized_phi_diff_torch(
                post_geo_dphi0s0 - post_geo_dphi01[None, :] * post_geo_t0
            ).abs()
            post_geo_phi_res1 = _wrap_normalized_phi_diff_torch(
                post_geo_dphi0s1 - post_geo_dphi01[None, :] * post_geo_t1
            ).abs()
            post_geo_z_res = torch.maximum(post_geo_z_res0, post_geo_z_res1)
            post_geo_phi_res = torch.maximum(post_geo_phi_res0, post_geo_phi_res1)
            post_geo_t = torch.minimum(post_geo_t0, post_geo_t1)
            post_geo_t_hi = torch.maximum(post_geo_t0, post_geo_t1)
        else:
            post_geo_rs = post_geo_source_coords[:, 2][:, None]
            post_geo_zs = post_geo_source_coords[:, 4][:, None]
            post_geo_ps = post_geo_source_coords[:, 3][:, None]
            post_geo_t = (post_geo_rs - post_geo_r0[None, :]) / post_geo_denom[None, :]
            post_geo_t_hi = post_geo_t
            post_geo_z_pred = post_geo_z0[None, :] + (post_geo_z1 - post_geo_z0)[None, :] * post_geo_t
            post_geo_z_res = (post_geo_zs - post_geo_z_pred).abs()
            post_geo_dphi0s = _wrap_normalized_phi_diff_torch(post_geo_ps - post_geo_p0[None, :])
            post_geo_phi_res = _wrap_normalized_phi_diff_torch(
                post_geo_dphi0s - post_geo_dphi01[None, :] * post_geo_t
            ).abs()
        post_geo_sim = post_geo_centroids[post_geo_small_rows] @ post_geo_centroids[post_geo_target_rows].t()
        post_geo_norm_res = (
            post_geo_z_res / float(_CODEX_POSTPAD_GEO_Z_MAX)
            + post_geo_phi_res / float(_CODEX_POSTPAD_GEO_PHI_MAX)
        )
        post_geo_score = post_geo_sim.float() - float(_CODEX_POSTPAD_GEO_SCORE_GEOM_WEIGHT) * post_geo_norm_res
        post_geo_bad = ~(post_geo_small_valid[:, None] & post_geo_target_valid[None, :])
        post_geo_bad |= post_geo_small_rows[:, None] == post_geo_target_rows[None, :]
        post_geo_bad |= post_geo_z_res > float(_CODEX_POSTPAD_GEO_Z_MAX)
        post_geo_bad |= post_geo_phi_res > float(_CODEX_POSTPAD_GEO_PHI_MAX)
        post_geo_bad |= post_geo_t < float(_CODEX_POSTPAD_GEO_T_MIN)
        post_geo_bad |= post_geo_t_hi > float(_CODEX_POSTPAD_GEO_T_MAX)
        post_geo_bad |= post_geo_sim.float() < float(_CODEX_POSTPAD_GEO_MIN_SIM)
        post_geo_row_counts = post_geo_counts[post_geo_small_rows][:, None]
        post_geo_target_counts = post_geo_counts[post_geo_target_rows][None, :]
        post_geo_bad |= post_geo_row_counts + post_geo_target_counts > post_geo_max_merged
        post_geo_acyclic = (post_geo_target_counts > post_geo_row_counts) | (
            (post_geo_target_counts == post_geo_row_counts)
            & (post_geo_target_rows[None, :] < post_geo_small_rows[:, None])
        )
        post_geo_bad |= ~post_geo_acyclic
        if int(_CODEX_POSTPAD_GEO_MAX_LAYER_OVERLAP) >= 0:
            post_geo_layers = layer_pad[post_geo_active_idx].long().clamp(0, layer_span - 1)
            post_geo_layer_keys = post_geo_labels * layer_span + post_geo_layers
            post_geo_presence_flat = torch.zeros(
                (n_labels + 1) * layer_span,
                device=predicted.device,
                dtype=torch.float32,
            )
            post_geo_presence_flat.scatter_add_(0, post_geo_layer_keys, post_geo_active_valid.to(torch.float32))
            post_geo_presence = post_geo_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0)
            post_geo_overlap = post_geo_presence[post_geo_small_rows] @ post_geo_presence[post_geo_target_rows].t()
            post_geo_bad |= post_geo_overlap > float(_CODEX_POSTPAD_GEO_MAX_LAYER_OVERLAP)
        post_geo_score = post_geo_score.masked_fill(post_geo_bad, float("-inf"))
        post_geo_vals, post_geo_col_pos = post_geo_score.max(dim=1)
        post_geo_cols = post_geo_target_rows[post_geo_col_pos]
        post_geo_keep = post_geo_small_valid & torch.isfinite(post_geo_vals)
        post_geo_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_geo_remap[post_geo_small_rows] = torch.where(
            post_geo_keep,
            post_geo_cols,
            post_geo_remap[post_geo_small_rows],
        )
        for _ in range(4):
            post_geo_remap = post_geo_remap[post_geo_remap]
        post_geo_merged_sizes = torch.zeros(n_labels + 1, device=predicted.device, dtype=post_geo_counts.dtype)
        post_geo_merged_sizes.scatter_add_(0, post_geo_remap, post_geo_counts)
        post_geo_base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_geo_remap = torch.where(
            post_geo_merged_sizes[post_geo_remap] > post_geo_max_merged,
            post_geo_base_remap,
            post_geo_remap,
        )
        for _ in range(2):
            post_geo_remap = post_geo_remap[post_geo_remap]
        post_geo_labels = post_geo_remap[post_geo_labels].long().clamp(0, n_labels)
        out_pad[post_geo_active_idx] = post_geo_labels
    if _CODEX_DO_POSTPAD_SEMANTIC_MERGE:
        post_small_cap = int(_CODEX_POSTPAD_SEMANTIC_SMALL_CAP)
        post_target_cap = int(_CODEX_POSTPAD_SEMANTIC_TARGET_CAP)
        post_max_merged = int(_CODEX_POSTPAD_MAX_MERGED_SIZE)
        post_active_idx = torch.nonzero_static(
            valid_pad.bool() & (out_pad >= 0),
            size=active_cap,
            fill_value=n_total,
        ).squeeze(1)
        post_active_valid = post_active_idx < n_total
        post_labels = out_pad[post_active_idx].long().clamp(0, n_labels)
        post_points = emb_pad[post_active_idx]
        post_weight = post_active_valid.to(emb.dtype)

        post_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_counts.scatter_add_(0, post_labels, post_active_valid.to(torch.long))
        post_sums = torch.zeros((n_labels + 1, feat_dim), device=emb.device, dtype=emb.dtype)
        post_sums.scatter_add_(
            0,
            post_labels[:, None].expand(-1, feat_dim),
            post_points * post_weight[:, None],
        )
        post_centroids = post_sums / post_counts.to(emb.dtype).clamp_min(1).unsqueeze(1)
        post_centroids = F.normalize(post_centroids, p=2, dim=1, eps=1e-12)

        post_small_rows = torch.nonzero_static(
            (post_counts[:n_labels] >= int(_CODEX_POSTPAD_SEMANTIC_MIN_SIZE))
            & (post_counts[:n_labels] <= int(_CODEX_POSTPAD_SEMANTIC_MAX_SIZE)),
            size=post_small_cap,
            fill_value=n_labels,
        ).squeeze(1)
        post_target_mask = (
            (post_counts[:n_labels] >= int(_CODEX_POSTPAD_SEMANTIC_TARGET_MIN_SIZE))
            & (post_counts[:n_labels] < post_max_merged)
        )
        if _CODEX_POSTPAD_SEMANTIC_TARGET_BY_CLF:
            post_clf_active = clf_pad[post_active_idx]
            post_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=post_clf_active.dtype)
            post_clf_sum.scatter_add_(
                0,
                post_labels,
                torch.where(post_active_valid, post_clf_active, torch.zeros_like(post_clf_active)),
            )
            post_clf = post_clf_sum / post_counts.to(post_clf_sum.dtype).clamp_min(1)
            post_target_scores = post_clf[:n_labels].masked_fill(~post_target_mask, float("-inf"))
            post_target_vals, post_target_rows = post_target_scores.topk(post_target_cap, largest=True)
            post_target_valid = torch.isfinite(post_target_vals)
        else:
            post_target_rows = torch.nonzero_static(
                post_target_mask,
                size=post_target_cap,
                fill_value=n_labels,
            ).squeeze(1)
            post_target_valid = post_target_rows < n_labels

        post_small_valid = post_small_rows < n_labels
        post_sim = post_centroids[post_small_rows] @ post_centroids[post_target_rows].t()
        post_sim = post_sim.masked_fill(
            ~(post_small_valid[:, None] & post_target_valid[None, :]),
            float("-inf"),
        )
        post_sim = post_sim.masked_fill(post_small_rows[:, None] == post_target_rows[None, :], float("-inf"))
        post_row_counts = post_counts[post_small_rows][:, None]
        post_target_counts = post_counts[post_target_rows][None, :]
        post_acyclic = (post_target_counts > post_row_counts) | (
            (post_target_counts == post_row_counts) & (post_target_rows[None, :] < post_small_rows[:, None])
        )
        post_sim = post_sim.masked_fill(~post_acyclic, float("-inf"))
        post_sim = post_sim.masked_fill(post_row_counts + post_target_counts > post_max_merged, float("-inf"))
        if int(_CODEX_POSTPAD_MAX_LAYER_OVERLAP) >= 0:
            post_layers = layer_pad[post_active_idx].long().clamp(0, layer_span - 1)
            post_layer_keys = post_labels * layer_span + post_layers
            post_presence_flat = torch.zeros(
                (n_labels + 1) * layer_span,
                device=predicted.device,
                dtype=torch.float32,
            )
            post_presence_flat.scatter_add_(0, post_layer_keys, post_active_valid.to(torch.float32))
            post_presence = post_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0)
            post_overlap = post_presence[post_small_rows] @ post_presence[post_target_rows].t()
            post_sim = post_sim.masked_fill(
                post_overlap > float(_CODEX_POSTPAD_MAX_LAYER_OVERLAP),
                float("-inf"),
            )
        post_vals, post_col_pos = post_sim.max(dim=1)
        post_cols = post_target_rows[post_col_pos]
        post_keep = post_small_valid & (post_vals >= float(_CODEX_POSTPAD_SEMANTIC_MIN_SIM))
        post_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_remap[post_small_rows] = torch.where(post_keep, post_cols, post_remap[post_small_rows])
        for _ in range(4):
            post_remap = post_remap[post_remap]
        post_merged_sizes = torch.zeros(n_labels + 1, device=predicted.device, dtype=post_counts.dtype)
        post_merged_sizes.scatter_add_(0, post_remap, post_counts)
        post_base_remap = torch.arange(n_labels + 1, device=predicted.device, dtype=torch.long)
        post_remap = torch.where(
            post_merged_sizes[post_remap] > post_max_merged,
            post_base_remap,
            post_remap,
        )
        for _ in range(2):
            post_remap = post_remap[post_remap]
        post_labels = post_remap[post_labels].long().clamp(0, n_labels)
        out_pad[post_active_idx] = post_labels
    if _CODEX_DO_FDM_TREE_DROP and _CODEX_FDM_TREE_CHEAP_ONLY:
        cheap_active_idx = torch.nonzero_static(
            valid_pad.bool() & (out_pad >= 0),
            size=active_cap,
            fill_value=n_total,
        ).squeeze(1)
        cheap_active_valid = cheap_active_idx < n_total
        cheap_labels = out_pad[cheap_active_idx].long().clamp(0, n_labels)
        cheap_points = emb_pad[cheap_active_idx].float()

        cheap_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        cheap_counts.scatter_add_(0, cheap_labels, cheap_active_valid.to(torch.long))
        cheap_counts_f = cheap_counts.to(torch.float32)

        cheap_sums = torch.zeros((n_labels + 1, feat_dim), device=emb.device, dtype=torch.float32)
        cheap_sums.scatter_add_(
            0,
            cheap_labels[:, None].expand(-1, feat_dim),
            cheap_points * cheap_active_valid.to(torch.float32)[:, None],
        )
        cheap_centroids = F.normalize(
            cheap_sums / cheap_counts_f.clamp_min(1.0).unsqueeze(1),
            p=2,
            dim=1,
            eps=1e-12,
        )
        cheap_sim = (cheap_points * cheap_centroids[cheap_labels]).sum(dim=1)
        cheap_sim_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.float32)
        cheap_sim_sum.scatter_add_(
            0,
            cheap_labels,
            torch.where(cheap_active_valid, cheap_sim, torch.zeros_like(cheap_sim)),
        )
        cheap_sim_mean = cheap_sim_sum / cheap_counts_f.clamp_min(1.0)
        cheap_sim_min = torch.full(
            (n_labels + 1,),
            float("inf"),
            device=predicted.device,
            dtype=torch.float32,
        )
        cheap_sim_min.scatter_reduce_(
            0,
            cheap_labels,
            torch.where(cheap_active_valid, cheap_sim, torch.full_like(cheap_sim, float("inf"))),
            reduce="amin",
            include_self=True,
        )
        cheap_sim_min = torch.where(cheap_counts > 0, cheap_sim_min, torch.zeros_like(cheap_sim_min))
        cheap_sim_gap = cheap_sim_mean - cheap_sim_min

        cheap_clf = clf_pad[cheap_active_idx].float()
        cheap_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.float32)
        cheap_clf_sum.scatter_add_(
            0,
            cheap_labels,
            torch.where(cheap_active_valid, cheap_clf, torch.zeros_like(cheap_clf)),
        )
        cheap_clf_mean = cheap_clf_sum / cheap_counts_f.clamp_min(1.0)
        cheap_clf_min = torch.full(
            (n_labels + 1,),
            float("inf"),
            device=predicted.device,
            dtype=torch.float32,
        )
        cheap_clf_min.scatter_reduce_(
            0,
            cheap_labels,
            torch.where(cheap_active_valid, cheap_clf, torch.full_like(cheap_clf, float("inf"))),
            reduce="amin",
            include_self=True,
        )
        cheap_clf_min = torch.where(cheap_counts > 0, cheap_clf_min, torch.zeros_like(cheap_clf_min))

        cheap_layers = layer_pad[cheap_active_idx].long().clamp(0, layer_span - 1)
        cheap_layer_keys = cheap_labels * layer_span + cheap_layers
        cheap_presence_flat = torch.zeros(
            (n_labels + 1) * layer_span,
            device=predicted.device,
            dtype=torch.float32,
        )
        cheap_presence_flat.scatter_add_(0, cheap_layer_keys, cheap_active_valid.to(torch.float32))
        cheap_unique_layers = cheap_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0).sum(dim=1)
        cheap_dup_layers = cheap_counts_f - cheap_unique_layers

        cheap_feature_values = torch.stack(
            (
                cheap_counts_f,
                cheap_dup_layers,
                cheap_clf_mean,
                cheap_clf_min,
                cheap_sim_mean,
                cheap_sim_min,
                cheap_sim_gap,
            ),
            dim=1,
        )
        cheap_left = torch.tensor(_CODEX_FDM_CHEAP_TREE_LEFT, device=predicted.device, dtype=torch.long)
        cheap_right = torch.tensor(_CODEX_FDM_CHEAP_TREE_RIGHT, device=predicted.device, dtype=torch.long)
        cheap_feature = torch.tensor(_CODEX_FDM_CHEAP_TREE_FEATURE, device=predicted.device, dtype=torch.long)
        cheap_threshold = torch.tensor(
            _CODEX_FDM_CHEAP_TREE_THRESHOLD,
            device=predicted.device,
            dtype=torch.float32,
        )
        cheap_drop_leaf = torch.tensor(_CODEX_FDM_CHEAP_TREE_DROP, device=predicted.device, dtype=torch.bool)
        cheap_node = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        for _ in range(12):
            cheap_f = cheap_feature[cheap_node]
            cheap_is_leaf = cheap_f < 0
            cheap_v = cheap_feature_values.gather(1, cheap_f.clamp_min(0).unsqueeze(1)).squeeze(1)
            cheap_go_left = cheap_v <= cheap_threshold[cheap_node]
            cheap_next = torch.where(cheap_go_left, cheap_left[cheap_node], cheap_right[cheap_node]).clamp_min(0)
            cheap_node = torch.where(cheap_is_leaf, cheap_node, cheap_next)
        cheap_drop_labels = (
            cheap_drop_leaf[cheap_node]
            & (cheap_counts >= int(_CODEX_FDM_TREE_MIN_SIZE))
            & (cheap_counts <= int(_CODEX_FDM_TREE_MAX_SIZE))
        )
        out_pad[cheap_active_idx] = torch.where(
            cheap_drop_labels[cheap_labels] & cheap_active_valid,
            torch.full_like(out_pad[cheap_active_idx], -1),
            out_pad[cheap_active_idx],
        )
    if (
        _CODEX_DO_FDM_TREE_DROP
        or (_CODEX_DO_FDM2_TREE_DROP and _CODEX_FDM2_TREE_READY)
    ) and (not _CODEX_FDM_TREE_CHEAP_ONLY):
        tree_active_idx = torch.nonzero_static(
            valid_pad.bool() & (out_pad >= 0),
            size=active_cap,
            fill_value=n_total,
        ).squeeze(1)
        tree_active_valid = tree_active_idx < n_total
        tree_labels = out_pad[tree_active_idx].long().clamp(0, n_labels)

        tree_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
        tree_counts.scatter_add_(0, tree_labels, tree_active_valid.to(torch.long))
        tree_counts_f = tree_counts.to(torch.float32)
        tree_label_mask = (
            (tree_counts >= int(_CODEX_FDM_TREE_MIN_SIZE))
            & (tree_counts <= int(_CODEX_FDM_TREE_MAX_SIZE))
        )
        tree_label_cap = int(_CODEX_FDM_TREE_LABEL_CAP)
        if tree_label_cap > 0:
            tree_rows = torch.nonzero_static(
                tree_label_mask[:n_labels],
                size=tree_label_cap,
                fill_value=n_labels,
            ).squeeze(1)
            tree_rows_valid = tree_rows < n_labels
            tree_rows = tree_rows.clamp(0, n_labels)
        else:
            tree_rows = torch.empty(0, device=predicted.device, dtype=torch.long)
            tree_rows_valid = torch.empty(0, device=predicted.device, dtype=torch.bool)

        if _CODEX_FDM_TREE_SMALL_ONLY:
            tree_stat_label_ok = tree_label_mask
            tree_stat_mask = tree_active_valid & tree_stat_label_ok[tree_labels]
            tree_stat_pos = torch.nonzero_static(
                tree_stat_mask,
                size=int(_CODEX_FDM_TREE_STAT_CAP),
                fill_value=active_cap,
            ).squeeze(1)
            tree_active_valid = tree_stat_pos < active_cap
            tree_stat_pos = tree_stat_pos.clamp_max(active_cap - 1)
            tree_active_idx = tree_active_idx[tree_stat_pos]
            tree_labels = tree_labels[tree_stat_pos]
        tree_active_cap = int(tree_active_idx.shape[0])

        tree_points = emb_pad[tree_active_idx]
        if _CODEX_FDM_TREE_FP16_SIM:
            tree_points = tree_points.to(torch.float16)
        else:
            tree_points = tree_points.float()
        tree_coords = coords_pad[tree_active_idx].float()

        tree_use_compact_stats = (
            _CODEX_FDM_TREE_COMPACT_STATS
            and tree_label_cap > 0
            and tree_active_cap > 0
        )
        tree_use_compact_sim = (
            (_CODEX_FDM_TREE_COMPACT_SIM or tree_use_compact_stats)
            and tree_label_cap > 0
            and tree_active_cap > 0
        )
        if tree_use_compact_sim:
            tree_row_map = torch.full(
                (n_labels + 1,),
                tree_label_cap,
                device=predicted.device,
                dtype=torch.long,
            )
            tree_row_map[tree_rows] = torch.arange(
                tree_label_cap,
                device=predicted.device,
                dtype=torch.long,
            )
            tree_compact_labels = tree_row_map[tree_labels]
            tree_compact_valid = tree_active_valid & (tree_compact_labels < tree_label_cap)
            tree_compact_labels_safe = tree_compact_labels.clamp(0, tree_label_cap - 1)
            tree_counts_compact = tree_counts_f[tree_rows].to(tree_points.dtype)
            tree_counts_rows_f = tree_counts_f[tree_rows]
            tree_sums_compact = torch.zeros(
                (tree_label_cap, feat_dim),
                device=emb.device,
                dtype=tree_points.dtype,
            )
            tree_sums_compact.scatter_add_(
                0,
                tree_compact_labels_safe[:, None].expand(-1, feat_dim),
                tree_points * tree_compact_valid.to(tree_points.dtype)[:, None],
            )
            tree_centroids_compact = F.normalize(
                tree_sums_compact / tree_counts_compact.clamp_min(1.0).unsqueeze(1),
                p=2,
                dim=1,
                eps=1e-12,
            )
            tree_sim_compact_points = (
                tree_points * tree_centroids_compact[tree_compact_labels_safe]
            ).sum(dim=1)
            tree_sim_sum_compact = torch.zeros(
                tree_label_cap,
                device=predicted.device,
                dtype=tree_points.dtype,
            )
            tree_sim_sum_compact.scatter_add_(
                0,
                tree_compact_labels_safe,
                torch.where(
                    tree_compact_valid,
                    tree_sim_compact_points,
                    torch.zeros_like(tree_sim_compact_points),
                ),
            )
            tree_sim_mean_compact = tree_sim_sum_compact / tree_counts_compact.clamp_min(1.0)
            tree_sim_min_compact = torch.full(
                (tree_label_cap,),
                float("inf"),
                device=predicted.device,
                dtype=tree_points.dtype,
            )
            tree_sim_min_compact.scatter_reduce_(
                0,
                tree_compact_labels_safe,
                torch.where(
                    tree_compact_valid,
                    tree_sim_compact_points,
                    torch.full_like(tree_sim_compact_points, float("inf")),
                ),
                reduce="amin",
                include_self=True,
            )
            tree_sim_min_compact = torch.where(
                tree_rows_valid & (tree_counts_f[tree_rows] > 0),
                tree_sim_min_compact,
                torch.zeros_like(tree_sim_min_compact),
            )
            tree_sim_gap_compact = tree_sim_mean_compact - tree_sim_min_compact
        else:
            tree_counts_rows_f = torch.empty(0, device=predicted.device, dtype=torch.float32)
            tree_sums = torch.zeros((n_labels + 1, feat_dim), device=emb.device, dtype=tree_points.dtype)
            tree_sums.scatter_add_(
                0,
                tree_labels[:, None].expand(-1, feat_dim),
                tree_points * tree_active_valid.to(tree_points.dtype)[:, None],
            )
            tree_centroids = F.normalize(
                tree_sums / tree_counts_f.clamp_min(1.0).to(tree_points.dtype).unsqueeze(1),
                p=2,
                dim=1,
                eps=1e-12,
            )
            tree_sim = (tree_points * tree_centroids[tree_labels]).sum(dim=1)
            tree_sim_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=tree_points.dtype)
            tree_sim_sum.scatter_add_(
                0,
                tree_labels,
                torch.where(tree_active_valid, tree_sim, torch.zeros_like(tree_sim)),
            )
            tree_sim_mean = tree_sim_sum / tree_counts_f.clamp_min(1.0).to(tree_points.dtype)
            tree_sim_min = torch.full(
                (n_labels + 1,),
                float("inf"),
                device=predicted.device,
                dtype=tree_points.dtype,
            )
            tree_sim_min.scatter_reduce_(
                0,
                tree_labels,
                torch.where(tree_active_valid, tree_sim, torch.full_like(tree_sim, float("inf"))),
                reduce="amin",
                include_self=True,
            )
            tree_sim_min = torch.where(tree_counts > 0, tree_sim_min, torch.zeros_like(tree_sim_min))
            tree_sim_gap = tree_sim_mean - tree_sim_min

        tree_clf = clf_pad[tree_active_idx].float()
        tree_layers = layer_pad[tree_active_idx].long().clamp(0, layer_span - 1)
        tree_coord_dim = int(coords.shape[1])
        tree_left = torch.tensor(_CODEX_FDM_TREE_LEFT, device=predicted.device, dtype=torch.long)
        tree_right = torch.tensor(_CODEX_FDM_TREE_RIGHT, device=predicted.device, dtype=torch.long)
        tree_feature = torch.tensor(_CODEX_FDM_TREE_FEATURE, device=predicted.device, dtype=torch.long)
        tree_threshold = torch.tensor(_CODEX_FDM_TREE_THRESHOLD, device=predicted.device, dtype=torch.float32)
        tree_drop_leaf = torch.tensor(_CODEX_FDM_TREE_DROP, device=predicted.device, dtype=torch.bool)
        if tree_use_compact_stats:
            tree_clf_sum_rows = torch.zeros(tree_label_cap, device=predicted.device, dtype=torch.float32)
            tree_clf_sum_rows.scatter_add_(
                0,
                tree_compact_labels_safe,
                torch.where(tree_compact_valid, tree_clf, torch.zeros_like(tree_clf)),
            )
            tree_clf_mean_rows = tree_clf_sum_rows / tree_counts_rows_f.clamp_min(1.0)
            tree_clf_min_rows = torch.full(
                (tree_label_cap,),
                float("inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_clf_min_rows.scatter_reduce_(
                0,
                tree_compact_labels_safe,
                torch.where(tree_compact_valid, tree_clf, torch.full_like(tree_clf, float("inf"))),
                reduce="amin",
                include_self=True,
            )
            tree_clf_min_rows = torch.where(
                tree_rows_valid & (tree_counts_rows_f > 0),
                tree_clf_min_rows,
                torch.zeros_like(tree_clf_min_rows),
            )

            tree_layer_keys_rows = tree_compact_labels_safe * layer_span + tree_layers
            tree_presence_flat_rows = torch.zeros(
                tree_label_cap * layer_span,
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_presence_flat_rows.scatter_add_(
                0,
                tree_layer_keys_rows,
                tree_compact_valid.to(torch.float32),
            )
            tree_unique_layers_rows = (
                tree_presence_flat_rows.reshape(tree_label_cap, layer_span).clamp_max(1.0).sum(dim=1)
            )
            tree_dup_layers_rows = tree_counts_rows_f - tree_unique_layers_rows
            tree_geo_need_rows = tree_rows_valid
            if _CODEX_FDM_TREE_PRUNE_GEO:
                tree_prefix_values = torch.stack(
                    (
                        tree_counts_rows_f,
                        tree_dup_layers_rows,
                        tree_clf_mean_rows,
                        tree_clf_min_rows,
                        tree_sim_mean_compact.float(),
                        tree_sim_min_compact.float(),
                        tree_sim_gap_compact.float(),
                    ),
                    dim=1,
                )
                tree_node_prefix = torch.zeros(tree_label_cap, device=predicted.device, dtype=torch.long)
                for _ in range(3):
                    tree_f_prefix = tree_feature[tree_node_prefix]
                    tree_is_leaf_prefix = tree_f_prefix < 0
                    tree_v_prefix = tree_prefix_values.gather(
                        1,
                        tree_f_prefix.clamp(0, 6).unsqueeze(1),
                    ).squeeze(1)
                    tree_go_left_prefix = tree_v_prefix <= tree_threshold[tree_node_prefix]
                    tree_next_prefix = torch.where(
                        tree_go_left_prefix,
                        tree_left[tree_node_prefix],
                        tree_right[tree_node_prefix],
                    ).clamp_min(0)
                    tree_node_prefix = torch.where(
                        tree_is_leaf_prefix,
                        tree_node_prefix,
                        tree_next_prefix,
                )
                tree_subtree_uses_geo = torch.tensor(
                    _CODEX_FDM_TREE_SUBTREE_USES_GEO,
                    device=predicted.device,
                    dtype=torch.bool,
                )
                tree_geo_need_rows = tree_subtree_uses_geo[tree_node_prefix] & tree_rows_valid
                if _CODEX_DO_FDM_TAIL_DROP:
                    tree_tail_geo_rows = (
                        (tree_counts_rows_f <= float(_CODEX_FDM_TAIL_MAX_SIZE))
                        & (tree_dup_layers_rows >= float(_CODEX_FDM_TAIL_MIN_DUP))
                        & (tree_clf_min_rows < float(_CODEX_FDM_TAIL_CLF_MIN_MAX))
                        & tree_rows_valid
                    )
                    tree_geo_need_rows = tree_geo_need_rows | tree_tail_geo_rows
                if _CODEX_DO_FDM2_TREE_DROP and _CODEX_FDM2_TREE_READY and _CODEX_FDM2_TREE_USES_GEO:
                    tree_geo_need_rows = tree_geo_need_rows | tree_rows_valid
            if _CODEX_FDM_TREE_GEO_SMALL_ONLY:
                tree_geo_mask = tree_compact_valid & tree_geo_need_rows[tree_compact_labels_safe]
                tree_geo_pos = torch.nonzero_static(
                    tree_geo_mask,
                    size=int(_CODEX_FDM_TREE_GEO_CAP),
                    fill_value=tree_active_cap,
                ).squeeze(1)
                tree_geo_valid = tree_geo_pos < tree_active_cap
                tree_geo_pos = tree_geo_pos.clamp_max(tree_active_cap - 1)
                tree_geo_labels_rows = tree_compact_labels_safe[tree_geo_pos]
                tree_geo_coords = tree_coords[tree_geo_pos]
            else:
                tree_geo_valid = tree_compact_valid & tree_geo_need_rows[tree_compact_labels_safe]
                tree_geo_labels_rows = tree_compact_labels_safe
                tree_geo_coords = tree_coords

            tree_r = tree_geo_coords[:, 2]
            tree_min_r_rows = torch.full(
                (tree_label_cap,),
                float("inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_max_r_rows = torch.full(
                (tree_label_cap,),
                float("-inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_min_r_rows.scatter_reduce_(
                0,
                tree_geo_labels_rows,
                torch.where(tree_geo_valid, tree_r, torch.full_like(tree_r, float("inf"))),
                reduce="amin",
                include_self=True,
            )
            tree_max_r_rows.scatter_reduce_(
                0,
                tree_geo_labels_rows,
                torch.where(tree_geo_valid, tree_r, torch.full_like(tree_r, float("-inf"))),
                reduce="amax",
                include_self=True,
            )
            tree_min_hit = tree_geo_valid & ((tree_r - tree_min_r_rows[tree_geo_labels_rows]).abs() <= 1e-6)
            tree_max_hit = tree_geo_valid & ((tree_r - tree_max_r_rows[tree_geo_labels_rows]).abs() <= 1e-6)
            tree_min_sums_rows = torch.zeros(
                (tree_label_cap, tree_coord_dim),
                device=coords.device,
                dtype=torch.float32,
            )
            tree_max_sums_rows = torch.zeros_like(tree_min_sums_rows)
            tree_min_sums_rows.scatter_add_(
                0,
                tree_geo_labels_rows[:, None].expand(-1, tree_coord_dim),
                tree_geo_coords * tree_min_hit.to(torch.float32)[:, None],
            )
            tree_max_sums_rows.scatter_add_(
                0,
                tree_geo_labels_rows[:, None].expand(-1, tree_coord_dim),
                tree_geo_coords * tree_max_hit.to(torch.float32)[:, None],
            )
            tree_min_counts_rows = torch.zeros(tree_label_cap, device=predicted.device, dtype=torch.float32)
            tree_max_counts_rows = torch.zeros_like(tree_min_counts_rows)
            tree_min_counts_rows.scatter_add_(0, tree_geo_labels_rows, tree_min_hit.to(torch.float32))
            tree_max_counts_rows.scatter_add_(0, tree_geo_labels_rows, tree_max_hit.to(torch.float32))
            tree_start_rows = tree_min_sums_rows / tree_min_counts_rows.clamp_min(1.0).unsqueeze(1)
            tree_end_rows = tree_max_sums_rows / tree_max_counts_rows.clamp_min(1.0).unsqueeze(1)
            tree_seed0 = tree_start_rows[tree_geo_labels_rows]
            tree_seed1 = tree_end_rows[tree_geo_labels_rows]
            tree_r0 = tree_seed0[:, 2]
            tree_r1 = tree_seed1[:, 2]
            tree_z0 = tree_seed0[:, 4]
            tree_z1 = tree_seed1[:, 4]
            tree_p0 = tree_seed0[:, 3]
            tree_p1 = tree_seed1[:, 3]
            tree_dr = tree_r1 - tree_r0
            tree_denom = torch.where(tree_dr >= 0, tree_dr.clamp_min(1e-6), tree_dr.clamp_max(-1e-6))
            tree_t = (tree_r - tree_r0) / tree_denom
            tree_z_pred = tree_z0 + (tree_z1 - tree_z0) * tree_t
            tree_z_res = (tree_geo_coords[:, 4] - tree_z_pred).abs()
            tree_dphi01 = _wrap_normalized_phi_diff_torch(tree_p1 - tree_p0)
            tree_dphi0 = _wrap_normalized_phi_diff_torch(tree_geo_coords[:, 3] - tree_p0)
            tree_phi_res = _wrap_normalized_phi_diff_torch(tree_dphi0 - tree_dphi01 * tree_t).abs()

            tree_z_sum_rows = torch.zeros(tree_label_cap, device=predicted.device, dtype=torch.float32)
            tree_phi_sum_rows = torch.zeros_like(tree_z_sum_rows)
            tree_z_sum_rows.scatter_add_(
                0,
                tree_geo_labels_rows,
                torch.where(tree_geo_valid, tree_z_res, torch.zeros_like(tree_z_res)),
            )
            tree_phi_sum_rows.scatter_add_(
                0,
                tree_geo_labels_rows,
                torch.where(tree_geo_valid, tree_phi_res, torch.zeros_like(tree_phi_res)),
            )
            tree_z_res_mean_rows = tree_z_sum_rows / tree_counts_rows_f.clamp_min(1.0)
            tree_phi_res_mean_rows = tree_phi_sum_rows / tree_counts_rows_f.clamp_min(1.0)
            tree_z_res_max_rows = torch.full(
                (tree_label_cap,),
                float("-inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_phi_res_max_rows = torch.full_like(tree_z_res_max_rows, float("-inf"))
            tree_z_res_max_rows.scatter_reduce_(
                0,
                tree_geo_labels_rows,
                torch.where(tree_geo_valid, tree_z_res, torch.full_like(tree_z_res, float("-inf"))),
                reduce="amax",
                include_self=True,
            )
            tree_phi_res_max_rows.scatter_reduce_(
                0,
                tree_geo_labels_rows,
                torch.where(tree_geo_valid, tree_phi_res, torch.full_like(tree_phi_res, float("-inf"))),
                reduce="amax",
                include_self=True,
            )
            tree_z_res_max_rows = torch.where(
                tree_rows_valid & (tree_counts_rows_f > 0),
                tree_z_res_max_rows,
                torch.zeros_like(tree_z_res_max_rows),
            )
            tree_phi_res_max_rows = torch.where(
                tree_rows_valid & (tree_counts_rows_f > 0),
                tree_phi_res_max_rows,
                torch.zeros_like(tree_phi_res_max_rows),
            )
            tree_min_r_rows = torch.where(
                tree_rows_valid & (tree_counts_rows_f > 0),
                tree_min_r_rows,
                torch.zeros_like(tree_min_r_rows),
            )
            tree_max_r_rows = torch.where(
                tree_rows_valid & (tree_counts_rows_f > 0),
                tree_max_r_rows,
                torch.zeros_like(tree_max_r_rows),
            )
        else:
            tree_clf_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.float32)
            tree_clf_sum.scatter_add_(
                0,
                tree_labels,
                torch.where(tree_active_valid, tree_clf, torch.zeros_like(tree_clf)),
            )
            tree_clf_mean = tree_clf_sum / tree_counts_f.clamp_min(1.0)
            tree_clf_min = torch.full(
                (n_labels + 1,),
                float("inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_clf_min.scatter_reduce_(
                0,
                tree_labels,
                torch.where(tree_active_valid, tree_clf, torch.full_like(tree_clf, float("inf"))),
                reduce="amin",
                include_self=True,
            )
            tree_clf_min = torch.where(tree_counts > 0, tree_clf_min, torch.zeros_like(tree_clf_min))

            tree_layer_keys = tree_labels * layer_span + tree_layers
            tree_presence_flat = torch.zeros(
                (n_labels + 1) * layer_span,
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_presence_flat.scatter_add_(0, tree_layer_keys, tree_active_valid.to(torch.float32))
            tree_unique_layers = tree_presence_flat.reshape(n_labels + 1, layer_span).clamp_max(1.0).sum(dim=1)
            tree_dup_layers = tree_counts_f - tree_unique_layers

            if _CODEX_FDM_TREE_GEO_SMALL_ONLY:
                tree_geo_label_ok = tree_label_mask
                tree_geo_mask = tree_active_valid & tree_geo_label_ok[tree_labels]
                tree_geo_pos = torch.nonzero_static(
                    tree_geo_mask,
                    size=int(_CODEX_FDM_TREE_GEO_CAP),
                    fill_value=tree_active_cap,
                ).squeeze(1)
                tree_geo_valid = tree_geo_pos < tree_active_cap
                tree_geo_pos = tree_geo_pos.clamp_max(tree_active_cap - 1)
                tree_geo_labels = tree_labels[tree_geo_pos]
                tree_geo_coords = tree_coords[tree_geo_pos]
            else:
                tree_geo_valid = tree_active_valid
                tree_geo_labels = tree_labels
                tree_geo_coords = tree_coords

            tree_r = tree_geo_coords[:, 2]
            tree_min_r = torch.full(
                (n_labels + 1,),
                float("inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_max_r = torch.full(
                (n_labels + 1,),
                float("-inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_min_r.scatter_reduce_(
                0,
                tree_geo_labels,
                torch.where(tree_geo_valid, tree_r, torch.full_like(tree_r, float("inf"))),
                reduce="amin",
                include_self=True,
            )
            tree_max_r.scatter_reduce_(
                0,
                tree_geo_labels,
                torch.where(tree_geo_valid, tree_r, torch.full_like(tree_r, float("-inf"))),
                reduce="amax",
                include_self=True,
            )
            tree_min_hit = tree_geo_valid & ((tree_r - tree_min_r[tree_geo_labels]).abs() <= 1e-6)
            tree_max_hit = tree_geo_valid & ((tree_r - tree_max_r[tree_geo_labels]).abs() <= 1e-6)
            tree_min_sums = torch.zeros((n_labels + 1, tree_coord_dim), device=coords.device, dtype=torch.float32)
            tree_max_sums = torch.zeros_like(tree_min_sums)
            tree_min_sums.scatter_add_(
                0,
                tree_geo_labels[:, None].expand(-1, tree_coord_dim),
                tree_geo_coords * tree_min_hit.to(torch.float32)[:, None],
            )
            tree_max_sums.scatter_add_(
                0,
                tree_geo_labels[:, None].expand(-1, tree_coord_dim),
                tree_geo_coords * tree_max_hit.to(torch.float32)[:, None],
            )
            tree_min_counts = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.float32)
            tree_max_counts = torch.zeros_like(tree_min_counts)
            tree_min_counts.scatter_add_(0, tree_geo_labels, tree_min_hit.to(torch.float32))
            tree_max_counts.scatter_add_(0, tree_geo_labels, tree_max_hit.to(torch.float32))
            tree_start = tree_min_sums / tree_min_counts.clamp_min(1.0).unsqueeze(1)
            tree_end = tree_max_sums / tree_max_counts.clamp_min(1.0).unsqueeze(1)
            tree_seed0 = tree_start[tree_geo_labels]
            tree_seed1 = tree_end[tree_geo_labels]
            tree_r0 = tree_seed0[:, 2]
            tree_r1 = tree_seed1[:, 2]
            tree_z0 = tree_seed0[:, 4]
            tree_z1 = tree_seed1[:, 4]
            tree_p0 = tree_seed0[:, 3]
            tree_p1 = tree_seed1[:, 3]
            tree_dr = tree_r1 - tree_r0
            tree_denom = torch.where(tree_dr >= 0, tree_dr.clamp_min(1e-6), tree_dr.clamp_max(-1e-6))
            tree_t = (tree_r - tree_r0) / tree_denom
            tree_z_pred = tree_z0 + (tree_z1 - tree_z0) * tree_t
            tree_z_res = (tree_geo_coords[:, 4] - tree_z_pred).abs()
            tree_dphi01 = _wrap_normalized_phi_diff_torch(tree_p1 - tree_p0)
            tree_dphi0 = _wrap_normalized_phi_diff_torch(tree_geo_coords[:, 3] - tree_p0)
            tree_phi_res = _wrap_normalized_phi_diff_torch(tree_dphi0 - tree_dphi01 * tree_t).abs()

            tree_z_sum = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.float32)
            tree_phi_sum = torch.zeros_like(tree_z_sum)
            tree_z_sum.scatter_add_(
                0,
                tree_geo_labels,
                torch.where(tree_geo_valid, tree_z_res, torch.zeros_like(tree_z_res)),
            )
            tree_phi_sum.scatter_add_(
                0,
                tree_geo_labels,
                torch.where(tree_geo_valid, tree_phi_res, torch.zeros_like(tree_phi_res)),
            )
            tree_z_res_mean = tree_z_sum / tree_counts_f.clamp_min(1.0)
            tree_phi_res_mean = tree_phi_sum / tree_counts_f.clamp_min(1.0)
            tree_z_res_max = torch.full(
                (n_labels + 1,),
                float("-inf"),
                device=predicted.device,
                dtype=torch.float32,
            )
            tree_phi_res_max = torch.full_like(tree_z_res_max, float("-inf"))
            tree_z_res_max.scatter_reduce_(
                0,
                tree_geo_labels,
                torch.where(tree_geo_valid, tree_z_res, torch.full_like(tree_z_res, float("-inf"))),
                reduce="amax",
                include_self=True,
            )
            tree_phi_res_max.scatter_reduce_(
                0,
                tree_geo_labels,
                torch.where(tree_geo_valid, tree_phi_res, torch.full_like(tree_phi_res, float("-inf"))),
                reduce="amax",
                include_self=True,
            )
            tree_z_res_max = torch.where(tree_counts > 0, tree_z_res_max, torch.zeros_like(tree_z_res_max))
            tree_phi_res_max = torch.where(tree_counts > 0, tree_phi_res_max, torch.zeros_like(tree_phi_res_max))
            tree_min_r = torch.where(tree_counts > 0, tree_min_r, torch.zeros_like(tree_min_r))
            tree_max_r = torch.where(tree_counts > 0, tree_max_r, torch.zeros_like(tree_max_r))

        if tree_label_cap > 0:
            if tree_use_compact_sim:
                tree_sim_mean_rows = tree_sim_mean_compact
                tree_sim_min_rows = tree_sim_min_compact
                tree_sim_gap_rows = tree_sim_gap_compact
            else:
                tree_sim_mean_rows = tree_sim_mean[tree_rows]
                tree_sim_min_rows = tree_sim_min[tree_rows]
                tree_sim_gap_rows = tree_sim_gap[tree_rows]
            if tree_use_compact_stats:
                tree_dup_layers_for_rows = tree_dup_layers_rows
                tree_clf_mean_for_rows = tree_clf_mean_rows
                tree_clf_min_for_rows = tree_clf_min_rows
                tree_z_res_mean_for_rows = tree_z_res_mean_rows
                tree_z_res_max_for_rows = tree_z_res_max_rows
                tree_phi_res_mean_for_rows = tree_phi_res_mean_rows
                tree_phi_res_max_for_rows = tree_phi_res_max_rows
                tree_min_r_for_rows = tree_min_r_rows
                tree_max_r_for_rows = tree_max_r_rows
            else:
                tree_dup_layers_for_rows = tree_dup_layers[tree_rows]
                tree_clf_mean_for_rows = tree_clf_mean[tree_rows]
                tree_clf_min_for_rows = tree_clf_min[tree_rows]
                tree_z_res_mean_for_rows = tree_z_res_mean[tree_rows]
                tree_z_res_max_for_rows = tree_z_res_max[tree_rows]
                tree_phi_res_mean_for_rows = tree_phi_res_mean[tree_rows]
                tree_phi_res_max_for_rows = tree_phi_res_max[tree_rows]
                tree_min_r_for_rows = tree_min_r[tree_rows]
                tree_max_r_for_rows = tree_max_r[tree_rows]
            tree_feature_values = torch.stack(
                (
                    tree_counts_rows_f,
                    tree_dup_layers_for_rows,
                    tree_clf_mean_for_rows,
                    tree_clf_min_for_rows,
                    tree_sim_mean_rows,
                    tree_sim_min_rows,
                    tree_sim_gap_rows,
                    tree_z_res_mean_for_rows,
                    tree_z_res_max_for_rows,
                    tree_phi_res_mean_for_rows,
                    tree_phi_res_max_for_rows,
                    tree_min_r_for_rows,
                    tree_max_r_for_rows,
                ),
                dim=1,
            )
            if _CODEX_DO_FDM_TREE_DROP:
                tree_node = torch.zeros(tree_label_cap, device=predicted.device, dtype=torch.long)
                for _ in range(10):
                    tree_f = tree_feature[tree_node]
                    tree_is_leaf = tree_f < 0
                    tree_v = tree_feature_values.gather(1, tree_f.clamp_min(0).unsqueeze(1)).squeeze(1)
                    tree_go_left = tree_v <= tree_threshold[tree_node]
                    tree_next = torch.where(tree_go_left, tree_left[tree_node], tree_right[tree_node]).clamp_min(0)
                    tree_node = torch.where(tree_is_leaf, tree_node, tree_next)
                tree_drop_rows = tree_drop_leaf[tree_node] & tree_rows_valid
            else:
                tree_drop_rows = torch.zeros(tree_label_cap, device=predicted.device, dtype=torch.bool)
            if _CODEX_DO_FDM2_TREE_DROP and _CODEX_FDM2_TREE_READY:
                tree2_left = torch.tensor(_CODEX_FDM2_TREE_LEFT, device=predicted.device, dtype=torch.long)
                tree2_right = torch.tensor(_CODEX_FDM2_TREE_RIGHT, device=predicted.device, dtype=torch.long)
                tree2_feature = torch.tensor(_CODEX_FDM2_TREE_FEATURE, device=predicted.device, dtype=torch.long)
                tree2_threshold = torch.tensor(_CODEX_FDM2_TREE_THRESHOLD, device=predicted.device, dtype=torch.float32)
                tree2_drop_leaf = torch.tensor(_CODEX_FDM2_TREE_DROP, device=predicted.device, dtype=torch.bool)
                tree2_node = torch.zeros(tree_label_cap, device=predicted.device, dtype=torch.long)
                for _ in range(int(_CODEX_FDM2_TREE_MAX_DEPTH)):
                    tree2_f = tree2_feature[tree2_node]
                    tree2_is_leaf = tree2_f < 0
                    tree2_v = tree_feature_values.gather(1, tree2_f.clamp_min(0).unsqueeze(1)).squeeze(1)
                    tree2_go_left = tree2_v <= tree2_threshold[tree2_node]
                    tree2_next = torch.where(
                        tree2_go_left,
                        tree2_left[tree2_node],
                        tree2_right[tree2_node],
                    ).clamp_min(0)
                    tree2_node = torch.where(tree2_is_leaf, tree2_node, tree2_next)
                tree2_drop_rows = (
                    tree2_drop_leaf[tree2_node]
                    & tree_rows_valid
                    & (tree_counts_rows_f >= float(_CODEX_FDM2_TREE_MIN_SIZE))
                    & (tree_counts_rows_f <= float(_CODEX_FDM2_TREE_MAX_SIZE))
                )
                tree_drop_rows = tree_drop_rows | tree2_drop_rows
            if _CODEX_DO_FDM_TAIL_DROP:
                tree_tail_rows = (
                    (tree_counts_rows_f <= float(_CODEX_FDM_TAIL_MAX_SIZE))
                    & (tree_dup_layers_rows >= float(_CODEX_FDM_TAIL_MIN_DUP))
                    & (tree_clf_min_rows < float(_CODEX_FDM_TAIL_CLF_MIN_MAX))
                    & (tree_z_res_max_rows > float(_CODEX_FDM_TAIL_Z_RES_MAX_MIN))
                    & tree_rows_valid
                )
                tree_drop_rows = tree_drop_rows | tree_tail_rows
            tree_drop_labels = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.bool)
            tree_drop_labels[tree_rows] = tree_drop_rows
        else:
            tree_feature_values = torch.stack(
                (
                    tree_counts_f,
                    tree_dup_layers,
                    tree_clf_mean,
                    tree_clf_min,
                    tree_sim_mean,
                    tree_sim_min,
                    tree_sim_gap,
                    tree_z_res_mean,
                    tree_z_res_max,
                    tree_phi_res_mean,
                    tree_phi_res_max,
                    tree_min_r,
                    tree_max_r,
                ),
                dim=1,
            )
            if _CODEX_DO_FDM_TREE_DROP:
                tree_node = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
                for _ in range(10):
                    tree_f = tree_feature[tree_node]
                    tree_is_leaf = tree_f < 0
                    tree_v = tree_feature_values.gather(1, tree_f.clamp_min(0).unsqueeze(1)).squeeze(1)
                    tree_go_left = tree_v <= tree_threshold[tree_node]
                    tree_next = torch.where(tree_go_left, tree_left[tree_node], tree_right[tree_node]).clamp_min(0)
                    tree_node = torch.where(tree_is_leaf, tree_node, tree_next)
                tree_drop_labels = tree_drop_leaf[tree_node] & tree_label_mask
            else:
                tree_drop_labels = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.bool)
            if _CODEX_DO_FDM2_TREE_DROP and _CODEX_FDM2_TREE_READY:
                tree2_left = torch.tensor(_CODEX_FDM2_TREE_LEFT, device=predicted.device, dtype=torch.long)
                tree2_right = torch.tensor(_CODEX_FDM2_TREE_RIGHT, device=predicted.device, dtype=torch.long)
                tree2_feature = torch.tensor(_CODEX_FDM2_TREE_FEATURE, device=predicted.device, dtype=torch.long)
                tree2_threshold = torch.tensor(_CODEX_FDM2_TREE_THRESHOLD, device=predicted.device, dtype=torch.float32)
                tree2_drop_leaf = torch.tensor(_CODEX_FDM2_TREE_DROP, device=predicted.device, dtype=torch.bool)
                tree2_node = torch.zeros(n_labels + 1, device=predicted.device, dtype=torch.long)
                for _ in range(int(_CODEX_FDM2_TREE_MAX_DEPTH)):
                    tree2_f = tree2_feature[tree2_node]
                    tree2_is_leaf = tree2_f < 0
                    tree2_v = tree_feature_values.gather(1, tree2_f.clamp_min(0).unsqueeze(1)).squeeze(1)
                    tree2_go_left = tree2_v <= tree2_threshold[tree2_node]
                    tree2_next = torch.where(
                        tree2_go_left,
                        tree2_left[tree2_node],
                        tree2_right[tree2_node],
                    ).clamp_min(0)
                    tree2_node = torch.where(tree2_is_leaf, tree2_node, tree2_next)
                tree2_label_mask = (
                    (tree_counts >= int(_CODEX_FDM2_TREE_MIN_SIZE))
                    & (tree_counts <= int(_CODEX_FDM2_TREE_MAX_SIZE))
                )
                tree_drop_labels = tree_drop_labels | (tree2_drop_leaf[tree2_node] & tree2_label_mask)
        if _CODEX_DO_FDM_TAIL_DROP and not (tree_use_compact_stats and tree_label_cap > 0):
            tree_drop_labels = tree_drop_labels | (
                (tree_counts <= int(_CODEX_FDM_TAIL_MAX_SIZE))
                & (tree_dup_layers >= float(_CODEX_FDM_TAIL_MIN_DUP))
                & (tree_clf_min < float(_CODEX_FDM_TAIL_CLF_MIN_MAX))
                & (tree_z_res_max > float(_CODEX_FDM_TAIL_Z_RES_MAX_MIN))
            )
        out_pad[tree_active_idx] = torch.where(
            tree_drop_labels[tree_labels] & tree_active_valid,
            torch.full_like(out_pad[tree_active_idx], -1),
            out_pad[tree_active_idx],
        )
    return out_pad[:n_total]


_CODEX_COMPILE_MODE = os.environ.get(
    "HEPTV2_CODEX_POST_COMPILE_MODE",
    os.environ.get("HEPTV2_CODEX_COMPILE_MODE", "reduce-overhead"),
)
if _env_bool("HEPTV2_CODEX_DISABLE_INDUCTOR_CUDAGRAPH_TREES", False):
    import torch._inductor.config as _codex_inductor_config

    _codex_inductor_config.triton.cudagraph_trees = False
_codex_compile_kwargs = {
    "dynamic": False,
    "fullgraph": True,
}
if _CODEX_COMPILE_MODE and _CODEX_COMPILE_MODE != "default":
    _codex_compile_kwargs["mode"] = _CODEX_COMPILE_MODE
if _CODEX_STEAL_DEBUG:
    _codex_nomask_target_core_compiled = _codex_nomask_target_core
else:
    _codex_nomask_target_core_compiled = torch.compile(
        _codex_nomask_target_core,
        **_codex_compile_kwargs,
    )


@torch.no_grad()
def _dedup_same_layer_clusters_label_space_fast(
    predicted,
    full_data,
    num_labels,
    min_cluster_size=4,
    min_size_after=3,
    min_sim_gap=0.0,
    normalized_emb=None,
    layer_min=0,
    layer_span=18,
):
    if (
        int(num_labels) <= 1
        or normalized_emb is None
        or not hasattr(full_data, "layer")
        or full_data.layer is None
    ):
        return None
    active_idx = torch.nonzero(full_data.valid_mask.bool() & (predicted >= 0), as_tuple=False).squeeze(1)
    if active_idx.numel() == 0:
        return predicted
    labels = predicted[active_idx].long()
    counts = torch.bincount(labels, minlength=int(num_labels))
    return _dedup_same_layer_label_space_core_compiled(
        predicted,
        active_idx,
        labels,
        counts,
        normalized_emb,
        full_data.layer.long(),
        int(layer_min),
        int(layer_span),
        int(min_cluster_size),
        int(min_size_after),
        float(min_sim_gap),
    )


@torch.no_grad()
def _kmeans_refine_assignments(
    init_pred,
    features,
    iters,
    min_margin=0.0,
    use_fp16_sim=False,
    max_refine_cluster_size=0,
    normalized_features=None,
    candidate_mask=None,
):
    active_mask = init_pred >= 0
    if not active_mask.any():
        return init_pred
    active_ids, inv = torch.unique(init_pred[active_mask], return_inverse=True)
    k = active_ids.numel()
    if k <= 1:
        return init_pred
    norm_features = normalized_features if normalized_features is not None else _l2_normalize(features)
    points_all = norm_features[active_mask]
    counts_init = torch.bincount(inv, minlength=k)
    if int(max_refine_cluster_size) > 0:
        refine_mask = counts_init[inv] <= int(max_refine_cluster_size)
    else:
        refine_mask = torch.ones_like(inv, dtype=torch.bool)
    if candidate_mask is not None:
        refine_mask &= candidate_mask[active_mask].bool()
    if not bool(refine_mask.any()):
        return init_pred
    points = points_all[refine_mask]
    assign = inv[refine_mask].clone()
    centroids = scatter_mean(points_all, inv, dim=0, dim_size=k)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)
    for step in range(int(iters)):
        if bool(use_fp16_sim) and points.is_cuda:
            sim = points.to(torch.float16) @ centroids.to(torch.float16).t()
        else:
            sim = points @ centroids.t()
        if float(min_margin) > 0.0:
            current_sim = sim.gather(1, assign[:, None]).squeeze(1)
            best_sim, best_assign = sim.max(dim=1)
            move = (best_sim - current_sim) >= float(min_margin)
            assign = torch.where(move, best_assign, assign)
        else:
            assign = sim.argmax(dim=1)
        if step == int(iters) - 1:
            continue
        assign_all = inv.clone()
        assign_all[refine_mask] = assign
        new_centroids = scatter_mean(points_all, assign_all, dim=0, dim_size=k)
        counts = torch.bincount(assign_all, minlength=k).to(points_all.dtype).unsqueeze(1)
        new_centroids = F.normalize(new_centroids, p=2, dim=1, eps=1e-12)
        centroids = torch.where(counts > 0, new_centroids, centroids)
    refined = init_pred.clone()
    active_idx = torch.nonzero(active_mask, as_tuple=False).squeeze(1)
    refined[active_idx[refine_mask]] = active_ids[assign]
    return refined


@torch.no_grad()
def _kmeans_refine_assignments_label_space_fast(
    init_pred,
    features,
    iters,
    num_labels,
    min_margin=0.0,
    use_fp16_sim=False,
    max_refine_cluster_size=0,
    normalized_features=None,
    candidate_mask=None,
):
    active_mask = init_pred >= 0
    if int(num_labels) <= 1:
        return init_pred
    active_idx = torch.nonzero(active_mask, as_tuple=False).squeeze(1)
    if active_idx.numel() == 0:
        return init_pred
    labels = init_pred[active_idx].long()
    counts_dense = torch.bincount(labels, minlength=int(num_labels))
    active_ids = torch.nonzero(counts_dense > 0, as_tuple=False).squeeze(1)
    k = active_ids.numel()
    if k <= 1:
        return init_pred

    row_map = torch.full((int(num_labels),), -1, device=init_pred.device, dtype=torch.long)
    row_map[active_ids] = torch.arange(k, device=init_pred.device, dtype=torch.long)
    inv = row_map[labels]
    norm_features = normalized_features if normalized_features is not None else _l2_normalize(features)
    points_all = norm_features[active_idx]
    counts_init = counts_dense[active_ids]
    if int(max_refine_cluster_size) > 0:
        refine_mask = counts_init[inv] <= int(max_refine_cluster_size)
    else:
        refine_mask = torch.ones_like(inv, dtype=torch.bool)
    if candidate_mask is not None:
        refine_mask &= candidate_mask[active_idx].bool()

    sums = torch.zeros((k, int(points_all.shape[1])), device=points_all.device, dtype=points_all.dtype)
    sums.scatter_add_(0, inv[:, None].expand(-1, int(points_all.shape[1])), points_all)
    centroids = sums / counts_init.to(points_all.dtype).clamp_min(1).unsqueeze(1)
    centroids = F.normalize(centroids, p=2, dim=1, eps=1e-12)

    points = points_all[refine_mask]
    assign = inv[refine_mask].clone()
    for step in range(int(iters)):
        if bool(use_fp16_sim) and points.is_cuda:
            sim = points.to(torch.float16) @ centroids.to(torch.float16).t()
        else:
            sim = points @ centroids.t()
        if float(min_margin) > 0.0:
            current_sim = sim.gather(1, assign[:, None]).squeeze(1)
            best_sim, best_assign = sim.max(dim=1)
            move = (best_sim - current_sim) >= float(min_margin)
            assign = torch.where(move, best_assign, assign)
        else:
            assign = sim.argmax(dim=1)
        if step == int(iters) - 1:
            continue
        assign_all = inv.clone()
        assign_all[refine_mask] = assign
        new_sums = torch.zeros_like(sums)
        new_sums.scatter_add_(0, assign_all[:, None].expand(-1, int(points_all.shape[1])), points_all)
        new_counts = torch.bincount(assign_all, minlength=int(k)).to(points_all.dtype).unsqueeze(1)
        new_centroids = F.normalize(new_sums, p=2, dim=1, eps=1e-12)
        centroids = torch.where(new_counts > 0, new_centroids, centroids)

    refined = init_pred.clone()
    refined[active_idx[refine_mask]] = active_ids[assign]
    return refined


